-- Poems batch 244
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5c1787d2-5e22-4d22-a3da-6074cfa3899a','鱸鄉道院','胡仲弓','宋','宋诗','song-poetry','','[]','宦情原自薄，卜得吳松居。',24,'全唐诗/poet.song.220000.json','["宦情原自薄，卜得吳松居。", "鄉味已飽諳，胡爲羨鱸魚。"]'),
('3babe696-7d49-4124-927b-d425ed332963','翠竹','胡仲弓','宋','宋诗','song-poetry','','[]','修修青琅玕，霜雪不可折。',24,'全唐诗/poet.song.220000.json','["修修青琅玕，霜雪不可折。", "肯隨流水去，頼有歲寒節。"]'),
('2273de4d-edf9-4f71-9c14-b47587578bd5','張南起爲作葦航圖仍示以詩次韻繼賦  其一','胡仲弓','宋','宋诗','song-poetry','','[]','風摇古柳散羣鴉，小艇尋詩來水涯。',32,'全唐诗/poet.song.220000.json','["風摇古柳散羣鴉，小艇尋詩來水涯。", "身在江湖平穩處，一塵不到浪頭花。"]'),
('696880df-c1da-4ea2-b836-60e791e1d588','張南起爲作葦航圖仍示以詩次韻繼賦  其二','胡仲弓','宋','宋诗','song-poetry','','[]','繫纜蕭蕭蘆葦傍，酒和翰墨醉淋浪。',32,'全唐诗/poet.song.220000.json','["繫纜蕭蕭蘆葦傍，酒和翰墨醉淋浪。", "靈槎不泝銀河去，却向人間羨野航。"]'),
('fedfe370-1be3-40ff-a2f7-38873854e248','過莆城懷劉後村中書因以奉寄  其一','胡仲弓','宋','宋诗','song-poetry','','[]','村在山邊雲半遮，懷人咫尺是天涯。',32,'全唐诗/poet.song.220000.json','["村在山邊雲半遮，懷人咫尺是天涯。", "眼前不見玄都觀，空負碧桃千樹花。"]'),
('c6cbd12b-5b97-4ea3-9f2c-5ef9210d6563','過莆城懷劉後村中書因以奉寄  其二','胡仲弓','宋','宋诗','song-poetry','','[]','入洛深衣已十春，聲名千載有知聞。',32,'全唐诗/poet.song.220000.json','["入洛深衣已十春，聲名千載有知聞。", "不須更結耆英社，溧水前頭獨繪君。"]'),
('a81e1522-4705-468c-90d1-6299e2c19efd','過莆城懷劉後村中書因以奉寄  其三','胡仲弓','宋','宋诗','song-poetry','','[]','當日揚清激濁流，身危肯作稻粱謀。',32,'全唐诗/poet.song.220000.json','["當日揚清激濁流，身危肯作稻粱謀。", "不從黨錮諸賢死，竊祿偷生亦可羞。"]'),
('14c401f4-c1b3-4b0e-9fc0-b00fdbda494c','過莆城懷劉後村中書因以奉寄  其四','胡仲弓','宋','宋诗','song-poetry','','[]','模楷從來屬李膺，臯比授業我何能。',32,'全唐诗/poet.song.220000.json','["模楷從來屬李膺，臯比授業我何能。", "倚牆甚欲重參請，恐累龍門不敢登。"]'),
('17fca6d0-776d-464d-b8c1-91349b39ac31','郊行','胡仲弓','宋','宋诗','song-poetry','','[]','杜鵑聲裏又花紅，處處陰雲日影蒙。',32,'全唐诗/poet.song.220000.json','["杜鵑聲裏又花紅，處處陰雲日影蒙。", "心事太平人事好，眼前無物不春風。"]'),
('c5ab3b11-7556-48da-a258-dba98163264d','題馮中郎廟','胡仲弓','宋','宋诗','song-poetry','','[]','論將功中可策勳，至今香火密如雲。',32,'全唐诗/poet.song.220000.json','["論將功中可策勳，至今香火密如雲。", "生時不遇孝文帝，定有何人肯薦君。"]'),
('b79cd2e0-a1f1-4daa-970a-a61c779b9fd2','山中有花一種俗名花葉不相見感而賦之','胡仲弓','宋','宋诗','song-poetry','','[]','世間鴈燕本無情，天上參商誰會面。',32,'全唐诗/poet.song.220000.json','["世間鴈燕本無情，天上參商誰會面。", "花葉自是同根生，何事開時不相見。"]'),
('61bbf6cd-0573-4557-a4fb-5f1b4a8066ee','紅遠','胡仲弓','宋','宋诗','song-poetry','','[]','濃淡中邊費剪裁，朱唇得酒笑顔開。',32,'全唐诗/poet.song.220000.json','["濃淡中邊費剪裁，朱唇得酒笑顔開。", "春風不度西流水，休說香從蜀道來。"]'),
('f01b41aa-f06a-428f-ba92-3dbae97688e5','觀中原指掌圖','胡仲弓','宋','宋诗','song-poetry','','[]','月明空照八陵碑，玉館瓊樓失舊基。',32,'全唐诗/poet.song.220000.json','["月明空照八陵碑，玉館瓊樓失舊基。", "故國不堪回首處，西風滿地黍離離。"]'),
('adaaa01b-81f3-494c-8265-403629dbab64','觀丙辰省試宣鎖作  其一','胡仲弓','宋','宋诗','song-poetry','','[]','四海文章屬品題，老夫刮膜有金篦。',32,'全唐诗/poet.song.220000.json','["四海文章屬品題，老夫刮膜有金篦。", "諸君熟讀阿房賦，未必能爲五色迷。"]'),
('f7279ad8-1883-4eb5-b1c9-cc768649f795','觀丙辰省試宣鎖作  其二','胡仲弓','宋','宋诗','song-poetry','','[]','撒幙焚香冰鑑開，觀君切莫負多才。',32,'全唐诗/poet.song.220000.json','["撒幙焚香冰鑑開，觀君切莫負多才。", "黜邊取迪渾閒事，只恐紛紛擲甓來。"]'),
('ddea3afd-86a6-493d-9782-59b95a9b8255','觀丙辰省試宣鎖作  其三','胡仲弓','宋','宋诗','song-poetry','','[]','一窗絲雨一簾風，當日虀鹽滋味同。',32,'全唐诗/poet.song.220000.json','["一窗絲雨一簾風，當日虀鹽滋味同。", "見說主司多好句，肯將蠶蟻待諸公。"]'),
('2a3e0afb-4ace-4396-9326-eda93ada0d37','過釣鈎嶺悼亡友盛景韓','胡仲弓','宋','宋诗','song-poetry','','[]','一見銘旌作許愁，西風飄落冷颼颼。',32,'全唐诗/poet.song.220000.json','["一見銘旌作許愁，西風飄落冷颼颼。", "早知真氣無伸處，悔不當時曲似鈎。"]'),
('c4adbaad-9fb5-4ab3-b8b7-70aef871bccd','暑中雜興  其一','胡仲弓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一刻之閒直萬金，苦無人可共幽襟。',32,'全唐诗/poet.song.220000.json','["一刻之閒直萬金，苦無人可共幽襟。", "成年不作西湖想，聽得啼鶑不自禁。"]'),
('a989b09a-b722-4933-9ceb-72c200be7d2a','暑中雜興  其二','胡仲弓','宋','宋诗','song-poetry','','[]','不慣山中夜月寒，滿窗樹影蘚花乾。',32,'全唐诗/poet.song.220000.json','["不慣山中夜月寒，滿窗樹影蘚花乾。", "移床近壁不敢卧，恐是龍蛇之屈蟠。"]'),
('71a3db82-31ea-433a-89c1-10dbd3abf88c','暑中雜興  其三','胡仲弓','宋','宋诗','song-poetry','','[]','今年不上一竿竹，渠豈於人亦世情。',32,'全唐诗/poet.song.220000.json','["今年不上一竿竹，渠豈於人亦世情。", "風雨尚餘千箇在，結巢吾欲聽秋聲。"]'),
('39029b92-5f00-4147-8f0f-bff9a441caad','暑中雜興  其四','胡仲弓','宋','宋诗','song-poetry','','[]','白鷗吾有一日雅，疇昔見之相與親。',32,'全唐诗/poet.song.220000.json','["白鷗吾有一日雅，疇昔見之相與親。", "滄浪忽欲從此逝，嗔我手揖無詩人。"]'),
('ccb5d4a4-fc6d-4d31-b25d-221ff8ffa8d4','暑中雜興  其五','胡仲弓','宋','宋诗','song-poetry','','[]','是非不到野溪邊，只就梧桐聽雨眠。',32,'全唐诗/poet.song.220000.json','["是非不到野溪邊，只就梧桐聽雨眠。", "睡熟不知溪水長，鷺鷥飛上釣魚船。"]'),
('de61b9c6-a3a8-4c1f-a6cd-1e7d3c641adc','暑中雜興  其六','胡仲弓','宋','宋诗','song-poetry','','[]','平生多可曹修士，說我唐詩最逼真。',32,'全唐诗/poet.song.220000.json','["平生多可曹修士，說我唐詩最逼真。", "不道蹇馿風雪裏，何如黄犢過比鄰。"]'),
('a1153ef1-fd5b-49e1-8e1a-b8a23e7b7e01','暑中雜興  其七','胡仲弓','宋','宋诗','song-poetry','','[]','俚謂革華烏脚鬼，吾尊毛穎黑頭公。',32,'全唐诗/poet.song.220000.json','["俚謂革華烏脚鬼，吾尊毛穎黑頭公。", "與華作傳何爲者，穎則萬世辭文工。"]'),
('3ca5957f-9a46-4588-89a3-1cc1db7a4846','暑中雜興  其八','胡仲弓','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','只鋤蔬甲亦妨閒，久與溪雲斷往還。',32,'全唐诗/poet.song.220000.json','["只鋤蔬甲亦妨閒，久與溪雲斷往還。", "今日偶來僧却在，共煎茶喫話廬山。"]'),
('864e038b-ef63-4938-8bd2-69e90f49834e','辛丑上元','胡仲弓','宋','宋诗','song-poetry','','[]','官府張燈試太平，斯民從此不聊生。',32,'全唐诗/poet.song.220000.json','["官府張燈試太平，斯民從此不聊生。", "使君只聽笙歌沸，不聽閭閻愁嘆聲。"]'),
('ffea0c95-0ea2-4c33-bd8d-75658b9b5037','雙髻山','胡仲弓','宋','宋诗','song-poetry','','[]','千古丫鬟高插天，淡粧濃抹傅雲煙。',32,'全唐诗/poet.song.220000.json','["千古丫鬟高插天，淡粧濃抹傅雲煙。", "眼前不見峨眉老，獨有青山長少年。"]'),
('f3aef951-0a6e-4b37-9e56-1f886c78e638','次韻烹筍一絕','胡仲弓','宋','宋诗','song-poetry','','[]','錦䙀纔脫見龍孫，便好西園倒玉尊。',32,'全唐诗/poet.song.220000.json','["錦䙀纔脫見龍孫，便好西園倒玉尊。", "滿肚歲寒無著處，此情難與俗人言。"]'),
('667d9c3f-5a35-43f2-bbc0-acba87b058fb','西來洞天','胡仲弓','宋','宋诗','song-poetry','','[]','可是胸中負怪奇，一丘一壑儘逶迤。',32,'全唐诗/poet.song.220000.json','["可是胸中負怪奇，一丘一壑儘逶迤。", "自從猿向西方去，鷲竺飛來未可知。"]'),
('561998fd-fafa-4ca1-8f55-284b7a80f525','送梅村歸三山  其一','胡仲弓','宋','宋诗','song-poetry','','[]','此別重逢知幾秋，梅花雖老更風流。',32,'全唐诗/poet.song.220000.json','["此別重逢知幾秋，梅花雖老更風流。", "東君未漏春消息，罰與人間作蹇修。"]'),
('efa156b7-ac2c-4cf4-85ca-0b69bc6c5f5e','送梅村歸三山  其二','胡仲弓','宋','宋诗','song-poetry','','[]','獨笑坐鞍自課詩，江雲雨樹兩依依。',32,'全唐诗/poet.song.220000.json','["獨笑坐鞍自課詩，江雲雨樹兩依依。", "客懷生怕西風惡，纔入秋來便賦歸。"]'),
('c1d6b47f-c93a-4f6e-b399-d7de6dc2bd35','遠將歸  其一','胡仲弓','宋','宋诗','song-poetry','','[]','不勘圖經認地名，亦知此去近桐城。',32,'全唐诗/poet.song.220000.json','["不勘圖經認地名，亦知此去近桐城。", "行人未至心先至，差勝離家第一程。"]'),
('414eb97b-42a6-43cd-bacb-47df5a287db9','遠將歸  其二','胡仲弓','宋','宋诗','song-poetry','','[]','鶴不歸來華表閒，輝金耀碧滿湖間。',32,'全唐诗/poet.song.220000.json','["鶴不歸來華表閒，輝金耀碧滿湖間。", "後來若有林和靖，定不吟梅向此山。"]'),
('71ad167b-e104-495a-8f66-034e98b1e748','寄題春谷監簿','胡仲弓','宋','宋诗','song-poetry','','[]','敲碎吟扉杳不聞，數聲犬吠谷中雲。',32,'全唐诗/poet.song.220000.json','["敲碎吟扉杳不聞，數聲犬吠谷中雲。", "幾番欲去重回首，立盡斜陽不見君。"]'),
('949f7fe3-d231-4e8c-b585-efd0408d6e8e','丹青閣','胡仲弓','宋','宋诗','song-poetry','','[]','紫芝峰上一凭欄，煙草茫茫天地寬。',32,'全唐诗/poet.song.220000.json','["紫芝峰上一凭欄，煙草茫茫天地寬。", "眼界已隨流水去，丹青無復舊時看。"]'),
('64d63809-4c84-4b55-a721-28d21136d633','失題  其一','胡仲弓','宋','宋诗','song-poetry','','[]','抱琴終日坐槐庭，萬綠陰中一掬清。',32,'全唐诗/poet.song.220000.json','["抱琴終日坐槐庭，萬綠陰中一掬清。", "天地山河俱蔭芘，肯將風浪向人生。"]'),
('394a4870-d8cc-40f7-99e0-d0fc0545b7f2','失題  其二','胡仲弓','宋','宋诗','song-poetry','','[]','年來古道不堪行，盡避君厨俊傑名。',32,'全唐诗/poet.song.220000.json','["年來古道不堪行，盡避君厨俊傑名。", "莫枉錐刀鞭算手，且調金石擊撞聲。"]'),
('20649584-f326-4217-8342-bd602364e562','失題  其三','胡仲弓','宋','宋诗','song-poetry','','[]','謫居姜相庸奚損，貧殺元英直是清。',32,'全唐诗/poet.song.220000.json','["謫居姜相庸奚損，貧殺元英直是清。", "風月分來無著處，摩挲海眼看長鯨。"]'),
('2262f3ba-0f68-4f27-9c73-399f94d7275a','梅答','胡仲弓','宋','宋诗','song-poetry','','[]','多謝東君爲主張，十分霜雪十分香。',32,'全唐诗/poet.song.220000.json','["多謝東君爲主張，十分霜雪十分香。", "開時已辦和羹料，肯作風流時世裝。"]'),
('186c64e5-ae78-42ee-9ebc-94f379b3e497','西湖寒食','胡仲弓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寒食風光不動塵，西湖幾處淚沾巾。',32,'全唐诗/poet.song.220000.json','["寒食風光不動塵，西湖幾處淚沾巾。", "客中忽作松楸夢，羞見原頭滴酹人。"]'),
('03e9bde4-8387-46cb-af31-695ac88e0f53','西陵橋','胡仲弓','宋','宋诗','song-poetry','','[]','界破蘇公十里堤，雕梁軋水漾虹霓。',32,'全唐诗/poet.song.220000.json','["界破蘇公十里堤，雕梁軋水漾虹霓。", "杜鵑也戀錢唐景，不向西陵橋上啼。"]'),
('1a784ee8-98b6-4337-9bac-ba9046da64dc','梅坡席上次韻牡丹  其一','胡仲弓','宋','宋诗','song-poetry','','[]','爲甚花神受氣偏，却來南地逞春妍。',32,'全唐诗/poet.song.220000.json','["爲甚花神受氣偏，却來南地逞春妍。", "鞓紅未數青州種，粉白猶疑洛浦仙。"]'),
('7769946b-6829-47f2-850d-b794f7a16c0d','梅坡席上次韻牡丹  其二','胡仲弓','宋','宋诗','song-poetry','','[]','不學時粧添酒暈，休將風景對茶前。',32,'全唐诗/poet.song.220000.json','["不學時粧添酒暈，休將風景對茶前。", "沈香亭北空回首，目斷關河萬里天。"]'),
('18b8d70f-a3c0-43b1-875e-f1552a5e279f','失題','胡仲弓','宋','宋诗','song-poetry','','[]','一別家山不計程，斷人腸處若爲情。',32,'全唐诗/poet.song.220000.json','["一別家山不計程，斷人腸處若爲情。", "客牀欲結鴛鴦夢，夜夜相思睡不成。"]'),
('281ac52d-7b1d-4c9e-9fb4-fa7f38c85325','柬石軒','胡仲弓','宋','宋诗','song-poetry','','[]','便著工夫去看山，蘭亭未遇莫空還。',32,'全唐诗/poet.song.220000.json','["便著工夫去看山，蘭亭未遇莫空還。", "向來一段風流事，只在茂林脩竹間。"]'),
('6974a663-cd35-43b8-b731-73b9837557ec','義谿舟中','胡仲弓','宋','宋诗','song-poetry','','[]','夢裏不知身是客，却疑身是老坡仙。',32,'全唐诗/poet.song.220000.json','["夢裏不知身是客，却疑身是老坡仙。", "羽衣道士飛將去，月在波心人在船。"]'),
('5ce3001f-f6af-44ac-846a-c897ecbac2e5','春遊','胡仲弓','宋','宋诗','song-poetry','','[]','不爲尋芳出錦城，偶隨吟杖繞山行。',32,'全唐诗/poet.song.220000.json','["不爲尋芳出錦城，偶隨吟杖繞山行。", "春風的是多情物，吹下紅樓笑語聲。"]'),
('05b5cfb3-ac2f-4092-8aa8-b7185ab3df91','遊天竺靈隠三絕  其一','胡仲弓','宋','宋诗','song-poetry','','[]','遊山此是第三回，天竺禪門八字開。',32,'全唐诗/poet.song.220000.json','["遊山此是第三回，天竺禪門八字開。", "已斷此生休佞佛，又隨人去乞靈來。"]'),
('83d5ec54-e84b-4991-9de6-e30e895d6144','遊天竺靈隠三絕  其二','胡仲弓','宋','宋诗','song-poetry','','[]','呼猿纔了復臨流，洗出胸中一派秋。',32,'全唐诗/poet.song.220000.json','["呼猿纔了復臨流，洗出胸中一派秋。", "泉石世間真富貴，幾生修得到巢由。"]'),
('5c776ad4-af74-4c35-ae63-55bb954388bc','遊天竺靈隠三絕  其三','胡仲弓','宋','宋诗','song-poetry','','[]','冷泉亭角坐移時，試看孤峰飛不飛。',32,'全唐诗/poet.song.220000.json','["冷泉亭角坐移時，試看孤峰飛不飛。", "峰自不飛人自醉，暮鴉棲了更忘歸。"]'),
('c3b6dd14-3588-45d9-95ac-13e2359d8aca','感懷','胡仲弓','宋','宋诗','song-poetry','','[]','曾將敝帚棄牆陰，十載塵埃懶重尋。',32,'全唐诗/poet.song.220000.json','["曾將敝帚棄牆陰，十載塵埃懶重尋。", "今日携來掃花徑，老夫安得不關心。"]'),
('63734936-ed2c-4822-bf72-4ab787a7398e','讀杜牧之詩','胡仲弓','宋','宋诗','song-poetry','','[]','風流不減晉諸賢，湧出胸中萬斛泉。',32,'全唐诗/poet.song.220000.json','["風流不減晉諸賢，湧出胸中萬斛泉。", "吟到秦淮商女句，令人憶殺杜樊川。"]'),
('b5c08dc8-3cb7-4479-997e-baf771ac5a75','山村即事','胡仲弓','宋','宋诗','song-poetry','','[]','春風無厚薄，隨分到山村。',48,'全唐诗/poet.song.220000.json','["春風無厚薄，隨分到山村。", "歌吹行南陌，鞦韆出短垣。", "稻田喧鳥雀，社鼓賽鷄豚。", "何事條桑月，人家緊閉門。"]'),
('07478cbb-3b77-4ee4-9368-39cd9383988e','送丁仲圭歸合沙','胡仲弓','宋','宋诗','song-poetry','','[]','去秋曾作送行詩，又見貞人話別離。',32,'全唐诗/poet.song.220000.json','["去秋曾作送行詩，又見貞人話別離。", "楊柳柔條未堪折，梅花聊贈歲寒枝。"]'),
('1d01017f-c041-4e3d-b529-4039cd6adb22','落花','胡仲弓','宋','宋诗','song-poetry','','[]','紅紫穠時雨未晴，每將春事嘆浮生。',64,'全唐诗/poet.song.220000.json','["紅紫穠時雨未晴，每將春事嘆浮生。", "誰憐綉地愁如織，我欲箋天訴不平。", "半點蒼苔猶有迹，一分流水去無情。", "東君更作風光主，蝶粉蜂黄莫浪爭。"]'),
('0c4fefa5-6100-43f6-8345-954a667f387b','思故鄉','胡仲弓','宋','宋诗','song-poetry','','[]','隨龍南渡後，五世作泉人。',48,'全唐诗/poet.song.220000.json','["隨龍南渡後，五世作泉人。", "僅識傳家譜，空餘報國身。", "中原無馬跡，鉅野隔邊塵。", "北定知何日，歸期未有因。"]'),
('1cda0777-73d6-4fb1-9fa1-a83062e7ec74','五峰巖','胡仲弓','宋','宋诗','song-poetry','','[]','開到荼䕷春事闌，又尋杖履看青山。',64,'全唐诗/poet.song.220000.json','["開到荼䕷春事闌，又尋杖履看青山。", "人行瘦石枯藤上，路入蠻風瘴雨間。", "佛地平分天界限，道場元屬鬼門關。", "野僧不會遊人意，日未晡時及早還。"]'),
('b543f46e-b2df-42f2-bca7-c6dd4b83912a','雲根','胡仲弓','宋','宋诗','song-poetry','','[]','出岫無心直等閑，却於天運頗相關。',32,'全唐诗/poet.song.220000.json','["出岫無心直等閑，却於天運頗相關。", "五雲飛繞黄金闕，留得雲根在越山。"]'),
('51167651-04fb-4dc9-8c1f-d0fe67723f2e','題天海風雲之樓','胡仲弓','宋','宋诗','song-poetry','','[]','欲艤扁舟約月明，倚樓少待暮潮平。',64,'全唐诗/poet.song.220000.json','["欲艤扁舟約月明，倚樓少待暮潮平。", "雁邊有客關新恨，鷗外無人訪舊盟。", "天地能容蒼海闊，風波難與白雲爭。", "回頭便踏塵埃路，莫忘山中此段清。"]'),
('e3687c67-f36c-4f7e-9c0d-e049f48dfecc','宮怨','胡仲參','宋','宋诗','song-poetry','','[]','淚粉羞臨寶鑑前，淡粧爭似舊嬋娟。',32,'全唐诗/poet.song.220000.json','["淚粉羞臨寶鑑前，淡粧爭似舊嬋娟。", "一言曾忤君王意，閉在長門十五年。"]'),
('3b3e3aa8-96a2-4d42-85a3-1a96eef1e9ca','寄竹院方丈孚師','胡仲參','宋','宋诗','song-poetry','','[]','江湖歲月易銷磨，振錫歸來鬢欲皤。',64,'全唐诗/poet.song.220000.json','["江湖歲月易銷磨，振錫歸來鬢欲皤。", "性懶吟編多散逸，門閑俗客少經過。", "虛檐破處懸蛛網，落葉空中見鳥窠。", "一片師心誰會得，半窗竹影綠婆娑。"]'),
('540f4366-08f2-4ff2-a726-25b4d74a2897','郊行暮歸','胡仲參','宋','宋诗','song-poetry','','[]','吟罷歸來興欲狂，重城半掩傍昏黄。',64,'全唐诗/poet.song.220000.json','["吟罷歸來興欲狂，重城半掩傍昏黄。", "鐘聲遥動山靈答，月魄未高人影長。", "竹葉淺斟杯量窄，梅花滿插帽簷香。", "不妨竟日酬心賞，纔到明朝事又忙。"]'),
('a2bd41af-fa9b-4872-b781-27dfb19f709f','偶得','胡仲參','宋','宋诗','song-poetry','','[]','欲問梅花信，山寒去未能。',48,'全唐诗/poet.song.220000.json','["欲問梅花信，山寒去未能。", "靜思天外句，坐對夜深燈。", "戒酒頻添衲，煎茶旋鑿冰。", "月殘霜又落，無復叩門僧。"]'),
('029f7854-de33-419b-812c-eca289f2ed34','醜婦吟','胡仲參','宋','宋诗','song-poetry','','[]','君不見漢殿丹青未漫滅，馬上琵琶向誰說。',70,'全唐诗/poet.song.220000.json','["君不見漢殿丹青未漫滅，馬上琵琶向誰說。", "又不見華清舞破霓裳衣，凌波竟墮嵬山血。", "從來艷色多累身，妾貌雖醜心自悅。", "幽閨到老無人知，白髮如絲鏡如鐵。"]'),
('501ae79a-7db4-4f17-9e01-6ab25e91418c','晚雨','胡仲參','宋','宋诗','song-poetry','','[]','勃姑鴉舅叫樓西，春色陰晴景不齊。',32,'全唐诗/poet.song.220000.json','["勃姑鴉舅叫樓西，春色陰晴景不齊。", "濃墨四垂收未起，明邊一片夕陽低。"]'),
('5b81ef15-97e0-4262-a1ff-855e3db27613','端午','胡仲參','宋','宋诗','song-poetry','','[]','千年流水去滔滔，此日人來弔汨羅。',32,'全唐诗/poet.song.220000.json','["千年流水去滔滔，此日人來弔汨羅。", "江上畫船無買處，閉門風雨讀離騷。"]'),
('d2efb526-54ec-4e1b-a51c-9e0b31d3e5a7','山中作','胡仲參','宋','宋诗','song-poetry','','[]','村居便野性，况復是清秋。',48,'全唐诗/poet.song.220000.json','["村居便野性，况復是清秋。", "爲愛山間好，因成旬日留。", "林深喧鳥雀，露重滴松楸。", "昨夜新寒入，篝燈覆弊裘。"]'),
('8b873335-8266-42a3-8f4b-53281ced244d','入京第一程','胡仲參','宋','宋诗','song-poetry','','[]','六載館杭州，重來訪舊游。',48,'全唐诗/poet.song.220000.json','["六載館杭州，重來訪舊游。", "山中纔過雨，客裏又驚秋。", "嵐氣蒸衣濕，泉聲激石流。", "功名苦行役，羞見渡頭鷗。"]'),
('4ca87dcf-0785-41df-9961-aaa4f5372117','道中早發','胡仲參','宋','宋诗','song-poetry','','[]','未曉催行色，微吟獨據鞍。',48,'全唐诗/poet.song.220000.json','["未曉催行色，微吟獨據鞍。", "露垂星影濕，月淡水光寒。", "犬吠知村近，雞鳴覺夜殘。", "親闈在何許，誰念客衣單。"]'),
('fc2685b6-ea07-4442-bdea-5679f3ed1b80','秋晚泛湖','胡仲參','宋','宋诗','song-poetry','','[]','載酒湖邊買小舟，水光山色解人愁。',64,'全唐诗/poet.song.220000.json','["載酒湖邊買小舟，水光山色解人愁。", "短籬寂寂菊花晚，兩岸蕭蕭楊柳秋。", "落日波間收戲鼓，暮煙林外出歌樓。", "倚欄長嘯西風裏，驚起前汀雙白鷗。"]'),
('e728b197-b188-47dc-9b61-5bcf6c455b33','試後書懷','胡仲參','宋','宋诗','song-poetry','','[]','踏遍天涯路，春三秋又三。',48,'全唐诗/poet.song.220000.json','["踏遍天涯路，春三秋又三。", "文章與時背，言語對人慙。", "湖海氣何餒，山林分未甘。", "閑僧時過我，揮麈共玄談。"]'),
('478fc5f5-03bd-4650-a006-6d5cdb1a8a3e','夜坐偶成','胡仲參','宋','宋诗','song-poetry','','[]','一字吟難穩，沉沉夜向闌。',48,'全唐诗/poet.song.220000.json','["一字吟難穩，沉沉夜向闌。", "燈明妨短夢，衣薄犯新寒。", "千里家山遠，三年客路難。", "明朝有佳便，尺紙報平安。"]'),
('8e317bf1-7d8d-4a7a-adbb-3a0e80b4bc31','送諸葛春卿還里','胡仲參','宋','宋诗','song-poetry','','[]','扁舟分袂出湖濱，我向吳中君向閩。',64,'全唐诗/poet.song.220000.json','["扁舟分袂出湖濱，我向吳中君向閩。", "自笑吟身猶是客，却來遠道送行人。", "家山會友憑傳語，旅舍逢詩爲拂塵。", "天北天南相憶處，梅花毋惜一枝春。"]'),
('dbda623a-bc5b-4592-bf33-8c51b08732c3','得家書','胡仲參','宋','宋诗','song-poetry','','[]','手剝鱗緘細細看，北堂垂白喜平安。',32,'全唐诗/poet.song.220000.json','["手剝鱗緘細細看，北堂垂白喜平安。", "爲憐客裏多霜雪，寄得衣來正及寒。"]'),
('62287124-3aed-4f50-ad8c-0849f5d63377','雪晴泛湖','胡仲參','宋','宋诗','song-poetry','','[]','雪後湖清淺，令人心眼開。',48,'全唐诗/poet.song.220000.json','["雪後湖清淺，令人心眼開。", "林疏知寺近，冰合礙舟回。", "寒色欺吟鬢，斜陽入酒杯。", "山行已清絕，况復是尋梅。"]'),
('32990452-3b4a-4e62-aec5-4a2d95a0f495','春晚見山茶花一枝獨開','胡仲參','宋','宋诗','song-poetry','','[]','荼䕷開盡見山茶，血色嬌春带雨斜。',32,'全唐诗/poet.song.220000.json','["荼䕷開盡見山茶，血色嬌春带雨斜。", "莫是今年逢閏月，東風吹到背時花。"]'),
('74a42b87-b697-47be-89c3-b5f7391fe257','山中口占三首  其一','胡仲參','宋','宋诗','song-poetry','','[]','四野平田春水肥，前山隠隠带殘暉。',32,'全唐诗/poet.song.220000.json','["四野平田春水肥，前山隠隠带殘暉。", "千林晚色無人共，時有樵翁獨自歸。"]'),
('9f7fc3bc-b5bf-425f-b0a4-7d33eaeb1dd5','山中口占三首  其二','胡仲參','宋','宋诗','song-poetry','','[]','躑躅花開野色濃，和風和雨卧叢叢。',32,'全唐诗/poet.song.220000.json','["躑躅花開野色濃，和風和雨卧叢叢。", "城中只買零枝看，那似山頭滿樹紅。"]'),
('d039842e-3bb0-4705-9be1-b3220930b6ad','山中口占三首  其三','胡仲參','宋','宋诗','song-poetry','','[]','飯罷呼僮旋煮茶，棋枰詩卷小生涯。',32,'全唐诗/poet.song.220000.json','["飯罷呼僮旋煮茶，棋枰詩卷小生涯。", "從今厭踏紅塵路，多在山間少在家。"]'),
('7c12ddbb-0c92-4958-be12-91a00672376e','夜坐即事','胡仲參','宋','宋诗','song-poetry','','[]','午夜空庭寂，心閑坐亦忘。',48,'全唐诗/poet.song.220000.json','["午夜空庭寂，心閑坐亦忘。", "竹間風動靜，雲裏月行藏。", "驚鵲出幽樹，寒螿語廢廊。", "甌茶聊當酒，清氣入詩腸。"]'),
('ef274139-f098-49a7-be35-b86ee25f3541','題墨梅竹','胡仲參','宋','宋诗','song-poetry','','[]','洗盡丹青料，清高絕點埃。',48,'全唐诗/poet.song.220000.json','["洗盡丹青料，清高絕點埃。", "數竿無韻竹，一樹不香梅。", "與可今已矣，補之安在哉。", "千年好風致，喚上筆頭來。"]'),
('ca41dc9d-9bf3-43ff-8c7d-fc805a09e98d','聽雨','胡仲參','宋','宋诗','song-poetry','','[]','聽盡燈前細雨聲，聲聲總是別離情。',32,'全唐诗/poet.song.220000.json','["聽盡燈前細雨聲，聲聲總是別離情。", "何時斷得閑煩惱，一任芭蕉滴到明。"]'),
('c4a6436c-a8c0-45ee-ae99-90329b8b1fdc','夜坐與伯氏葦航對床閲江湖詩偶成一首','胡仲參','宋','宋诗','song-poetry','','[]','對床因話弟兄情，話到山林世念輕。',64,'全唐诗/poet.song.220000.json','["對床因話弟兄情，話到山林世念輕。", "几上江湖詩一卷，窗前燈火夜三更。", "茶經未展神先爽，香片纔燒味較清。", "吟罷忽聞譙角動，石橋霜曉有人行。"]'),
('aae44ac2-b7e5-4ff9-a6ef-4d5415ad7df1','薄暮','胡仲參','宋','宋诗','song-poetry','','[]','薄暮抱幽獨，無言倚小樓。',48,'全唐诗/poet.song.220000.json','["薄暮抱幽獨，無言倚小樓。", "日沉千樹晚，風起一天秋。", "警枕團新夢，寒衣带舊愁。", "祇因吟太苦，餘病未全瘳。"]'),
('1f1e6788-9d9e-45af-b155-ff5dbb695db0','山行','胡仲參','宋','宋诗','song-poetry','','[]','石磴手難攀，林深去復還。',48,'全唐诗/poet.song.220000.json','["石磴手難攀，林深去復還。", "人行啼鳥外，僧住白雲間。", "野興平秋水，吟魂繞暮山。", "馬頭風作惡，潘鬢任闌珊。"]'),
('7195c7ab-3d07-4299-a9d8-fb81a9ae31b2','月夜聽琴效漁父辭','胡仲參','宋','宋诗','song-poetry','','[]','風入古松成節奏，泉奔幽磴響琮琤。',48,'全唐诗/poet.song.220000.json','["風入古松成節奏，泉奔幽磴響琮琤。", "琴中彈意不彈聲，猛拂朱絃燈焰落。", "細敲玉版夢魂清，啼烏枝上月三更。"]'),
('90182e5f-9f81-411f-bb6b-0226930dc6b5','寒中偶題','胡仲參','宋','宋诗','song-poetry','','[]','酒對紅爐暖，香凝繡被溫。',24,'全唐诗/poet.song.220000.json','["酒對紅爐暖，香凝繡被溫。", "老天有私意，寒不到朱門。"]'),
('b2d2c65e-c677-4b27-b95a-4eba70ea3a19','枕上得句寄潜君升','胡仲參','宋','宋诗','song-poetry','','[]','無奈篷窗雪打聲，夢魂纔穩又還驚。',32,'全唐诗/poet.song.220000.json','["無奈篷窗雪打聲，夢魂纔穩又還驚。", "枕衾如許猶嫌冷，多少閻閭睡不成。"]'),
('87cdc829-bf3a-43cb-8831-23ff0bcefc1a','留宿陳氏書齋','胡仲參','宋','宋诗','song-poetry','','[]','因訪吟朋到竹居，春寒策策動窗虛。',64,'全唐诗/poet.song.220000.json','["因訪吟朋到竹居，春寒策策動窗虛。", "幾番好雨偏留客，一盞青燈共讀書。", "徐孺舊曾親下榻，陳遵見說好投車。", "與君靜夜評心事，萬斛閑愁盡掃除。"]'),
('15b35e21-1799-4f3f-8500-816f226d37a1','游白石山觀音寺','胡仲參','宋','宋诗','song-poetry','','[]','綠陰深處石橋橫，纔入山門意便清。',32,'全唐诗/poet.song.220000.json','["綠陰深處石橋橫，纔入山門意便清。", "林下一僧無箇事，時來倚樹聽泉聲。"]'),
('99251b5a-a93e-4754-b6e4-5093c94f70d1','與生上人','胡仲參','宋','宋诗','song-poetry','','[]','久住深山裏，相忘物外形。',48,'全唐诗/poet.song.220000.json','["久住深山裏，相忘物外形。", "逢人出好語，入定掩殘經。", "古字碑成軸，名詩榜作屏。", "欲知祖師意，柏樹在中庭。"]'),
('ddc1e2eb-b814-4c92-b981-0b0efa867e85','雨中','胡仲參','宋','宋诗','song-poetry','','[]','愁坐黄昏掩客扉，風翻霜葉滿庭飛。',32,'全唐诗/poet.song.220000.json','["愁坐黄昏掩客扉，風翻霜葉滿庭飛。", "孤燈挑到寒更盡，猶有行人带雨歸。"]'),
('ae17deed-980a-4df7-ba99-bee3d8d6eb1a','讀岳鄂王行實','胡仲參','宋','宋诗','song-poetry','','[]','飛鵠來何意，英雄此日生。',48,'全唐诗/poet.song.220000.json','["飛鵠來何意，英雄此日生。", "山河張膽氣，宇宙載風聲。", "一片堂中紙，千年身後名。", "至今墳上木，猶作不平鳴。"]'),
('192d7815-3a72-4152-badf-23de81ce9c83','和林梅臞西淙瀑布圖韻','胡仲參','宋','宋诗','song-poetry','','[]','瀑駛驚風雨，危懸峭壁前。',48,'全唐诗/poet.song.220000.json','["瀑駛驚風雨，危懸峭壁前。", "臨流清客耳，入夜攪幽眠。", "旁是龍爲廟，高疑山有仙。", "一塵飛不到，長似九秋天。"]'),
('8392e372-dfa8-4b0d-92b2-0cee4d96602b','喜郭希范自上庠歸','胡仲參','宋','宋诗','song-poetry','','[]','馬蹄明日是君家，千里歸來傍節華。',32,'全唐诗/poet.song.220000.json','["馬蹄明日是君家，千里歸來傍節華。", "幾夜深閨寒寂寂，有人和淚卜燈花。"]'),
('93c650a3-e949-420c-a81b-5c2a4ebd6f3c','用伯氏韻柬梅臞','胡仲參','宋','宋诗','song-poetry','','[]','榾柮爐前坐夜深，寒侵窗戶月西沉。',64,'全唐诗/poet.song.220000.json','["榾柮爐前坐夜深，寒侵窗戶月西沉。", "冥搜天地無窮趣，寫盡江湖一片心。", "霜葉落邊添客思，梅花瘦處動高吟。", "訪君欲問推敲訣，擬把清樽共細斟。"]'),
('6f54795e-8f0d-44ae-92c3-401fd6356666','柬竹院孚老','胡仲參','宋','宋诗','song-poetry','','[]','別來旬日許，又過一分春。',48,'全唐诗/poet.song.220000.json','["別來旬日許，又過一分春。", "因感塵中事，空慙物外人。", "吟清便境靜，語苦見情真。", "近况知何似，篇詩得細詢。"]'),
('2bcba9fa-bd60-41f2-b79c-7dc71c5a0da2','送梅臞還三山','胡仲參','宋','宋诗','song-poetry','','[]','十年湖海上，此日值梅兄。',48,'全唐诗/poet.song.220000.json','["十年湖海上，此日值梅兄。", "一見纔傾蓋，相逢又問程。", "新編聯畫卷，清話入詩評。", "從此雲山別，因風時寄聲。"]'),
('9dd0471d-e506-457f-a3c6-0f442e348c26','題雪舟雲心二友吟卷','胡仲參','宋','宋诗','song-poetry','','[]','君詩何所似，絕似晚唐詩。',48,'全唐诗/poet.song.220000.json','["君詩何所似，絕似晚唐詩。", "寫出春雲狀，融成白雪詞。", "百篇多態度，二妙一襟期。", "與我爲三友，他年題品誰。"]'),
('6b0425e8-be7d-4f3c-a3ab-1eb9632d1953','清明','胡仲參','宋','宋诗','song-poetry','','[]','杯酒濃澆壠上春，東風吹起紙灰塵。',32,'全唐诗/poet.song.220000.json','["杯酒濃澆壠上春，東風吹起紙灰塵。", "可堪腸斷中原路，草掩荒丘不見人。"]'),
('1f524802-9bdf-439f-90a9-ecfcd75ee571','寄黄雲心','胡仲參','宋','宋诗','song-poetry','','[]','竹屋少行跡，閉門春晝長。',48,'全唐诗/poet.song.220000.json','["竹屋少行跡，閉門春晝長。", "天時半晴濕，人意共炎凉。", "苔蘚侵階綠，荼䕷壓架香。", "冥搜尋杖屨，不爲看花忙。"]'),
('9d301212-ae0f-43fd-8afb-10a9aff4d5be','采桑女','胡仲參','宋','宋诗','song-poetry','','[]','葉滿筐箱花滿簪，低頭微笑出桑陰。',32,'全唐诗/poet.song.220000.json','["葉滿筐箱花滿簪，低頭微笑出桑陰。", "後來若有秋胡子，說與黄金必動心。"]'),
('cf51b748-e2d3-4d02-b8ef-86d86c77d8fc','過永春縣','胡仲參','宋','宋诗','song-poetry','','[]','距城纔百里，世路便難平。',48,'全唐诗/poet.song.220000.json','["距城纔百里，世路便難平。", "碣石唐人墓，桃源晉地名。", "危譙依嶽勢，荒市带溪聲。", "往日罹兵火，頹垣蔓草生。"]'),
('8a7fc82f-6d17-495c-a4c9-ef18dae05ae7','圩田','胡仲參','宋','宋诗','song-poetry','','[]','圩田依澗水，入夏未栽禾。',24,'全唐诗/poet.song.220000.json','["圩田依澗水，入夏未栽禾。", "不是春耕晚，山中寒氣多。"]'),
('31515b79-8a56-4f57-9853-745a2a87d276','閨中詞  其一','胡仲參','宋','宋诗','song-poetry','','[]','寫就相思字，燈前带淚看。',24,'全唐诗/poet.song.220000.json','["寫就相思字，燈前带淚看。", "欲緘還未忍，少待淚痕乾。"]'),
('312aa1b7-9b82-4e96-9650-4eb27ea53b5f','閨中詞  其二','胡仲參','宋','宋诗','song-poetry','','[]','聽盡芭蕉雨，愁人夜不眠。',24,'全唐诗/poet.song.220000.json','["聽盡芭蕉雨，愁人夜不眠。", "憑誰將此意，爲妾到郎邊。"]'),
('6c5b3790-4b06-4299-8dd4-106b81061383','早發','胡仲參','宋','宋诗','song-poetry','','[]','早發六七里，前途曙未分。',48,'全唐诗/poet.song.220000.json','["早發六七里，前途曙未分。", "漁舟依岸立，水碓隔溪聞。", "獨樹支殘月，空山半白雲。", "清晨那可駐，日出又如焚。"]'),
('3433a548-74ca-4775-9af5-6fea3d26b0c9','無題','胡仲參','宋','宋诗','song-poetry','','[]','露重濕征衣，風急翻紗帽。',24,'全唐诗/poet.song.220000.json','["露重濕征衣，風急翻紗帽。", "山下灌園人，倚鋤看馬過。"]'),
('291c6c42-6aa7-4c7d-9075-3ed2e8d61f37','過界首','胡仲參','宋','宋诗','song-poetry','','[]','幾重嶺隔幾重灣，路入濛濛煙雨間。',32,'全唐诗/poet.song.220000.json','["幾重嶺隔幾重灣，路入濛濛煙雨間。", "獨立溪橋重回首，前頭已是劍州山。"]'),
('9985bbc0-237b-4e6f-9d70-f6cf50137ac0','思家','胡仲參','宋','宋诗','song-poetry','','[]','夜夢到山居，回頭千里餘。',48,'全唐诗/poet.song.220000.json','["夜夢到山居，回頭千里餘。", "屢傳歸去信，不得寄來書。", "小逕應添笋，荒畦欠理蔬。", "客程頻得雨，田里事何如。"]'),
('d811c04d-20ef-449a-9616-a43cbbd49b77','漁梁嶺禹廟','胡仲參','宋','宋诗','song-poetry','','[]','古今陳迹幾興亡，閩嶺何因祀夏王。',32,'全唐诗/poet.song.220000.json','["古今陳迹幾興亡，閩嶺何因祀夏王。", "莫是當年平水日，曾驅魚鱉渡漁梁。"]'),
('802058ca-36d5-4b9a-a825-1035bbfc4e74','陵上','胡仲參','宋','宋诗','song-poetry','','[]','身爲功名役，因思隠者賢。',24,'全唐诗/poet.song.220000.json','["身爲功名役，因思隠者賢。", "只行山後路，羞過釣臺前。"]'),
('a4f69674-8867-45a4-ad47-62073c614989','西湖會上和趙靖軒韻','胡仲參','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不著人間半點愁，每於勝處一凭樓。',64,'全唐诗/poet.song.220000.json','["不著人間半點愁，每於勝處一凭樓。", "吟邊只欠林和靖，坐上追思馬少游。", "暈臉芙蕖酣薄暮，低眉楊柳拂新秋。", "酒闌拍掌狂歌舞，自是忘機可狎鷗。"]'),
('1b0eeca5-879a-4096-b3f0-3751df795671','秋意','胡仲參','宋','宋诗','song-poetry','','[]','梧葉飄殘客夢驚，擁衾危坐到天明。',64,'全唐诗/poet.song.220000.json','["梧葉飄殘客夢驚，擁衾危坐到天明。", "片心除是眉頭識，萬感都從念脚生。", "江上鱸肥銷旅况，樓前雁過带邊聲。", "挑燈無語閑商略，謀國謀家底計成。"]'),
('feaaffdd-f16c-418d-b5e8-acc5421b8465','還趙靖軒吟卷','胡仲參','宋','宋诗','song-poetry','','[]','借得君詩在案頭，篝燈夜夜看銀鈎。',32,'全唐诗/poet.song.220000.json','["借得君詩在案頭，篝燈夜夜看銀鈎。", "苦吟暗數秋更盡，何處笛聲人倚樓。"]'),
('d5889b88-330b-42c4-a61c-29e6b9117106','重陽','胡仲參','宋','宋诗','song-poetry','','[]','漫浪江湖已十霜，一秋强半又重陽。',64,'全唐诗/poet.song.220000.json','["漫浪江湖已十霜，一秋强半又重陽。", "可憐白日渾閑度，偶對黄花覺自傷。", "客舍題詩書感遇，市樓沽酒慰凄凉。", "登高不爲酬心賞，直欲凭欄望故鄉。"]'),
('5156d4f8-7f0c-40ae-aa28-4fd10aeb3ba9','夜來聞曾性之丘君就二友隔樓吟聲不絕以詩柬之','胡仲參','宋','宋诗','song-poetry','','[]','月下歸來深閉門，衾寒時倩博山溫。',32,'全唐诗/poet.song.220000.json','["月下歸來深閉門，衾寒時倩博山溫。", "隔樓忽聽吟聲苦，引得清愁入夢魂。"]'),
('2a901d39-60e2-4fd2-ab2a-a2d82652c754','問性之病','胡仲參','宋','宋诗','song-poetry','','[]','莫向推敲苦用心，聞君病裏亦沉吟。',64,'全唐诗/poet.song.220000.json','["莫向推敲苦用心，聞君病裏亦沉吟。", "書燈挑盡無人共，藥鼎煎殘到夜深。", "霜後菊花方寂寂，臘前梅事又駸駸。", "相看咫尺如千里，幾度逢人問信音。"]'),
('248ce911-2782-4804-bbbd-7d08e4939200','過千頃寺訪谷隠老','胡仲參','宋','宋诗','song-poetry','','[]','別久交情淡，重來似舊時。',48,'全唐诗/poet.song.220000.json','["別久交情淡，重來似舊時。", "人生雲聚散，世事月盈虧。", "茶具權行酒，禪牀借看詩。", "漫天多雪意，預約探梅期。"]'),
('817791b8-d157-4c81-ba49-738338092fce','性之尋梅歸來有詩因感一絕','胡仲參','宋','宋诗','song-poetry','','[]','處士廬前門逕深，僅留佳句與人吟。',32,'全唐诗/poet.song.220000.json','["處士廬前門逕深，僅留佳句與人吟。", "孤山近日無行路，疏影暗香何處尋。"]'),
('5b14e3e5-2242-4367-acc9-0c8850913b72','枕上偶成','胡仲參','宋','宋诗','song-poetry','','[]','客樓蕭索抱愁眠，雁過聲聲到枕邊。',64,'全唐诗/poet.song.220000.json','["客樓蕭索抱愁眠，雁過聲聲到枕邊。", "念脚動如魚撥剌，吟身寒似鷺聯拳。", "匣中幸有劉琨劍，囊裏猶餘杜老錢。", "忽憶西山山下路，夜深霜露滴松阡。"]'),
('b121d73b-00d9-4716-ac50-befc6999316e','夾河中有矮道人自住小舟持呪爲生人莫不異之者','胡仲參','宋','宋诗','song-poetry','','[]','道人神貌古，雙鬢欲垂肩。',48,'全唐诗/poet.song.220000.json','["道人神貌古，雙鬢欲垂肩。", "坐席容三尺，浮家住一船。", "養生憑佛果，持鉢信人緣。", "早泊橋梁下，蓬頭起白煙。"]'),
('eb9ae41c-957d-4bde-bfc4-8e7a894eb672','寄懶庵','胡仲參','宋','宋诗','song-poetry','','[]','天寒日短道路長，白雲飛處知吾鄉。',144,'全唐诗/poet.song.220000.json','["天寒日短道路長，白雲飛處知吾鄉。", "大江之東渭之北，念我故人何可忘。", "別來楊柳春依依，只今開到梅花香。", "扁舟漫浪歸未得，京塵海裏安行藏。", "身名未立仰天笑，牀頭夜夜鳴干將。", "羨師物外無寵辱，庭前柏樹常蒼蒼。", "吁嗟念羽飛不到，二千里外空相望。", "五雲前墜滿室光，報師之意無以將。", "篇詩濃墨纔淋浪，一聲雁過天南翔。"]'),
('27cd5f83-1918-4d0a-aade-47ff623eb95e','偶得','胡仲參','宋','宋诗','song-poetry','','[]','挑燈伴寒夜，兀坐竹爐邊。',24,'全唐诗/poet.song.220000.json','["挑燈伴寒夜，兀坐竹爐邊。", "赤脚知吟苦，時將山茗煎。"]'),
('b2390839-df95-4b56-9270-837ee845521b','和性之見寄韻','胡仲參','宋','宋诗','song-poetry','','[]','窗燭銷殘轉寂寥，柴門無復野僧敲。',64,'全唐诗/poet.song.220000.json','["窗燭銷殘轉寂寥，柴門無復野僧敲。", "偶來枕上吟詩就，記向心頭欠筆抄。", "鳴竹數聲疑雪片，尋梅清夢到山坳。", "世情雲雨多翻覆，誰是江湖耐久交。"]'),
('72703435-4a18-4543-964f-a08c9863a640','游山中','胡仲參','宋','宋诗','song-poetry','','[]','世途平處起波瀾，輸與高僧占好山。',64,'全唐诗/poet.song.220000.json','["世途平處起波瀾，輸與高僧占好山。", "竹麈直爲揮俗具，槿籬虛設掩塵關。", "林泉有分酬清供，瓶錫無人伴此閑。", "擺脫名韁須早計，半生猶得住雲間。"]'),
('8b062e3a-0e88-47a5-86e2-e3f006d6a616','寒夜作','胡仲參','宋','宋诗','song-poetry','','[]','生計尚茫茫，微吟思故鄉。',48,'全唐诗/poet.song.220000.json','["生計尚茫茫，微吟思故鄉。", "羈愁消不盡，寒夜未爲長。", "門掩梅花月，禽翻竹葉霜。", "挑燈裁錦字，明發有歸航。"]'),
('014642ec-d8b5-4927-be97-356f2c018dab','讀秦紀','胡仲參','宋','宋诗','song-poetry','','[]','萬雉雲邊萬馬屯，築來直欲障胡塵。',32,'全唐诗/poet.song.220000.json','["萬雉雲邊萬馬屯，築來直欲障胡塵。", "誰知斬木爲干者，只是長城裏面人。"]'),
('142efc45-42d1-4ec3-8b76-21f21a443b5f','雪','胡仲參','宋','宋诗','song-poetry','','[]','凝雲商作雪，頃刻滿天涯。',48,'全唐诗/poet.song.220000.json','["凝雲商作雪，頃刻滿天涯。", "片片疏還密，霏霏整復斜。", "映窗疑月影，著地似楊花。", "四望渾同色，微茫認點鴉。"]'),
('60860601-c6b2-426e-9ea1-8b10a5ff3b61','用馮深居韻題莆陽章氏環翠樓','胡仲參','宋','宋诗','song-poetry','','[]','百尺危梯眇海寰，欄干十二盡青山。',64,'全唐诗/poet.song.220000.json','["百尺危梯眇海寰，欄干十二盡青山。", "煙光濃淡藏多景，野水周遭匝四環。", "勝地只宜騷客住，老天未放主人閑。", "憑誰說與九仙道，方丈移來在此間。"]'),
('09fd0829-fbc2-46df-a55a-d141e31ee31d','書懷呈曾性之','胡仲參','宋','宋诗','song-poetry','','[]','覽鏡嘆頭顱，梅花一樣臞。',48,'全唐诗/poet.song.220000.json','["覽鏡嘆頭顱，梅花一樣臞。", "病因吟後有，愁到醉邊無。", "心事歸梁燕，年華過隙駒。", "世途難著脚，况復是江湖。"]'),
('baf26496-b613-4101-9aa8-69fa60588a95','和伯氏春雨中韻  其一','胡仲參','宋','宋诗','song-poetry','','[]','癡寒脈脈壓晴莎，春漸三分景未和。',32,'全唐诗/poet.song.220000.json','["癡寒脈脈壓晴莎，春漸三分景未和。", "待得濃陰收拾後，花邊春色已無多。"]'),
('8eacc1fe-9e7c-450f-bfa8-9016f6617849','和伯氏春雨中韻  其二','胡仲參','宋','宋诗','song-poetry','','[]','兩堤楊柳拂新亭，怪底遊人懶踏青。',32,'全唐诗/poet.song.220000.json','["兩堤楊柳拂新亭，怪底遊人懶踏青。", "手撚梨花成小立，半窗湖水雨冥冥。"]'),
('f2fcf132-0037-4cc2-8129-4ef5d58117c3','寄梅臞','胡仲參','宋','宋诗','song-poetry','','[]','別去忽經旬，春風閲二分。',48,'全唐诗/poet.song.220000.json','["別去忽經旬，春風閲二分。", "幾番吟對雨，獨自暗思君。", "客裏加頻病，愁邊駭近聞。", "倚欄商不得，心目亂於雲。"]'),
('f8fdfe43-4116-4024-998b-f7fa442d0ef3','和伯氏包山觀桃花韻','胡仲參','宋','宋诗','song-poetry','','[]','因訪桃花到嶺根，御林春色此平分。',64,'全唐诗/poet.song.220000.json','["因訪桃花到嶺根，御林春色此平分。", "千株未數栽唐觀，一幅猶堪畫晉源。", "仙在雲間無處覓，人行風外有香聞。", "笙簫隠隠宮城隔，立盡黄昏更斷魂。"]'),
('bdf8d507-c08b-4f22-88aa-7234d793b6ab','蕭山望城中遺','胡仲參','宋','宋诗','song-poetry','','[]','見說天文變，頻占太史臺。',48,'全唐诗/poet.song.220000.json','["見說天文變，頻占太史臺。", "但云星犯月，不料火爲災。", "盡夜看煙滅，逢人問訊來。", "丹心勤戀闕，東向極裴回。"]'),
('0a51ca4e-c94c-4793-9d93-5c90338d5ecf','吳王試劍石','胡仲參','宋','宋诗','song-poetry','','[]','吳王鑄劍成，自謂古難比。',68,'全唐诗/poet.song.220000.json','["吳王鑄劍成，自謂古難比。", "試之高山巔，石裂斷橫理。", "那無昔時人，相逢干將里。", "故宮宮中白日長，春風野田百草香。", "有誰慷慨不平事，被褐踏花推酒缸。"]'),
('41bb90e2-7749-41ec-91f6-42a58d9e5981','次林庭植留別韻','胡仲參','宋','宋诗','song-poetry','','[]','麴生皆可醉，何必問醇醨。',48,'全唐诗/poet.song.220000.json','["麴生皆可醉，何必問醇醨。", "浩氣長看劍，愁腸半貯詩。", "歸舟無麥載，去路有梅隨。", "瘴海風波惡，此行君自知。"]'),
('dde64494-3949-46a3-8b45-fcdf92b5e1b6','王用和屢言別而未歸頤齋有詩戲之次韻奉寄','胡仲參','宋','宋诗','song-poetry','','[]','幾度西郊餞馬塵，曾將尺素託文鱗。',64,'全唐诗/poet.song.220000.json','["幾度西郊餞馬塵，曾將尺素託文鱗。", "荷盃酌盡開懷酒，柳線縈回有脚春。", "瘴海自多流落客，陽關少見別離人。", "出門有礙何爲者，徒負江湖老大身。"]'),
('47c11217-d125-45ad-8c4d-459101f3eed8','留別社友','胡仲參','宋','宋诗','song-poetry','','[]','漫浪歸來六換秋，又携書劍入皇州。',64,'全唐诗/poet.song.220000.json','["漫浪歸來六換秋，又携書劍入皇州。", "得些湖海元龍氣，作箇山川司馬遊。", "奔走客城因念脚，勾牽時事上眉頭。", "中朝滿目皆知己，還有篇詩遣寄不。"]'),
('f9a6ae9a-de47-4b2b-a569-c21ba114cbea','和王和禮留別韻','胡仲參','宋','宋诗','song-poetry','','[]','歸騎怱怱十日程，客身猶自戀桐城。',64,'全唐诗/poet.song.220000.json','["歸騎怱怱十日程，客身猶自戀桐城。", "未應江左追王建，且去隆中卧孔明。", "雞黍幾番陪夜話，鶑花一路伴伶聲。", "秦溪溪上無風浪，好與白鷗尋舊盟。"]'),
('67d547e5-e760-4638-89ea-810a2b11d7dd','胡葦航寄古劍','盛世忠','宋','宋诗','song-poetry','','[]','有人尺錦長安來，遠寄寶匣手自開。',96,'全唐诗/poet.song.220000.json','["有人尺錦長安來，遠寄寶匣手自開。", "紅雲紫氣燦虛室，鋏中青蛇鱗生苔。", "誠携掌握一揮動，瞬息天地興風雷。", "少年志氣老益壯，惟願聖詔下九垓。", "廐中我有汗血馬，與汝直北清氛埃。", "丈夫當爲國雪恥，笑指經生真不才。"]'),
('c5805765-421c-4959-b702-eb9553153e90','柴門','盛世忠','宋','宋诗','song-poetry','','[]','石砌苔初合，柴門手自開。',48,'全唐诗/poet.song.220000.json','["石砌苔初合，柴門手自開。", "日催花影轉，風遞竹聲來。", "蟹眼翻茶鼎，鵝兒灧酒杯。", "不須憂歲計，魁芋已新栽。"]'),
('c417288f-313e-4397-b17c-2cdd4efb1d9d','劉常簿席上','盛世忠','宋','宋诗','song-poetry','','[]','近授長生券，從天下綺筵。',48,'全唐诗/poet.song.220000.json','["近授長生券，從天下綺筵。", "潞公專洛日，呂望佐姬年。", "坐語風生舌，梳頭雪滿肩。", "上思耆舊用，飛詔到林泉。"]'),
('59ab80d9-f8ec-420d-b500-393588bd9b87','觀棋','盛世忠','宋','宋诗','song-poetry','','[]','爭先劉與項，得勢楚侵秦。',48,'全唐诗/poet.song.220000.json','["爭先劉與項，得勢楚侵秦。", "本是知心友，翻成敵國人。", "運籌爭劫殺，敗局在逡巡。", "袖手旁觀者，機深亦損神。"]'),
('6ebefe28-a973-465a-bc2c-1dba1901abdb','送呂東山之清漳','盛世忠','宋','宋诗','song-poetry','','[]','君是純陽派，神清性亦真。',48,'全唐诗/poet.song.220000.json','["君是純陽派，神清性亦真。", "有詩聊遣興，無術可醫貧。", "富貴皆尤物，江湖易老人。", "置山錢足矣，客路莫因循。"]'),
('9ff354ca-91df-402c-941b-ae9c048a97f4','寄藏叟僧善珍','盛世忠','宋','宋诗','song-poetry','','[]','訪友南山路，橋橫古木陰。',48,'全唐诗/poet.song.220000.json','["訪友南山路，橋橫古木陰。", "砌苔無俗跡，庭柏是禪心。", "舊衲連雲補，新詩带月吟。", "同袍嚴戒行，別是一叢林。"]'),
('b02de63b-b452-4f4c-980c-145086c630e7','生涯詩','盛世忠','宋','宋诗','song-poetry','','[]','壯歲欲飛騰，生涯亦可矜。',48,'全唐诗/poet.song.220000.json','["壯歲欲飛騰，生涯亦可矜。", "一千餘日戰，三十九年僧。", "硯枕秋風夢，書燈夜雨澄。", "儒生貴知命，飲水曲吾肱。"]'),
('1e006dd3-76d0-4ba5-8c4f-0576b1f5e261','簡賈戶部','盛世忠','宋','宋诗','song-poetry','','[]','十五年前別，相逢各老成。',48,'全唐诗/poet.song.220000.json','["十五年前別，相逢各老成。", "舊遊如一夢，忽見似重生。", "劇飲無人敵，高談坐客驚。", "諸郎尤可喜，事業短燈檠。"]'),
('0acd8ba9-45a5-4894-bfa8-d9d9e4058603','病起書院偶成','盛世忠','宋','宋诗','song-poetry','','[]','蓄水滋蘭畹，開窗近竹林。',48,'全唐诗/poet.song.220000.json','["蓄水滋蘭畹，開窗近竹林。", "敗糊黄螘鬨，斷簡老蟲侵。", "酒尚欺人病，詩能對客吟。", "晨昏一飽足，此外不關心。"]'),
('61258df3-b002-4a5a-90fd-c6b9323556e2','秦竹溪校書清漳未回','盛世忠','宋','宋诗','song-poetry','','[]','茅齋雅稱竹方牀，風過疎籬有暗香。',64,'全唐诗/poet.song.220000.json','["茅齋雅稱竹方牀，風過疎籬有暗香。", "劇飲一冬成酒病，得閑終日爲詩忙。", "新移橘本便霜信，貪看梅花倚夕陽。", "相望故人三百里，十宵九夢到清漳。"]'),
('1ca52a32-49e3-4e81-a989-025939c8ef95','今是行呈劉以道','盛世忠','宋','宋诗','song-poetry','','[]','少年湖海誤加鞭，久戍歸歟暫息肩。',64,'全唐诗/poet.song.220000.json','["少年湖海誤加鞭，久戍歸歟暫息肩。", "時有故山來夢裏，更無愁緒到吟邊。", "晨餐全仰數畦菜，歲計尤逋二頃田。", "閑倚瘦筇長嘯處，此身疑是結繩前。"]'),
('369ef4ea-e96b-42ad-b122-77a3bdcb362b','塞上聞角','盛世忠','宋','宋诗','song-poetry','','[]','刁斗城頭夜月寒，一聲嗚咽到江干。',32,'全唐诗/poet.song.220000.json','["刁斗城頭夜月寒，一聲嗚咽到江干。", "梅花吹落渾閑事，白首征人淚暗彈。"]'),
('4aa03102-9499-4ad0-aa2b-12c1a6d099b8','倦妝圖','盛世忠','宋','宋诗','song-poetry','','[]','睡覺春山懶更添，起來餘恨鎖眉尖。',32,'全唐诗/poet.song.220000.json','["睡覺春山懶更添，起來餘恨鎖眉尖。", "料應春事關心曲，怕見楊花不捲簾。"]'),
('d1c2d3b6-4fc7-4f6d-a088-bffa6a040508','嬾讀書','盛世忠','宋','宋诗','song-poetry','','[]','不弄絲桐不作詩，槃池疊石學兒嬉。',32,'全唐诗/poet.song.220000.json','["不弄絲桐不作詩，槃池疊石學兒嬉。", "少年讀易都忘却，身似羲皇未畫時。"]'),
('7a4989b5-dc1a-4bda-bc2b-08bbacb575a0','王昭君','盛世忠','宋','宋诗','song-poetry','','[]','漢使南歸絕信音，氈庭青草始知春。',32,'全唐诗/poet.song.220000.json','["漢使南歸絕信音，氈庭青草始知春。", "蛾眉却解安邦國，羞殺麒麟閣上人。"]'),
('c14a5987-4384-4d20-8653-5c0eb98b1869','書事','葉采','宋','宋诗','song-poetry','','[]','雙雙瓦雀行書案，點點楊花入硯池。',32,'全唐诗/poet.song.220000.json','["雙雙瓦雀行書案，點點楊花入硯池。", "閒坐小窗讀周易，不知春去幾多時。"]'),
('6e325d40-f8d1-4281-b5a4-27ae918b1ed6','迎神詞','黄應龍','宋','宋诗','song-poetry','','[]','真人福地金庭宮，身佩含景蒼精龍。',187,'全唐诗/poet.song.220000.json','["真人福地金庭宮，身佩含景蒼精龍。", "坐朝五岳位顯崇，威儀衛從行虛空。", "杳眇濁世塵溟濛，神符道契浮丘公。", "英爽瑩澈表裏融，倏忽飛馭凌剛風。", "鳳凰承翼聲雝雝，胎仙舞導游方蓬。", "帝閔赤子顛厓中，旱乾水溢{疒眾}誰恫。", "分司百靈前豐窿，瓊臺琳宇環奇峰，時駕玉輅滄溟東。", "邇來烈日勢藴隆，稻田若枯病我農。", "字民所覬惟年豐，九關虎守呼莫從。", "高真慈念亟感通，天瓢一灑神馬騣。", "嘉惠千里成天工，靈貺億載垂無窮。"]'),
('4be839fe-6005-4007-a963-3687d8f4780f','寒瀑','陳栩','宋','宋诗','song-poetry','','[]','玄冥布令雨成雪，白瀑傾崖玉作花。',32,'全唐诗/poet.song.220000.json','["玄冥布令雨成雪，白瀑傾崖玉作花。", "坐愛奔聲空谷窅，幽深方覺是仙家。"]'),
('27a2de84-598c-4007-94ee-6026a21bbeb6','暮春','錢端琮','宋','宋诗','song-poetry','','[]','園林深處綠成堆，更著松陰一徑苔。',64,'全唐诗/poet.song.220000.json','["園林深處綠成堆，更著松陰一徑苔。", "煙欲過牆風約轉，水將爭港石衝回。", "斷雲收雨鳩呼婦，嫩麥盈堤雉應媒。", "獨有殘紅春不管，等閒飛入酒巵來。"]'),
('a40217c5-43a8-41cb-87df-f4dd1bb37345','青紫峰亭','錢益','宋','宋诗','song-poetry','','[]','壯歲事遠遊，衰齡守鄉井。',72,'全唐诗/poet.song.220000.json','["壯歲事遠遊，衰齡守鄉井。", "閒看舊遊地，偶陟黄旗嶺。", "因登青紫峰，雙目肆遐騁。", "孤亭倚山巔，當午風日冷。", "憑欄飛鳥外，振衣白雲頂。", "勝景浩無邊，此意君能領。"]'),
('abce3a8c-5852-4fb5-b5c8-c8849d0ef665','平元曲寄二弟植與格','陳碧娘','宋','宋诗','song-poetry','','[]','虎頭將軍眼如電，領兵夜渡龍舟堰。',192,'全唐诗/poet.song.220000.json','["虎頭將軍眼如電，領兵夜渡龍舟堰。", "良人腰懸大羽箭，廣西略地崖西戰。", "三年消息無鴻便，咫尺憑誰寄春怨。", "日長花柳暗庭院，斜倚妝樓倦針線。", "心懷良人幾時見，忽覩二郎來我面。", "植兮再吸傾六礶，格也一彈落雙燕。", "何不將我張郎西，協義維舟同虎闈。", "無術平寇報明主，恨身不是奇男子。", "倘妾當年未嫁夫，願學明妃和西虜。", "元人未知肯我許，我能管瑟又能舞。", "二弟慨然舍我去，日覩江頭淚如雨。", "幾回聞雞幾欲死，未審良人能再覩。"]'),
('98a7a5f8-174f-42e1-ad99-c34de18377d8','崖山六咏','陳格','宋','宋诗','song-poetry','','[]','戰艦衝風起怒濤，北船曉挫暮猶多。',48,'全唐诗/poet.song.220000.json','["戰艦衝風起怒濤，北船曉挫暮猶多。", "强胡難滿吞天慾，志士橫罹伏海號。", "一劍掛腰隨我去，萬方引領奈君何。"]'),
('86613dd6-cebe-4eac-accf-5e34842c7993','感舊','方岳','宋','宋诗','song-poetry','','[]','昔年訪月寒溪頭，霜高酒劣稜生裘。',64,'全唐诗/poet.song.220000.json','["昔年訪月寒溪頭，霜高酒劣稜生裘。", "溪僧輟寢從吾幽，共移不繫漁人舟。", "斷崖老木紛金虬，又如蘋藻涵清流。", "鶴骨浸煩風露憂，妙語滿地無人收。"]'),
('982491f6-c553-46d9-8d32-3f3ea2ae885b','鷺','方岳','宋','宋诗','song-poetry','','[]','聳兩吟肩似我愁，菰蒲葉下一身秋。',32,'全唐诗/poet.song.220000.json','["聳兩吟肩似我愁，菰蒲葉下一身秋。", "溪風昨夜吹魚落，飛過前灘看水流。"]'),
('8332f694-36a9-4bb6-a42b-0556223142e0','芭蕉','方岳','宋','宋诗','song-poetry','','[]','數葉芭蕉數葉秋，燈長雨久不眠愁。',32,'全唐诗/poet.song.220000.json','["數葉芭蕉數葉秋，燈長雨久不眠愁。", "靈溪寺裏夜曾聽，又聽靈溪溪水流。"]'),
('ea5e4102-cb80-418f-af4c-89157e1814fc','讀浯碑漫成一絕','張知復','宋','宋诗','song-poetry','','[]','開元天子樂昇平，肯向華清戒履冰。',32,'全唐诗/poet.song.220000.json','["開元天子樂昇平，肯向華清戒履冰。", "縱有浯溪溪上石，元郎何意頌中興。"]'),
('7e02bec1-035a-4330-a884-7d260cac71e3','上元遇雨','淳祐士人','宋','宋诗','song-poetry','','[]','隠隠雷聲天鼓吹，熒熒燈火夜星辰。',32,'全唐诗/poet.song.220000.json','["隠隠雷聲天鼓吹，熒熒燈火夜星辰。", "風流太守明如鏡，何用姮娥作主人。"]'),
('9b127ff6-178a-46b8-b548-37272f404589','山中吟','薛嵎','宋','宋诗','song-poetry','','[]','疎拙本天性，束書歸舊林。',48,'全唐诗/poet.song.220000.json','["疎拙本天性，束書歸舊林。", "世人皆失笑，泉石自知心。", "山柿紅猶澀，池魚靜亦沉。", "於中觀物意，吾道樂彌深。"]'),
('1f95796b-2cc8-47be-a098-21f347d906c7','題扶疏亭竹','薛嵎','宋','宋诗','song-poetry','','[]','風晴雨雪天，無趣不蕭然。',48,'全唐诗/poet.song.220000.json','["風晴雨雪天，無趣不蕭然。", "影過鄰家月，根通石下泉。", "長因終日看，憶得故山眠。", "物性今方會，心虛節自堅。"]'),
('5ef23b83-3518-4199-bca3-e7ea5f72a825','歲暮書懷','薛嵎','宋','宋诗','song-poetry','','[]','園林春又近，老態更無懽。',48,'全唐诗/poet.song.220000.json','["園林春又近，老態更無懽。", "添歲兒童喜，照貧燈火寒。", "直心嗟道喪，多事識才難。", "已種梅千樹，從今爛熳看。"]'),
('8309bf62-093d-4bee-86b1-7b30bf5854cc','賦中上人頑坐','薛嵎','宋','宋诗','song-poetry','','[]','嗜吟忘夜凍，立雪此同機。',48,'全唐诗/poet.song.220000.json','["嗜吟忘夜凍，立雪此同機。", "工苦精靈聚，毫端造化歸。", "石牀趺半結，荒徑葉頻飛。", "客至應相訝，無心聽扣扉。"]'),
('35256b20-dc45-490d-80b7-3d0ca57d79d2','賦陳子在瓢飲','薛嵎','宋','宋诗','song-poetry','','[]','羨爾甘貧居陋巷，遥知清德繼前脩。',64,'全唐诗/poet.song.220000.json','["羨爾甘貧居陋巷，遥知清德繼前脩。", "平時所樂從中得，外物雖微不過求。", "自枕曲肱安澹泊，閑挑拄杖亦風流。", "百千年內誰相望，寂寞箕山一許由。"]'),
('f80255b3-c39c-4877-a19f-3ba2cc50bfe2','舟泊曹娥祠下','薛嵎','宋','宋诗','song-poetry','','[]','身沒一朝事，孝名垂至今。',48,'全唐诗/poet.song.220000.json','["身沒一朝事，孝名垂至今。", "江空夜濤泣，日落霧天陰。", "社祭陳簫鼓，蠻歌進寶琛。", "予生無愧怍，風浪不驚心。"]'),
('2e70d763-8d5d-443f-b76d-d1f5f82ee448','旅中秋夜','薛嵎','宋','宋诗','song-poetry','','[]','車馬日西東，阮生途自窮。',48,'全唐诗/poet.song.220000.json','["車馬日西東，阮生途自窮。", "三年辭舊國，今日又秋風。", "邊雁凄凉過，池花寂寞紅。", "邦人慣相識，漸覺語音通。"]'),
('401124b8-b3a7-4f0a-ac8e-c4325b02c418','送劉荆山','薛嵎','宋','宋诗','song-poetry','','[]','束書入京闕，憂國最情深。',48,'全唐诗/poet.song.220000.json','["束書入京闕，憂國最情深。", "天意有興廢，人才無古今。", "布衣萬言疏，孤劍一生心。", "直道嗟難遇，賈生終陸沉。"]'),
('1f43075e-d729-46f5-bf30-f84656ba64bd','中秋家人翫月','薛嵎','宋','宋诗','song-poetry','','[]','年年照離別，今夕喜團欒。',48,'全唐诗/poet.song.220000.json','["年年照離別，今夕喜團欒。", "不是人心異，全勝昨夜看。", "八荒同皎潔，列宿讓清寒。", "自有銀河路，乘槎到不難。"]'),
('4d63dd1c-4857-48f2-a90c-e1bf84ddac74','古淡師然公遊方','薛嵎','宋','宋诗','song-poetry','','[]','野僧携錫別，何處度殘春。',48,'全唐诗/poet.song.220000.json','["野僧携錫別，何處度殘春。", "天地無窮事，江湖自在身。", "真心齊得物，道貌異於人。", "昔日安禪地，深山虎亦馴。"]'),
('733bfbec-f062-4e21-a16b-8a460fee6842','天育道中','薛嵎','宋','宋诗','song-poetry','','[]','除將吟卷外，琴與鶴相隨。',48,'全唐诗/poet.song.220000.json','["除將吟卷外，琴與鶴相隨。", "問寺路猶遠，入山僧未知。", "鳥靈巢佛塔，猿飲掛藤枝。", "陵谷幾遷變，道傍橫古碑。"]'),
('b543454d-b9e2-4eaa-8e48-8db51b1d6e29','山中古松','薛嵎','宋','宋诗','song-poetry','','[]','曾經雷斧劈，上有鶻巢腥。',48,'全唐诗/poet.song.220000.json','["曾經雷斧劈，上有鶻巢腥。", "過客誰摽紙，山精此托靈。", "虬龍雲際頂，龜鳥土中苓。", "月夜境荒寂，秋聲不可聽。"]'),
('55843c5f-f6c4-4164-8dd2-90723ed6d2c7','育王寺','薛嵎','宋','宋诗','song-poetry','','[]','寺在衆山裏，白雲深更深。',48,'全唐诗/poet.song.220000.json','["寺在衆山裏，白雲深更深。", "不知行樂意，何似坐禪心。", "護塔龍常在，倚松僧獨吟。", "渡江前賜字，珍重到于今。"]'),
('bb636933-f05e-4d48-8c96-ffe56f724802','太白山觀雪','薛嵎','宋','宋诗','song-poetry','','[]','二十里松聲，千山雪未晴。',48,'全唐诗/poet.song.220000.json','["二十里松聲，千山雪未晴。", "人當絕頂見，吟到此時清。", "大地球琳滿，空林鳥雀驚。", "老僧觀物化，無滅亦無生。"]'),
('e4f05702-d04e-493a-9cd9-e4710b494e35','天童寺','薛嵎','宋','宋诗','song-poetry','','[]','佛界似仙居，樓臺出翠微。',48,'全唐诗/poet.song.220000.json','["佛界似仙居，樓臺出翠微。", "浙中山水最，海內衲僧歸。", "草樹有真意，禽魚盡息機。", "禪房無別事，唯見白雲飛。"]'),
('ca0e520e-5267-4ba6-9967-b74710b540d1','送潘道士','薛嵎','宋','宋诗','song-poetry','','[]','春渚微茫碧草連，千花飛盡柳飛綿。',64,'全唐诗/poet.song.220000.json','["春渚微茫碧草連，千花飛盡柳飛綿。", "孤雲野鶴生遥思，明月清風共一船。", "破褐還尋棲隠地，空囊唯乞送行篇。", "先生自有修真訣，不倚丹砂駐少年。"]'),
('528d5d0b-ba76-4464-87fb-dbbf7a74ad6a','過村翁家','薛嵎','宋','宋诗','song-poetry','','[]','白髮茅茨下，耰鉏力未衰。',48,'全唐诗/poet.song.220000.json','["白髮茅茨下，耰鉏力未衰。", "兒孫收滯穗，雞犬入寒籬。", "俗朴人家善，山深井稅遲。", "能言耆舊事，相問坐移時。"]'),
('bb28a83b-f289-49ee-a5d1-7657f70dbd88','薛野鶴','薛嵎','宋','宋诗','song-poetry','','[]','瘦形如鶴頭如雪，流浪江湖歲月深。',32,'全唐诗/poet.song.221000.json','["瘦形如鶴頭如雪，流浪江湖歲月深。", "但是胸中有丘壑，何分城市與山林。"]'),
('086a04eb-01b8-4d21-bb29-ffc22d3527ed','漁父','薛嵎','宋','宋诗','song-poetry','','[]','一笠一蓑衣，空江雨雪霏。',48,'全唐诗/poet.song.221000.json','["一笠一蓑衣，空江雨雪霏。", "得魚雖假餌，於世本無機。", "晚唱教兒和，閑身盡醉歸。", "滄浪猶未足，長羨白鷗飛。"]'),
('d7551452-c33b-42d8-8b9d-cd88a868b694','開爐節賦','薛嵎','宋','宋诗','song-poetry','','[]','閑身何所似，丈室老維摩。',48,'全唐诗/poet.song.221000.json','["閑身何所似，丈室老維摩。", "茅屋地爐小，荒園樹葉多。", "移窗就梅影，曬草補漁蓑。", "似此寧辭苦，邊寒尚枕戈。"]'),
('065d9227-acf0-454c-84de-e948e3efd611','除夜苦雨','薛嵎','宋','宋诗','song-poetry','','[]','華髮負滄洲，星霜又一周。',48,'全唐诗/poet.song.221000.json','["華髮負滄洲，星霜又一周。", "未憑終夜雨，能洗隔年愁。", "池草起吟思，樹禽棲屋頭。", "空餘壯心在，燈下看吳鈎。"]'),
('eb581a0f-c273-4305-94f9-323c2f06eb08','呈楮溪主人','薛嵎','宋','宋诗','song-poetry','','[]','一水傍通四五池，竹亭茅榭亦相宜。',32,'全唐诗/poet.song.221000.json','["一水傍通四五池，竹亭茅榭亦相宜。", "中間更著高人住，不到溪山無好詩。"]'),
('8a4aada8-6588-40e6-a15e-f37fbee989e8','寄公衮舍弟','薛嵎','宋','宋诗','song-poetry','','[]','每恨世交薄，相期情最深。',48,'全唐诗/poet.song.221000.json','["每恨世交薄，相期情最深。", "秋風一迴首，明月兩關心。", "鶴病難爲藥，砂頑不化金。", "余生百計拙，耐可事清吟。"]'),
('ae993fe3-742d-4954-ad77-3f2c182f4106','己亥大旱官催秋苗甚急','薛嵎','宋','宋诗','song-poetry','','[]','立秋纔一日，期會到林泉。',48,'全唐诗/poet.song.221000.json','["立秋纔一日，期會到林泉。", "已悟征苗意，曾吟喜雨篇。", "饑鋤山草盡，暍汲井泥堅。", "聞道鄰州牧，憂民夜不眠。"]'),
('50cd26d5-bc9d-402f-a6b5-788383b0eb8f','新築湖外草閣','薛嵎','宋','宋诗','song-poetry','','[]','揮手紅塵吾老矣，斷隄流水草堂新。',64,'全唐诗/poet.song.221000.json','["揮手紅塵吾老矣，斷隄流水草堂新。", "幾年荆棘無行路，一日雲山有主人。", "未許園丁知姓字，先從漁父問仁鄰。", "謝他鷗鷺煙光裏，飛去飛來伴隠淪。"]'),
('1e69ec4b-6bf1-4f41-8ea9-f7d418ae78d9','山居簡飲冰友清溪槐逕二弟','薛嵎','宋','宋诗','song-poetry','','[]','別後全無夢，寄書安得頻。',48,'全唐诗/poet.song.221000.json','["別後全無夢，寄書安得頻。", "誰憐獨往意，天棄苦吟人。", "債長新年息，貧欺漸老身。", "入林知未密，猶與俗相親。"]'),
('baad6706-8e73-4139-8e27-b322ed6662ac','送友人之括蒼','薛嵎','宋','宋诗','song-poetry','','[]','石門當半道，想見泊舟時。',48,'全唐诗/poet.song.221000.json','["石門當半道，想見泊舟時。", "伴鶴立終日，就巖題幾詩。", "近山秋易老，問隠地偏宜。", "我亦江湖去，心期爾得知。"]'),
('ac32e489-75b1-4931-a556-120ba873c95c','爲張上翁賦松交','薛嵎','宋','宋诗','song-poetry','','[]','之人梅竹操，抱此歲寒心。',48,'全唐诗/poet.song.221000.json','["之人梅竹操，抱此歲寒心。", "古道久不作，高風獨在今。", "無言欣意會，肥遯愛山深。", "我亦蕭閑者，從君澗壑吟。"]'),
('00dd0390-14d9-4c24-bf4e-263590bc6610','友人入京','薛嵎','宋','宋诗','song-poetry','','[]','猿鶴亦悲鳴，家山莫浪輕。',48,'全唐诗/poet.song.221000.json','["猿鶴亦悲鳴，家山莫浪輕。", "千峰带秋色，一路獨吟情。", "野水衝潮白，孤雲趁月行。", "遥憐歸夢斷，七十二灘聲。"]'),
('b25a345b-c09a-4ce6-901c-1cdde5e0ec76','秋試下有感','薛嵎','宋','宋诗','song-poetry','','[]','焦桐何處是知音，猶向殘編惜寸陰。',64,'全唐诗/poet.song.221000.json','["焦桐何處是知音，猶向殘編惜寸陰。", "此日便爲終隠計，青山已負十年心。", "梅花獨對寒流潔，野鳥高飛古木深。", "萬古紅塵徒擾擾，幾人頭上有朝簪。"]'),
('3cb1fb1b-631c-4151-a74f-ade6f953d4c8','哭薛元善兄弟','薛嵎','宋','宋诗','song-poetry','','[]','寂寞一窗燈，隨風滅又明。',48,'全唐诗/poet.song.221000.json','["寂寞一窗燈，隨風滅又明。", "空堂連夜雨，白髮哭兒聲。", "樹色悲摇落，交情隔死生。", "唯應骨肉愛，爲鬼亦同行。"]'),
('efbdd55d-1e88-4dbb-9488-b6c8cde1b919','送松風僧淵中二公遊方','薛嵎','宋','宋诗','song-poetry','','[]','無累雲相似，悠悠天地間。',48,'全唐诗/poet.song.221000.json','["無累雲相似，悠悠天地間。", "新秋生遠思，此去未應還。", "撼錫驚棲鶴，聽松思故山。", "吟詩與說法，同是一機關。"]'),
('0174e23e-d812-4260-950a-e34ee4655494','湖外別業四詠 歸潔庵','薛嵎','宋','宋诗','song-poetry','','[]','行藏自有意，非命亦非時。',48,'全唐诗/poet.song.221000.json','["行藏自有意，非命亦非時。", "洗耳笑心褊，折腰慚悟遲。", "榮枯花上見，寒暑鬢邊知。", "獨立衡門下，悠悠千古思。"]'),
('1d119cb4-97f7-4ff4-ac4a-8473f785ca2d','湖外別業四詠 漁村晚照','薛嵎','宋','宋诗','song-poetry','','[]','舊遊憶得瀟湘路，今喜烟波似舊時。',64,'全唐诗/poet.song.221000.json','["舊遊憶得瀟湘路，今喜烟波似舊時。", "澤畔怕逢漁父問，桃源已被世人知。", "數家草市添新戶，一樹寒鴉傍古祠。", "蘭杜香深洲渚闊，小窗長日賦騷辭。"]'),
('3f3a8f9d-56ee-444a-ae9e-3e5242f239dc','湖外別業四詠 苜蓿軒','薛嵎','宋','宋诗','song-poetry','','[]','好是春風長育天，闌干低護曉窗前。',32,'全唐诗/poet.song.221000.json','["好是春風長育天，闌干低護曉窗前。", "園丁未必知吾事，補闕清聲四百年。"]'),
('ddcaf1d6-0d1a-4050-b99d-2ae0cd80b7e4','湖外別業四詠 蓑衣步','薛嵎','宋','宋诗','song-poetry','','[]','水浸石根冷，風吹藤葉飛。',24,'全唐诗/poet.song.221000.json','["水浸石根冷，風吹藤葉飛。", "菰蒲秋影裏，長趁釣船歸。"]'),
('85195977-ccc8-4879-8594-7a7ce56d4c7f','寄宋希仁兄弟','薛嵎','宋','宋诗','song-poetry','','[]','咫尺不相見，閉門唯苦吟。',48,'全唐诗/poet.song.221000.json','["咫尺不相見，閉門唯苦吟。", "聽殘寒夜雨，灰盡壯年心。", "身外一貧在，燈前百慮深。", "所欣交友義，白首亦如今。"]'),
('080f3750-b2cd-46ca-9994-365bfc9e186b','送僧自然過許峰','薛嵎','宋','宋诗','song-poetry','','[]','知心逢豈易，語別喜從容。',48,'全唐诗/poet.song.221000.json','["知心逢豈易，語別喜從容。", "因得靜中趣，又尋雲外峰。", "吟篇題在竹，拄杖曲如松。", "後會期難定，來書勿厭重。"]'),
('c84c3533-aa9a-4a8c-bb4a-1b59b3fa03a2','題中川張氏所居','薛嵎','宋','宋诗','song-poetry','','[]','鷗鳥往來處，此翁甘隠淪。',48,'全唐诗/poet.song.221000.json','["鷗鳥往來處，此翁甘隠淪。", "地因人物著，名入郡圖新。", "夜月情懷淡，茅茨意態真。", "高風無識拔，老却採薇身。"]'),
('ea27b1eb-28e4-4dea-bdb2-1f6b3e469d10','松風閣','薛嵎','宋','宋诗','song-poetry','','[]','地形連斗閣連雲，松籟曾經佛祖聞。',32,'全唐诗/poet.song.221000.json','["地形連斗閣連雲，松籟曾經佛祖聞。", "永夜月明人到少，海光山色自平分。"]'),
('f6877254-1c19-4288-99af-ace56ce869e8','題仙巖玉桂花','薛嵎','宋','宋诗','song-poetry','','[]','生在龍居最上層，重重碎玉簇孤藤。',64,'全唐诗/poet.song.221000.json','["生在龍居最上層，重重碎玉簇孤藤。", "靈根舊說宜丹汞，仙種元無到馬塍。", "風過乍疑吹珮響，日籠還似點酥凝。", "三年刻楮成何事，除却天工人不能。"]'),
('492006b5-92cd-47c6-a0b3-026c2e730088','和雁來紅','薛嵎','宋','宋诗','song-poetry','','[]','若將群卉分高下，此種無因到畫欄。',32,'全唐诗/poet.song.221000.json','["若將群卉分高下，此種無因到畫欄。", "寒蝶不知紅是葉，飛來猶作野花看。"]'),
('7f4ceff9-a97c-4af8-b5b4-eb795b03e823','劉荆山漁屋','薛嵎','宋','宋诗','song-poetry','','[]','客星沉沒釣臺空，千載風流獨此翁。',64,'全唐诗/poet.song.221000.json','["客星沉沒釣臺空，千載風流獨此翁。", "萬頃波心歌杜若，九霄雲外見冥鴻。", "已將名字編漁戶，只有琴書在室中。", "楊柳煙深杖藜出，滿頭衰白任春風。"]'),
('33add25e-3986-4654-a822-dde20b595820','歸雲壁上人遊方歸','薛嵎','宋','宋诗','song-poetry','','[]','亦是無心出，不如歸意閑。',48,'全唐诗/poet.song.221000.json','["亦是無心出，不如歸意閑。", "一身隨鐵錫，十載住金山。", "定石沾花雨，清齋带病顔。", "常云迷覺路，只在片言間。"]'),
('ff96d5e4-aeeb-451b-9c24-6e30af05d22d','友人以修鍊遊方或傳其以此死者爲賦是詩','薛嵎','宋','宋诗','song-poetry','','[]','鶴骨難污世上塵，西風惆悵瘞湖雲。',64,'全唐诗/poet.song.221000.json','["鶴骨難污世上塵，西風惆悵瘞湖雲。", "莫悲生死今朝隔，須信仙凡此路分。", "丹竈空遺鷄犬恨，青山誰吊鹿麋群。", "蓬萊今古知何在，秋草唯添處處墳。"]'),
('f9d01c32-9228-4597-ba7e-f1d08a8bdc2e','李氏愛山樓','薛嵎','宋','宋诗','song-poetry','','[]','境自吾心會，於焉識所存。',48,'全唐诗/poet.song.221000.json','["境自吾心會，於焉識所存。", "鳥聲喧後寂，樹色郭中村。", "靜壽備仁理，乾坤悟易門。", "白雲同此意，相對亦無言。"]'),
('038a398e-d347-4a84-ad94-04e5891c18f2','黄蜀葵','薛嵎','宋','宋诗','song-poetry','','[]','嬌黄無力趁芳菲，待得秋風落葉飛。',32,'全唐诗/poet.song.221000.json','["嬌黄無力趁芳菲，待得秋風落葉飛。", "空有丹心能就日，年年憔悴對斜暉。"]'),
('e22c0ba0-661d-4aee-a050-dc28891ed3d0','贈漁者','薛嵎','宋','宋诗','song-poetry','','[]','幾度看山愧白鷗，身名心事兩悠悠。',32,'全唐诗/poet.song.221000.json','["幾度看山愧白鷗，身名心事兩悠悠。", "何如醉醒寒江上，風捲蘆花雪滿頭。"]'),
('11dc5556-dcff-40c2-88c9-64419298df64','真隠寺呈延上人','薛嵎','宋','宋诗','song-poetry','','[]','塔光圓照室，香炷讀經晨。',48,'全唐诗/poet.song.221000.json','["塔光圓照室，香炷讀經晨。", "林下有清福，塵中無悟人。", "巖陰常候雨，松色不知春。", "青草何年墓，標題界碣新。"]'),
('dc2e0003-0a3c-4f06-8bbd-06a79d843b01','茅屋','薛嵎','宋','宋诗','song-poetry','','[]','茅舍竹椽短，不勞朱堊施。',48,'全唐诗/poet.song.221000.json','["茅舍竹椽短，不勞朱堊施。", "高無神鬼瞰，貧與子孫宜。", "近古意全朴，當風勢亦危。", "梅花有幽致，一樹隔疎籬。"]'),
('fd56742b-9c1b-4035-a801-82fd423cdc20','胡賢良進史','薛嵎','宋','宋诗','song-poetry','','[]','白首裒遺傳，難甘閟一丘。',48,'全唐诗/poet.song.221000.json','["白首裒遺傳，難甘閟一丘。", "表成趨闕拜，路左別家愁。", "文字歸中祕，科名異雜流。", "當年韓吏部，何自抱深憂。"]'),
('faa38a0f-d780-4a95-9ca5-c0abd1efd513','秋夜宋希仁同吟松風閣有感','薛嵎','宋','宋诗','song-poetry','','[]','相逢長日坐如癡，瘦得吟肩聳過頤。',64,'全唐诗/poet.song.221000.json','["相逢長日坐如癡，瘦得吟肩聳過頤。", "天意復生郊島在，人心自逐古今移。", "高秋月色行松頂，半夜山中讀楚辭。", "此道若無千載後，塵昏何處照妍媸。"]'),
('af9ed001-f7f7-4c58-bab9-19652d69c9e4','寄羅浮楊天經居士','薛嵎','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','羅浮峰對海壇峰，只隔長江半里風。',64,'全唐诗/poet.song.221000.json','["羅浮峰對海壇峰，只隔長江半里風。", "君向西方了生死，我於易象悟窮通。", "數聲清梵空林下，一幅漁罾落照中。", "各各閉門無俯仰，不相同處偶相同。"]'),
('9c25203e-6d93-4dcc-9c57-08d0022d28a4','冬日雜言五首  其一','薛嵎','宋','宋诗','song-poetry','','[]','茅簷日出勝重裘，飽飯看山倦即休。',32,'全唐诗/poet.song.221000.json','["茅簷日出勝重裘，飽飯看山倦即休。", "識得箇中真氣味，自然無夢到封侯。"]'),
('b9c71f3a-f3db-4826-b796-8ac8911a2ccd','冬日雜言五首  其二','薛嵎','宋','宋诗','song-poetry','','[]','古藤荒草亂成堆，自課園丁日日來。',32,'全唐诗/poet.song.221000.json','["古藤荒草亂成堆，自課園丁日日來。", "只有梅花耐清苦，霜風枝上犯寒開。"]'),
('e62b01a0-91a4-44e4-b60d-3314f62c5e82','冬日雜言五首  其三','薛嵎','宋','宋诗','song-poetry','','[]','竹爐槁葉坐燒殘，冷屋荒村夜更寒。',32,'全唐诗/poet.song.221000.json','["竹爐槁葉坐燒殘，冷屋荒村夜更寒。", "凍得形模龜樣縮，誰知方寸似天寬。"]'),
('30a2bf5b-a206-4a96-a8b3-5221ba6e183b','冬日雜言五首  其四','薛嵎','宋','宋诗','song-poetry','','[]','鶴唳柴門月過牆，梅花如雪滿林香。',32,'全唐诗/poet.song.221000.json','["鶴唳柴門月過牆，梅花如雪滿林香。", "風光直許閑人占，不耐閑人夜亦忙。"]'),
('f78031a3-e966-4bef-9066-dee06d26cdfa','冬日雜言五首  其五','薛嵎','宋','宋诗','song-poetry','','[]','布被烘來暖似湯，蒙頭高卧未昏黄。',32,'全唐诗/poet.song.221000.json','["布被烘來暖似湯，蒙頭高卧未昏黄。", "道人不是貪鼾睡，省事門中第一方。"]'),
('55f55964-fa73-4a93-818a-531860b0d869','雁山紀遊七首 壽昌寺','薛嵎','宋','宋诗','song-poetry','','[]','野服掛僧單，禪扉月未關。',48,'全唐诗/poet.song.221000.json','["野服掛僧單，禪扉月未關。", "桂香清近佛，秋色老依山。", "目盡遥峰出，步回流水閑。", "相傳登蕩路，數處可躋攀。"]'),
('e3ced469-42a6-4f2f-8328-91fc08983ad5','雁山紀遊七首 能仁寺','薛嵎','宋','宋诗','song-poetry','','[]','過盡盤山險，登臨意忽平。',48,'全唐诗/poet.song.221000.json','["過盡盤山險，登臨意忽平。", "殿燈摇佛影，瀑布雜鐘聲。", "湫闊龍居頂，路迴峰換名。", "曉行林日薄，海氣接雲生。"]'),
('91c8e35a-f465-455c-b911-a1756a00e698','雁山紀遊七首 大龍湫','薛嵎','宋','宋诗','song-poetry','','[]','深冬雷未蟄，雨雹半空飛。',48,'全唐诗/poet.song.221000.json','["深冬雷未蟄，雨雹半空飛。", "久立怪生眼，迴看日變暉。", "萬松聲不出，尺蜃鬣猶威。", "僧說分流闊，長年無旱饑。"]'),
('27bd8429-76a3-45c7-88a9-db3b83db1688','雁山紀遊七首 靈巖寺','薛嵎','宋','宋诗','song-poetry','','[]','千巖崚骨露，隨怪各生形。',48,'全唐诗/poet.song.221000.json','["千巖崚骨露，隨怪各生形。", "目力到天盡，心旌倚佛寧。", "夜鐘傳谷杳，石氣逼燈青。", "崖腹獼猴住，多年性亦靈。"]'),
('66f467a3-0662-4167-a0ad-d42a14a9a7d9','雁山紀遊七首 浄明寺','薛嵎','宋','宋诗','song-poetry','','[]','入寺嫌僧俗，獨行松逕幽。',48,'全唐诗/poet.song.221000.json','["入寺嫌僧俗，獨行松逕幽。", "夜扉崖室寂，齋磬鐵盂秋。", "谷棧雲迷級，石溪霜迸流。", "維摩不語坐，何日病能瘳。"]'),
('ff445223-bfb1-46d0-9ffe-a6ce2659bc32','雁山紀遊七首 靈峰寺','薛嵎','宋','宋诗','song-poetry','','[]','神功開地秘，怪石盡爲峰。',48,'全唐诗/poet.song.221000.json','["神功開地秘，怪石盡爲峰。", "佛界虛空造，龍居十二重。", "睛瞳隨境役，蟾兔及秋逢。", "却憶謝靈運，嶺頭迷去蹤。"]'),
('14a712f9-a1d9-4a49-9fb2-2a7ba8255d02','雁山紀遊七首 寶冠靈雲二寺','薛嵎','宋','宋诗','song-poetry','','[]','夜鐘寥閴遠相聞，古佛青山自結鄰。',64,'全唐诗/poet.song.221000.json','["夜鐘寥閴遠相聞，古佛青山自結鄰。", "片石掛空平可渡，兩峰侵漢立如人。", "雲歸蕩頂無多路，僧住巖根老此身。", "爲憶龍湫重迴首，來看瀑布獨逡巡。"]'),
('aaab45ac-787f-4d26-8b96-6d1077104b26','劉荆山謁賈秋壑','薛嵎','宋','宋诗','song-poetry','','[]','鬢絲千縷去衝寒，酒放詩豪强自寬。',64,'全唐诗/poet.song.221000.json','["鬢絲千縷去衝寒，酒放詩豪强自寬。", "天下英雄從古少，人生遇合至今難。", "婚姻債裏拋吟屋，雨雪聲中起客單。", "造物與君强健在，歸囊知有暮年歡。"]'),
('fd33dd5c-c232-4368-9fec-9ebc2a09cd98','素上人圓鑑','薛嵎','宋','宋诗','song-poetry','','[]','何須百鍊取晶熒，大化非由巧力成。',64,'全唐诗/poet.song.221000.json','["何須百鍊取晶熒，大化非由巧力成。", "所性本來無闕蝕，認形却恐未分明。", "寒泉深夜轆轤靜，素魄中天世界清。", "到此萬緣皆了了，笑他拂拭墮纏縈。"]'),
('1c5fb8a8-3e1f-4dbb-89d2-15920b50d909','新春感懷五首  其一','薛嵎','宋','宋诗','song-poetry','','[]','新春風物舊山川，老大情懷一惘然。',32,'全唐诗/poet.song.221000.json','["新春風物舊山川，老大情懷一惘然。", "桃樹不知秦世換，落花流水自年年。"]'),
('469cfe11-5c87-45d9-aa2c-1e0443bc41a9','新春感懷五首  其二','薛嵎','宋','宋诗','song-poetry','','[]','兒女添年暗自欣，不知婚嫁逼儂身。',32,'全唐诗/poet.song.221000.json','["兒女添年暗自欣，不知婚嫁逼儂身。", "羹藜衣褐由天分，莫負當初種德人。"]'),
('f5fc2c79-934a-4d05-a426-7e773ccc4e9d','新春感懷五首  其三','薛嵎','宋','宋诗','song-poetry','','[]','自悔中年廢讀書，餘生祇可業樵漁。',32,'全唐诗/poet.song.221000.json','["自悔中年廢讀書，餘生祇可業樵漁。", "青山白屋笑歸去，從我高眠百事疎。"]'),
('566e2a17-8703-45c2-bb78-ac998270a998','新春感懷五首  其四','薛嵎','宋','宋诗','song-poetry','','[]','新種黄精助晚糧，生涯小小拙何妨。',32,'全唐诗/poet.song.221000.json','["新種黄精助晚糧，生涯小小拙何妨。", "春風吹鬢不重綠，白日笑人長自忙。"]'),
('f76b9797-4a52-4740-ab90-aba6addb7aef','新春感懷五首  其五','薛嵎','宋','宋诗','song-poetry','','[]','多置田園占好官，妻兒奴婢盡生歡。',32,'全唐诗/poet.song.221000.json','["多置田園占好官，妻兒奴婢盡生歡。", "貧家有子纔堪教，身後窮愁且放寬。"]'),
('269b3040-798f-4a6b-8cab-27ccca4c6f65','送廉村宗人薛庭芝薛如晦還里','薛嵎','宋','宋诗','song-poetry','','[]','老我儒冠誤，憐君亦固窮。',48,'全唐诗/poet.song.221000.json','["老我儒冠誤，憐君亦固窮。", "山川居壤異，友愛所天同。", "江渡乘潮闊，霜林逐曉空。", "永懷楸壠敬，淹泊志難通。"]'),
('3febab53-757d-4429-b05a-3ddd1e17955e','郊外隠居','薛嵎','宋','宋诗','song-poetry','','[]','自是山林士，非因失志餘。',48,'全唐诗/poet.song.221000.json','["自是山林士，非因失志餘。", "兒童知稼穡，猿鶴近詩書。", "曙色浮滄海，春風滿太虛。", "固窮須學力，不敢廢經鋤。"]'),
('46544120-bc49-4be0-8f77-97f347978eaa','趙東閣倅越','薛嵎','宋','宋诗','song-poetry','','[]','百指忍貧需遠次，壯心銷盡鬢絲知。',64,'全唐诗/poet.song.221000.json','["百指忍貧需遠次，壯心銷盡鬢絲知。", "身如韋素居常泰，官被聲名折得遲。", "束檐喜聞千里戍，出山唯有十年詩。", "蘭亭風月應須記，人物依稀似晉時。"]'),
('e61e099b-5fc8-46a2-82fc-3d9c7d3cc3cf','秋日書懷','薛嵎','宋','宋诗','song-poetry','','[]','萬事榮枯一聚塵，塵中誰是獨醒人。',64,'全唐诗/poet.song.221000.json','["萬事榮枯一聚塵，塵中誰是獨醒人。", "壯無學力吟將退，老入賢關路轉貧。", "昨夜立秋凉到曉，空齋對月靜如賓。", "首陽千載蕨薇綠，唯有夷齊紀逸民。"]'),
('a960984e-e60a-4657-b785-3af70def8fac','爲歸雲師賦野航','薛嵎','宋','宋诗','song-poetry','','[]','遇坎與乘流，誰能捨迹求。',48,'全唐诗/poet.song.221000.json','["遇坎與乘流，誰能捨迹求。", "即空皆是境，大渡本無舟。", "風浪隨機息，乾坤任泡浮。", "可憐迷岸者，漂蕩幾時休。"]'),
('d2367ac4-34e6-4748-a345-8f525e80885c','夜坐課子姪','薛嵎','宋','宋诗','song-poetry','','[]','微風弄孤燭，蛬響泣將晨。',48,'全唐诗/poet.song.221000.json','["微風弄孤燭，蛬響泣將晨。", "欲辦男兒事，當爲志氣人。", "簞瓢非外樂，韋布只身貧。", "慎勿忘科第，務求榮爾親。"]'),
('617f22f1-524a-467d-98fa-fe84c9108057','賦王九山滄浪閣','薛嵎','宋','宋诗','song-poetry','','[]','千年孺子吟，誰會此時心。',48,'全唐诗/poet.song.221000.json','["千年孺子吟，誰會此時心。", "方寸有涇渭，煙波無古今。", "水禽知雨候，山氣愛秋深。", "不盡凭欄意，橈歌歸故林。"]'),
('da5e1483-0a0e-45a4-b89a-64d691b93505','省試舟中','薛嵎','宋','宋诗','song-poetry','','[]','闕下春光近，囊金又一空。',48,'全唐诗/poet.song.221000.json','["闕下春光近，囊金又一空。", "霜風欺敗絮，星斗隔疎篷。", "世道誰能挽，妻孥見未同。", "青燈對黄冊，銷盡幾英雄。"]'),
('942b3dc8-5516-489a-9582-8ad925bcdae4','旅店早起','薛嵎','宋','宋诗','song-poetry','','[]','半醒夢猶在，擁衾無限情。',48,'全唐诗/poet.song.221000.json','["半醒夢猶在，擁衾無限情。", "曉窗燈影淡，山路雪吟清。", "歲暮羨歸客，囊空兼去程。", "故書多廢理，驚愧動心旌。"]'),
('da003c99-fc1d-4838-8170-4e6878ba3ea0','鮑靖之左藏','薛嵎','宋','宋诗','song-poetry','','[]','一門期負荷，太息此生終。',48,'全唐诗/poet.song.221000.json','["一門期負荷，太息此生終。", "世道不如古，君心誰與同。", "官清餘橐在，虞返故堂空。", "作善寧須報，悠悠付彼穹。"]'),
('88db57ef-294b-4cb4-bc47-21fc20f705a6','下第','薛嵎','宋','宋诗','song-poetry','','[]','寸晷場中較尺尋，榮親無路淚盈襟。',64,'全唐诗/poet.song.221000.json','["寸晷場中較尺尋，榮親無路淚盈襟。", "一貧誰過簞瓢巷，百口難寬兒女心。", "昨夢重圓知誤喜，平生失計爲工吟。", "近來文體尤趨薄，古道何由可語今。"]'),
('81024c48-7ecd-47db-97ff-c599aa8a0185','爲槐逕弟賦亦愛','薛嵎','宋','宋诗','song-poetry','','[]','無私天地情，物我豈殊形。',48,'全唐诗/poet.song.221000.json','["無私天地情，物我豈殊形。", "此事關方寸，何人立戶庭。", "一琴調舜曲，半壁寫西銘。", "萬慮境常適，誰能羨獨醒。"]'),
('4685b931-30c5-4102-8724-9bf1dc7563d5','初夏過湖外別業','薛嵎','宋','宋诗','song-poetry','','[]','郊原新綠喜初晴，一曲湖光瀲灧明。',64,'全唐诗/poet.song.221000.json','["郊原新綠喜初晴，一曲湖光瀲灧明。", "幾處樓臺空鎖鑰，百年人物盡丘塋。", "好花自分隨春去，惡木寧思擇地生。", "獨念索居聞識寡，夜窗長對讀書檠。"]'),
('36522740-a177-4e77-b1e1-5589c86e2cc4','趙東閣奏院去國','薛嵎','宋','宋诗','song-poetry','','[]','帆遠浙江風，蓴鱸趣一同。',48,'全唐诗/poet.song.221000.json','["帆遠浙江風，蓴鱸趣一同。", "無人持國是，舉世咎詩窮。", "身退山林重，心怡學問充。", "冥鴻離罾繳，瞬息九霄空。"]'),
('99df57c3-41c0-420b-aee4-51036ec42188','爲迪上人賦寒倚','薛嵎','宋','宋诗','song-poetry','','[]','山僧愛脩竹，種此出囂塵。',48,'全唐诗/poet.song.221000.json','["山僧愛脩竹，種此出囂塵。", "霜雪不知苦，歲時長自春。", "定回閑坐石，風過動吟身。", "儻欲求歸止，清虛即道真。"]'),
('2272cb72-10cd-4a64-8dee-482643800392','劉荆山過惟揚再謁賈秋壑','薛嵎','宋','宋诗','song-poetry','','[]','扉屨踐淮雪，故人師帥歡。',48,'全唐诗/poet.song.221000.json','["扉屨踐淮雪，故人師帥歡。", "燈前話疇昔，時事又艱難。", "陪宴平山曉，尋梅古署寒。", "却歸訪泉石，珍重慰團欒。"]'),
('a74ced8f-0859-4521-8aab-59f73fd3db68','山居述懷','薛嵎','宋','宋诗','song-poetry','','[]','山瓢動瀑冰，一枕曲肱清。',48,'全唐诗/poet.song.221000.json','["山瓢動瀑冰，一枕曲肱清。", "未遇勤求日，非沽隠逸名。", "梅邊月在水，寒夜酒如兵。", "悟得乘除數，貧中心自平。"]'),
('67adfa25-2c30-497c-bf2b-5752ca50ed4f','本無師住甸陽山庵','薛嵎','宋','宋诗','song-poetry','','[]','萬松圍坐石，大海浴金輪。',48,'全唐诗/poet.song.221000.json','["萬松圍坐石，大海浴金輪。", "不識入城路，唯脩成佛身。", "出生來虎子，持咒拱山神。", "何必工吟苦，機鋒自絕塵。"]'),
('cb37ecc8-0d8b-472a-ab54-5929cd5e8ffe','冬蘭','薛嵎','宋','宋诗','song-poetry','','[]','出林詎爲晚，知我歲寒心。',48,'全唐诗/poet.song.221000.json','["出林詎爲晚，知我歲寒心。", "不入離騷怨，來親冰雪吟。", "衆芳歸槁壤，獨幹長窮陰。", "爲有幽人致，相看情倍深。"]'),
('78111a49-a345-4a4d-a694-bf498ea526d4','閑居雜興十首  其一','薛嵎','宋','宋诗','song-poetry','','[]','亦有入城路，門前秋草長。',48,'全唐诗/poet.song.221000.json','["亦有入城路，門前秋草長。", "荷鉏書在手，負鍤醉爲鄉。", "霜渡溪流澀，厨煙樹葉香。", "爲貧從儉約，猶欠半年糧。"]'),
('30981428-b7a1-4782-89e1-5cde36d702e5','閑居雜興十首  其二','薛嵎','宋','宋诗','song-poetry','','[]','昔日黄金屋，十年荆棘林。',48,'全唐诗/poet.song.221000.json','["昔日黄金屋，十年荆棘林。", "浮生真亦假，世事古猶今。", "電隙無留景，雲泉属自心。", "紛紛蝸角裏，朝暮幾升沈。"]'),
('b04e7783-c0a0-4ff6-96b9-1ffd7c88b3a1','閑居雜興十首  其三','薛嵎','宋','宋诗','song-poetry','','[]','鐵硯幾磨研，依然螢雪邊。',48,'全唐诗/poet.song.221000.json','["鐵硯幾磨研，依然螢雪邊。", "薄才遺聖世，無祿盡親年。", "多病唯諳藥，當寒不識綿。", "素心期淡泊，冰蘗誓能堅。"]'),
('bd7ac89d-7610-4e34-b1e0-6db3db816305','閑居雜興十首  其四','薛嵎','宋','宋诗','song-poetry','','[]','秋蟲隨響滅，振羽不知疲。',48,'全唐诗/poet.song.221000.json','["秋蟲隨響滅，振羽不知疲。", "譬彼附炎士，寧思失勢時。", "垂竿動天象，定策茹商芝。", "投分諒非淺，翻然弗可追。"]'),
('1058b1ba-fb0a-4e57-a804-a8bad3e1a3cd','閑居雜興十首  其五','薛嵎','宋','宋诗','song-poetry','','[]','閉戶謝流俗，青山獨自看。',48,'全唐诗/poet.song.221000.json','["閉戶謝流俗，青山獨自看。", "淡交從古少，冷面對人難。", "農圃元非學，神仙不在丹。", "孤懷無別想，回向此心觀。"]'),
('73f563a9-0986-4ff5-b33c-674b43a130e7','閑居雜興十首  其六','薛嵎','宋','宋诗','song-poetry','','[]','四時俱橐籥，一氣自迴旋。',48,'全唐诗/poet.song.221000.json','["四時俱橐籥，一氣自迴旋。", "誰謂春風力，能專萬物權。", "榮枯忘晦朔，霜雪抱貞堅。", "賦分有深淺，殊非天道偏。"]'),
('b8183fb2-e266-44e1-9a2d-0c283ed53d52','閑居雜興十首  其七','薛嵎','宋','宋诗','song-poetry','','[]','已是中年後，何當絕悔尤。',48,'全唐诗/poet.song.221000.json','["已是中年後，何當絕悔尤。", "漁樵非始志，燈火企前脩。", "葉落秋容見，巢傾鶴貌愁。", "詩窮安敢避，天爲拙人謀。"]'),
('97e0c73e-7688-46c5-8200-8f48f5fac9d4','閑居雜興十首  其八','薛嵎','宋','宋诗','song-poetry','','[]','土木非吾事，支東復拄西。',48,'全唐诗/poet.song.221000.json','["土木非吾事，支東復拄西。", "雨盈溝壅葉，簷側礎沈泥。", "護壁時編葦，登樓恐折梯。", "若無憂撓至，終歲亦安棲。"]'),
('670ac11f-5c09-4abb-bd91-c7274e9d3b01','閑居雜興十首  其九','薛嵎','宋','宋诗','song-poetry','','[]','近覺吟無趣，權將俗累刪。',48,'全唐诗/poet.song.221000.json','["近覺吟無趣，權將俗累刪。", "鶑花老眼倦，風雨半春閑。", "野面便粗褐，柴扉掩暮山。", "片雲尋處泊，飛度竹簷間。"]'),
('e9827086-e2bf-4023-b8fe-27419c159fd5','閑居雜興十首  其一○','薛嵎','宋','宋诗','song-poetry','','[]','白髮天應棄，春風吹不青。',48,'全唐诗/poet.song.221000.json','["白髮天應棄，春風吹不青。", "神仙歸恍惚，書傳出英靈。", "周粟豈醫餓，湘流難活醒。", "迄今名字在，百世仰芳馨。"]'),
('abd1efb5-9870-4dc6-be5a-0175347f18c8','潘懷古參學','薛嵎','宋','宋诗','song-poetry','','[]','同吟四十過三四，常恨詩銜欠一官。',64,'全唐诗/poet.song.221000.json','["同吟四十過三四，常恨詩銜欠一官。", "人事中年多感慨，仕途今日更艱難。", "爐亭圍坐推前輩，夜店單牀定薄寒。", "最喜親庭佳闕近，盡携兒女入長安。"]'),
('4dfd0ea0-e184-4d3d-ac68-8418b607ed95','廉村族人命賦唐補闕薛公墓  其一','薛嵎','宋','宋诗','song-poetry','','[]','一自東宮吟苜蓿，吁嗟直道竟難容。',64,'全唐诗/poet.song.221000.json','["一自東宮吟苜蓿，吁嗟直道竟難容。", "精忠夙佇危邦慮，明哲寧高避世蹤。", "疎傅有心辭漢陛，甘盤無夢佐商宗。", "寥寥千載聞風者，引領猶能式墓松。"]'),
('17ec2e39-8739-4618-9c9c-18158748993e','廉村族人命賦唐補闕薛公墓  其二','薛嵎','宋','宋诗','song-poetry','','[]','何處青山無白骨，先生高節死猶存。',64,'全唐诗/poet.song.221000.json','["何處青山無白骨，先生高節死猶存。", "古今人物一抔土，閩浙詩書百世孫。", "鄉邑有祠尊往哲，樵芻知禁避荒垣。", "斷碑殘碣堪摩拭，慙愧年年宿草蕃。"]'),
('16606b9d-46a7-4c57-8d99-37ef6eadf46d','潘南夫察院出臺鄉人榮其歸拉余迎訪因賦七言','薛嵎','宋','宋诗','song-poetry','','[]','囊封朝上暮身擠，讒口何如萬目齊。',64,'全唐诗/poet.song.221000.json','["囊封朝上暮身擠，讒口何如萬目齊。", "昔謂椒蘭誠擇地，今知蕭艾適同畦。", "波濤不動中流砥，風雨難瘖晦旦雞。", "自著漁蓑厭趨謁，晨鐘欣出郭門西。"]'),
('8cbf265d-bc99-45e6-81bf-c435960e0797','早起即事','薛嵎','宋','宋诗','song-poetry','','[]','隔水鐘聲枕上聞，城中人事已紛紛。',32,'全唐诗/poet.song.221000.json','["隔水鐘聲枕上聞，城中人事已紛紛。", "開門放鶴溪邊去，衝破閑階一片雲。"]'),
('9166795f-6d37-40a6-ab4b-722fb5914f61','電眸相士索詩','薛嵎','宋','宋诗','song-poetry','','[]','築室漁村五六年，湖光山色在吟邊。',32,'全唐诗/poet.song.221000.json','["築室漁村五六年，湖光山色在吟邊。", "道人不作閑人看，浪說前程博酒錢。"]'),
('3f3a15a1-604f-4581-a094-04a2fc3dc3a8','林景雲參學','薛嵎','宋','宋诗','song-poetry','','[]','一門四世同堂樂，門外傳呼釋褐歸。',64,'全唐诗/poet.song.221000.json','["一門四世同堂樂，門外傳呼釋褐歸。", "自此高車訪遊舊，屏將呵從叩漁扉。", "三冬晴暖春寒在，千里詩書野意違。", "又說携琴搜逸譜，休嫌古調按今徽。"]'),
('c381012f-7918-4332-bfee-5a21dcd89687','王九山提刑於子城西舊宅累石作小阜見示五言因次韻奉呈','薛嵎','宋','宋诗','song-poetry','','[]','幽懷隨所寓，數石几窗前。',48,'全唐诗/poet.song.221000.json','["幽懷隨所寓，數石几窗前。", "荆棘儻迷道，山林空浩然。", "雲生寧擇地，龍處即爲淵。", "誰謂達觀士，終當違市廛。"]'),
('e3b04884-a79d-47e3-8766-086f8cc7090c','郭氏抗雲樓','薛嵎','宋','宋诗','song-poetry','','[]','宴坐群峰表，太空無一塵。',48,'全唐诗/poet.song.221000.json','["宴坐群峰表，太空無一塵。", "青山獨往意，白首自由身。", "放鶴重霄闊，凭欄萬木春。", "紛紛荆棘裏，跬步亦逡巡。"]'),
('f652f8e2-3303-489b-824e-9c7de80b0514','郭氏遺經堂','薛嵎','宋','宋诗','song-poetry','','[]','校讎存手澤，肯構烱前光。',48,'全唐诗/poet.song.221000.json','["校讎存手澤，肯構烱前光。", "際此聖明代，應無屋壁藏。", "半窗分雪影，群蠹避芸香。", "靜想趨庭意，居然師友旁。"]'),
('be824fe8-24bb-4ce9-a4db-c4eeeeeeeb46','徐太古主清江簿','薛嵎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','四靈詩體變江西，玉笥峰青首入題。',64,'全唐诗/poet.song.221000.json','["四靈詩體變江西，玉笥峰青首入題。", "舊隠乍違鷗鷺去，新篇高與簿書齊。", "身閑自喜瓜期遠，俸薄還因楮價低。", "摻別正逢寒食日，洞庭春淥草萋萋。"]'),
('c14d7725-7b6d-4b5b-b498-6e3c0777646b','漁村會諸友戲呈','薛嵎','宋','宋诗','song-poetry','','[]','磯頭濯足動滄浪，獨醒何曾與世妨。',64,'全唐诗/poet.song.221000.json','["磯頭濯足動滄浪，獨醒何曾與世妨。", "盡寫騷經粘屋壁，未逢漁父似瀟湘。", "遠山不離煙雲色，流水時聞蘭杜香。", "製得荷衣恐驚俗，對人稱是楚賢裝。"]'),
('db006428-b924-4577-8afc-9724464499fc','再別徐太古主簿','薛嵎','宋','宋诗','song-poetry','','[]','枌社過從久，新知盡不如。',48,'全唐诗/poet.song.221000.json','["枌社過從久，新知盡不如。", "素心非必仕，此別遂成疎。", "清苦辭藜藿，寒暄慎起居。", "川途脩復阻，相憶眇愁予。"]'),
('c4f5ee97-50d6-40ac-8f82-3ebfa0e38807','悼張寺丞','薛嵎','宋','宋诗','song-poetry','','[]','五馬歸來絕送迎，全將漚泡視浮榮。',64,'全唐诗/poet.song.221000.json','["五馬歸來絕送迎，全將漚泡視浮榮。", "宅依林麓樓臺小，門有詩書氣味清。", "身後只如僧冷淡，墓頭曾是手經營。", "夫人扶疾秋窗下，深夜看經带哭聲。"]'),
('eb231132-0922-441d-ac4d-fc0e2c53a91f','瓢飲陳子在病後見寄次韻奉答','薛嵎','宋','宋诗','song-poetry','','[]','聞君卧病長於悒，文會過從迹頓疎。',64,'全唐诗/poet.song.221000.json','["聞君卧病長於悒，文會過從迹頓疎。", "空對秋風驚節物，無因杯酒具園蔬。", "柴荆晝揜聽殘雨，燈火凉生理故書。", "一啟來緘拜佳什，清泠如奉笑談餘。"]'),
('aa736af6-df58-4efc-8f47-1a6b375e3a72','棲褊絕句','薛嵎','宋','宋诗','song-poetry','','[]','不學踰垣與閉門，誅茅先卜遠人村。',32,'全唐诗/poet.song.221000.json','["不學踰垣與閉門，誅茅先卜遠人村。", "釣魚磯在平如席，坐對青山無一言。"]'),
('322e628e-d7c8-49ae-a7a9-3d06626440b5','重遊雁山分得六題 蕩頂','薛嵎','宋','宋诗','song-poetry','','[]','高平餘十里，湖湗落中間。',48,'全唐诗/poet.song.221000.json','["高平餘十里，湖湗落中間。", "此地可耕鑿，長年迷草菅。", "一菴猶有路，四望忽無山。", "道者了經課，慰余登陟艱。"]'),
('964f42cf-528d-49cf-8330-8d579b9d1d8a','重遊雁山分得六題 龍鼻水','薛嵎','宋','宋诗','song-poetry','','[]','怪極生真想，饑凶禱請勤。',48,'全唐诗/poet.song.221000.json','["怪極生真想，饑凶禱請勤。", "半身鱗甲具，一勺渺瀰分。", "應谷聲如鬼，飛空石礙雲。", "精誠隨寓在，亦以感通聞。"]'),
('70784773-c30b-4e2e-a977-156c45a6e009','重遊雁山分得六題 天聰洞','薛嵎','宋','宋诗','song-poetry','','[]','天聽本非耳，形容獨費吟。',48,'全唐诗/poet.song.221000.json','["天聽本非耳，形容獨費吟。", "豈伊穿鑿力，能探杳冥心。", "混沌開中竅，空虛納衆音。", "下臨千仞險，當暑骨毛森。"]'),
('43051115-266d-4e9f-b1c9-7b37b49d4108','重遊雁山分得六題 水簾谷','薛嵎','宋','宋诗','song-poetry','','[]','石壁斧修痕，風泉斷續聞。',48,'全唐诗/poet.song.221000.json','["石壁斧修痕，風泉斷續聞。", "琉璃光閃日，空洞濕飛雲。", "妙出神功造，源從湫底分。", "誰能爲鈎起，深處謁龍君。"]'),
('aa40b9e1-d74e-422f-a3ee-910de1664705','重遊雁山分得六題 照膽潭','薛嵎','宋','宋诗','song-poetry','','[]','彼我俱澄澈，中涵理趣深。',48,'全唐诗/poet.song.221000.json','["彼我俱澄澈，中涵理趣深。", "游鯈具龍體，幽洞通潭心。", "影動猿摇樹，沙明日耀金。", "片巖經霹靂，痕鑿到于今。"]'),
('ab014d21-d83a-4a69-ab75-46f0018f858f','重遊雁山分得六題 五老峰','薛嵎','宋','宋诗','song-poetry','','[]','巖前看不足，化此石爲身。',48,'全唐诗/poet.song.221000.json','["巖前看不足，化此石爲身。", "憶昔白頭者，於中第幾人。", "相逢應失笑，久立豈迷津。", "勿厭薜蘿密，癡容免俗嗔。"]'),
('7b2b2e6c-1b86-4c22-9084-16aecf380098','哭瓢飲陳子在  其一','薛嵎','宋','宋诗','song-poetry','','[]','案頭螢火散，惆悵夜吟魂。',48,'全唐诗/poet.song.221000.json','["案頭螢火散，惆悵夜吟魂。", "路暗重泉迥，堂空半影存。", "命無藜藿富，書獨鬼神尊。", "猿鶴聲聲怨，愁人不可言。"]'),
('8397aafa-2c21-4a68-9c77-4fefe827fa04','哭瓢飲陳子在  其二','薛嵎','宋','宋诗','song-poetry','','[]','蟬蛻塵埃外，閑身樂未涯。',48,'全唐诗/poet.song.221000.json','["蟬蛻塵埃外，閑身樂未涯。", "山林天豈靳，脩短數難移。", "吟硯誰濡墨，空瓢想掛枝。", "深衣古賢貌，猶覬夢來時。"]'),
('b1dbb045-55c9-4155-8efc-7b16107a30fe','哭瓢飲陳子在  其三','薛嵎','宋','宋诗','song-poetry','','[]','每恨去城遠，番番語別難。',48,'全唐诗/poet.song.221000.json','["每恨去城遠，番番語別難。", "論交置疏數，盡醉就團欒。", "事往遽成感，松彫不待寒。", "尚餘親翰墨，收淚再三看。"]'),
('dcab5d47-0236-4a0b-8103-394cd1caf848','哭瓢飲陳子在  其四','薛嵎','宋','宋诗','song-poetry','','[]','寢食難忘置，心懷故友情。',48,'全唐诗/poet.song.221000.json','["寢食難忘置，心懷故友情。", "花枝封蠟寄，詩遞出門迎。", "忍聽偏親哭，相期嗣子成。", "乘除理終定，人事未容輕。"]'),
('f4ce9734-9a1a-41d6-8b82-8128e2530ad0','月海遠上人遊方過靈隠','薛嵎','宋','宋诗','song-poetry','','[]','一點靈光在，月生滄海深。',48,'全唐诗/poet.song.221000.json','["一點靈光在，月生滄海深。", "此中難著語，何處可相尋。", "野寺齋無定，窮冬日易陰。", "聽松行九里，却坐冷泉吟。"]'),
('1ea4f04c-70d8-4caa-b4db-fa4d6b9c6dfd','漁村雜句十首  其一','薛嵎','宋','宋诗','song-poetry','','[]','莫論塵土與煙霞，收拾襟懷即我家。',32,'全唐诗/poet.song.221000.json','["莫論塵土與煙霞，收拾襟懷即我家。", "絮帽蒙頭霜月下，水村深夜看梅花。"]'),
('76b59580-dae7-4e4c-b254-759e51bda453','漁村雜句十首  其二','薛嵎','宋','宋诗','song-poetry','','[]','非智非愚浪著鞭，前程倒指事茫然。',32,'全唐诗/poet.song.221000.json','["非智非愚浪著鞭，前程倒指事茫然。", "臨流一洗巢由耳，獨立斜陽認釣船。"]'),
('0a709899-1d5e-49cd-b21b-e2fed2fae8ca','漁村雜句十首  其三','薛嵎','宋','宋诗','song-poetry','','[]','盡醉茅柴得自由，蘆花飛雪滿人頭。',32,'全唐诗/poet.song.221000.json','["盡醉茅柴得自由，蘆花飛雪滿人頭。", "蓑衣碎葉重重補，聽雨吟風卒未休。"]'),
('f3c65eab-5c22-4b1e-b035-c14f2d637880','漁村雜句十首  其四','薛嵎','宋','宋诗','song-poetry','','[]','青山如主復如賓，相對無言意自真。',32,'全唐诗/poet.song.221000.json','["青山如主復如賓，相對無言意自真。", "富貴不應忘此味，從來世上少閑人。"]'),
('916c3787-b416-469c-b22d-d4eaee482903','漁村雜句十首  其五','薛嵎','宋','宋诗','song-poetry','','[]','月下門開不用敲，渡頭長繫木蘭橈。',32,'全唐诗/poet.song.221000.json','["月下門開不用敲，渡頭長繫木蘭橈。", "盤餐市遠從真率，會宿何妨屢卜宵。"]'),
('74f9e0c5-b93c-46d8-8b75-50f06d02795d','漁村雜句十首  其六','薛嵎','宋','宋诗','song-poetry','','[]','澤畔行行歌楚騷，一襟忠憤付湘濤。',32,'全唐诗/poet.song.221000.json','["澤畔行行歌楚騷，一襟忠憤付湘濤。", "難教舉世無醒者，莫羨漁翁活計高。"]'),
('9c733963-4c42-462b-864e-f67215319628','漁村雜句十首  其七','薛嵎','宋','宋诗','song-poetry','','[]','三五人家住一灣，近城無路去來難。',32,'全唐诗/poet.song.221000.json','["三五人家住一灣，近城無路去來難。", "溪邊自結同吟友，松柏青青到歲寒。"]'),
('d173c6b2-7bf4-4dcd-9f21-5431706db76a','漁村雜句十首  其八','薛嵎','宋','宋诗','song-poetry','','[]','野水微茫路欲迷，重重沙渚自高低。',32,'全唐诗/poet.song.221000.json','["野水微茫路欲迷，重重沙渚自高低。", "鷺鷥飛過無心泊，直入殘陽樹杪棲。"]'),
('d4c870ba-8bac-403c-8ae1-59c7d6eac488','漁村雜句十首  其九','薛嵎','宋','宋诗','song-poetry','','[]','猿鶴何曾肯受羈，偶來亭畔立多時。',32,'全唐诗/poet.song.221000.json','["猿鶴何曾肯受羈，偶來亭畔立多時。", "物情未到忘機地，步步行行只自疑。"]'),
('a35dc235-3afb-4915-9802-b65ac7890163','漁村雜句十首  其一○','薛嵎','宋','宋诗','song-poetry','','[]','白雲相顧尚依依，十載江湖負宿知。',32,'全唐诗/poet.song.221000.json','["白雲相顧尚依依，十載江湖負宿知。", "時事未容輕所學，山中依舊只吟詩。"]'),
('78b3d13d-bf33-4f9f-bb78-56f6297769ab','普覺院登上人房老梅擅名滋久昔四靈與其先師道公方公遊賦詠盈紙距今三世矣余每至其所輒徘徊不忍去登亦對坐不倦有前輩之風槐逕弟拉同遊者賦詩因用其韻俾登藏之庶不愧昔日爾  其一','薛嵎','宋','宋诗','song-poetry','','[]','年年心與雪霜期，一點寒生古樹枝。',32,'全唐诗/poet.song.221000.json','["年年心與雪霜期，一點寒生古樹枝。", "昨夜故人相問信，隔窗無月坐移時。"]'),
('716a6af7-be3e-42dd-8961-814dd5afd7b5','普覺院登上人房老梅擅名滋久昔四靈與其先師道公方公遊賦詠盈紙距今三世矣余每至其所輒徘徊不忍去登亦對坐不倦有前輩之風槐逕弟拉同遊者賦詩因用其韻俾登藏之庶不愧昔日爾  其二','薛嵎','宋','宋诗','song-poetry','','[]','四靈歿後誰知己，惟有清香滿舊枝。',32,'全唐诗/poet.song.221000.json','["四靈歿後誰知己，惟有清香滿舊枝。", "頭白山僧猶愛客，爲曾親見老師時。"]'),
('76ce2ed0-430c-4e30-8ef8-aae4f224db43','感興','薛嵎','宋','宋诗','song-poetry','','[]','簞瓢吾道在，此樂語人難。',48,'全唐诗/poet.song.221000.json','["簞瓢吾道在，此樂語人難。", "遺却形骸累，始知天地寬。", "遠山不辨樹，高屋易生寒。", "數夜雪風急，編蘆壁未完。"]'),
('b8105070-2402-4944-b51a-bb1cbd6e7932','新年換桃符','薛嵎','宋','宋诗','song-poetry','','[]','桃符頻換句難新，休對春風訴舊貧。',64,'全唐诗/poet.song.221000.json','["桃符頻換句難新，休對春風訴舊貧。", "近日兒童談道學，幾時徵詔及閑人。", "山田收薄官輸在，樹雪吹殘曙色真。", "慨昔巢由老巖穴，終身擊壤作堯民。"]'),
('40c4f50d-208c-4905-b12d-010f69b95209','漁村雜詩十首再和前韻  其一','薛嵎','宋','宋诗','song-poetry','','[]','晴空萬里散餘霞，一葉漁舟穩似家。',32,'全唐诗/poet.song.221000.json','["晴空萬里散餘霞，一葉漁舟穩似家。", "學道未能全寡欲，水邊隙地亦栽花。"]'),
('a6c27a98-45fa-4274-a988-e7af59fabe56','漁村雜詩十首再和前韻  其二','薛嵎','宋','宋诗','song-poetry','','[]','蘭菊分畦筍作鞭，南山相對意悠然。',32,'全唐诗/poet.song.221000.json','["蘭菊分畦筍作鞭，南山相對意悠然。", "城中有路何曾入，只許蒼頭趁釣船。"]'),
('9d15862d-0fd6-4417-9d6a-d710b7c87e0b','漁村雜詩十首再和前韻  其三','薛嵎','宋','宋诗','song-poetry','','[]','此身閑却有來由，白髮中年已上頭。',32,'全唐诗/poet.song.221000.json','["此身閑却有來由，白髮中年已上頭。", "莫道無官無可棄，從今放下一齊休。"]'),
('d0a62ead-ccdf-465b-93b6-9ed7dde54f05','漁村雜詩十首再和前韻  其四','薛嵎','宋','宋诗','song-poetry','','[]','獨作漁樵最上賓，土風淳朴物情真。',32,'全唐诗/poet.song.221000.json','["獨作漁樵最上賓，土風淳朴物情真。", "鮑家兄弟皆和樂，林子詩豪膽壓人。"]'),
('2de12e89-e360-4547-ba2d-08f6eb74c8bc','漁村雜詩十首再和前韻  其五','薛嵎','宋','宋诗','song-poetry','','[]','巡簷脩竹晚風敲，古寺僧歸月下橈。',32,'全唐诗/poet.song.221000.json','["巡簷脩竹晚風敲，古寺僧歸月下橈。", "童子閉門無一事，只須清坐過中宵。"]'),
('fb969ef5-0837-42e5-b455-a46a54182776','漁村雜詩十首再和前韻  其六','薛嵎','宋','宋诗','song-poetry','','[]','微吟朗詠足風騷，切莫危言試怒濤。',32,'全唐诗/poet.song.221000.json','["微吟朗詠足風騷，切莫危言試怒濤。", "雲本無心泉自潔，不因作意立名高。"]'),
('93c15a29-4054-416a-877b-faea49a7241e','漁村雜詩十首再和前韻  其七','薛嵎','宋','宋诗','song-poetry','','[]','生涯小小落溪灣，妻子知時不說難。',32,'全唐诗/poet.song.221000.json','["生涯小小落溪灣，妻子知時不說難。", "畢竟直鈎爲計拙，晚來無酒可銷寒。"]'),
('a85ead99-59fa-4241-845a-881db0cdb356','漁村雜詩十首再和前韻  其八','薛嵎','宋','宋诗','song-poetry','','[]','暝色和煙四望迷，仰眠牛背覺天低。',32,'全唐诗/poet.song.221000.json','["暝色和煙四望迷，仰眠牛背覺天低。", "村翁遥指笙歌處，此地魚沉鳥不棲。"]'),
('0178a9de-d82b-4193-95f9-f7c2660584a6','漁村雜詩十首再和前韻  其九','薛嵎','宋','宋诗','song-poetry','','[]','雉入樊籠馬受羈，低頭猶怕欠趨時。',32,'全唐诗/poet.song.221000.json','["雉入樊籠馬受羈，低頭猶怕欠趨時。", "人心到此無真識，未必人疑先自疑。"]'),
('858b1fae-7060-4a6c-85d8-d78d0d71a2e6','漁村雜詩十首再和前韻  其一○','薛嵎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','歲寒無物可相依，惟有梅花似故知。',32,'全唐诗/poet.song.221000.json','["歲寒無物可相依，惟有梅花似故知。", "名世何曾在科甲，西湖處士只吟詩。"]'),
('5e803f41-c07c-4139-911f-aa5a601653cb','春晴泛湖','薛嵎','宋','宋诗','song-poetry','','[]','平湖新漲綠，沙觜浄涵波。',48,'全唐诗/poet.song.221000.json','["平湖新漲綠，沙觜浄涵波。", "芳草思無際，春風情最多。", "移舟動山影，止樂聽漁歌。", "得意唯鴻鵠，高飛避網羅。"]'),
('7f8f92e9-9f13-4a76-b16a-b76ee683cc64','呈井南劉主簿','薛嵎','宋','宋诗','song-poetry','','[]','何處井南居，青山遶屋廬。',48,'全唐诗/poet.song.221000.json','["何處井南居，青山遶屋廬。", "竹生從礙路，泉響不驚魚。", "有道貌亦古，淡交情似疎。", "慈親更彌壽，堂上步徐徐。"]'),
('51b2e402-bdf0-4e69-bfa3-39b61dcad285','春半','薛嵎','宋','宋诗','song-poetry','','[]','春半數風雨，水村增曉寒。',48,'全唐诗/poet.song.221000.json','["春半數風雨，水村增曉寒。", "不辭蓑笠重，自覺起居安。", "隔霧山疑失，占晴礎未乾。", "可憐桃與李，無語受摧殘。"]'),
('c1a9ed65-2f26-4eb6-8991-478bb8ee4d66','太古元西堂過萬壽謁住山肇淮海禪師并簡','薛嵎','宋','宋诗','song-poetry','','[]','老子舊知己，江湖獨爾思。',48,'全唐诗/poet.song.221000.json','["老子舊知己，江湖獨爾思。", "此行逢作者，送別若爲辭。", "風雨過春半，詩書滯海涯。", "心心儻相印，亦足慰衰遲。"]'),
('88133716-c585-4601-af63-47451f682c72','憶汪氏山亭舊遊并簡','薛嵎','宋','宋诗','song-poetry','','[]','因山爲址屋無多，中有幽人衣薜蘿。',64,'全唐诗/poet.song.221000.json','["因山爲址屋無多，中有幽人衣薜蘿。", "自擷溪毛充野腹，頻敲牛角和漁歌。", "舟車相過情難數，姓字長留石可磨。", "遥想對牀風雨際，一燈終夜照吟哦。"]'),
('2d2710c3-772d-4ed8-bee8-831834725eaf','古淡然老得帖住長蘆不受却歸松風舊寺次社中韻','薛嵎','宋','宋诗','song-poetry','','[]','拄杖挑雲上半肩，尋幽重到舊棲禪。',64,'全唐诗/poet.song.221000.json','["拄杖挑雲上半肩，尋幽重到舊棲禪。", "浮生多故成南北，白髮相驚問歲年。", "房閉松聲難辨雨，山連海脈暗通泉。", "自從勇却長蘆請，猿鶴終宵亦穩眠。"]'),
('8f30f073-2b22-43c8-8f5a-9a7338bf3a6e','佺上人遊方','薛嵎','宋','宋诗','song-poetry','','[]','燕鴻來去盡，蕭索此時心。',48,'全唐诗/poet.song.221000.json','["燕鴻來去盡，蕭索此時心。", "杖錫投何寺，風霜別故林。", "夜牀煨葉火，朝谷應樵音。", "往往長松下，看山坐獨吟。"]'),
('33c5f606-99ef-4d86-bb76-e8d11ad62f7f','送宋飲冰過四明郡齋  其一','薛嵎','宋','宋诗','song-poetry','','[]','元戎招士重親臨，喜遂詩書萬里心。',64,'全唐诗/poet.song.221000.json','["元戎招士重親臨，喜遂詩書萬里心。", "乍免客愁供帳具，暫停遊事戟門深。", "秋空矯首瞻魁彩，夜燭憑花聽雁音。", "從此文名滄海闊，好風三日到雞林。"]'),
('e46e68d9-18e3-455d-9913-849b44dc3908','送宋飲冰過四明郡齋  其二','薛嵎','宋','宋诗','song-poetry','','[]','憶昔曾登太白巔，閑雲留我石床眠。',64,'全唐诗/poet.song.221000.json','["憶昔曾登太白巔，閑雲留我石床眠。", "集詩刪失題猶記，人事乖違歲屢遷。", "極羨故交遊汗漫，不禁離思對嬋娟。", "山中乏致兼金餽，形迹相忘二十年。"]'),
('90ecb012-02a2-4910-b888-0a338b123170','松風隆首座住雲際禪院','薛嵎','宋','宋诗','song-poetry','','[]','山門開望海，鐘鼓動魚龍。',48,'全唐诗/poet.song.221000.json','["山門開望海，鐘鼓動魚龍。", "人具慈悲相，秋生寂寞容。", "隨身唯一鉢，留偈別雙松。", "後夜橋西月，支筇失所從。"]'),
('a9b20da2-57db-4c1f-9811-90c15704936c','入京逢故人','薛嵎','宋','宋诗','song-poetry','','[]','長貧復羈旅，共爽十年歡。',48,'全唐诗/poet.song.221000.json','["長貧復羈旅，共爽十年歡。", "在世誰無累，如君事獨難。", "蹴居憐火後，多病卧春殘。", "縱决歸山計，煙蘿不療寒。"]'),
('79bf4c2b-c509-4386-99d5-c4ea61ca984d','下第歸故園','薛嵎','宋','宋诗','song-poetry','','[]','扁舟摇蕩水心村，幾度煙波入夢魂。',64,'全唐诗/poet.song.221000.json','["扁舟摇蕩水心村，幾度煙波入夢魂。", "猨鶴認名聽號令，漁樵執禮敘寒溫。", "浮生多事景逾促，自古求人道不尊。", "莫爲窮途妨曠達，定應束帛賁丘園。"]'),
('2c5b95cd-e2fa-4aaa-b4f7-e46ce4f609a8','山中','薛嵎','宋','宋诗','song-poetry','','[]','依然木石居，造物任乘除。',48,'全唐诗/poet.song.221000.json','["依然木石居，造物任乘除。", "時事今休問，山中計不疎。", "泉聲增雨後，禽語變春初。", "吟得詩名世，終身甘荷鋤。"]'),
('1790c25e-8539-415a-ac36-eb3ebc65ae20','山居十首  其一','薛嵎','宋','宋诗','song-poetry','','[]','深澗遊群魚，高樹鳴幽禽。',48,'全唐诗/poet.song.221000.json','["深澗遊群魚，高樹鳴幽禽。", "山中白日長，同此逍遥心。", "脫粳香可炊，濁酒聊自斟。", "過茲非所求，孰爲升與沉。"]'),
('8ff2b722-11bf-4b69-ba1e-fdbff5012e00','山居十首  其二','薛嵎','宋','宋诗','song-poetry','','[]','陰壑生暮寒，白雲如炊煙。',48,'全唐诗/poet.song.221000.json','["陰壑生暮寒，白雲如炊煙。", "麋鹿不識人，時復近我前。", "青松三四株，石床在其邊。", "意思清且閑，可以終餘年。"]'),
('97b8cdb5-26ae-481d-966a-a07b5e152363','山居十首  其三','薛嵎','宋','宋诗','song-poetry','','[]','名利能移人，智者爲之愚。',48,'全唐诗/poet.song.221000.json','["名利能移人，智者爲之愚。", "歷觀古英雄，鮮或全其軀。", "幸逃世網牽，園綺真吾徒。", "勿令千載下，嘆惜斯人無。"]'),
('784436ba-aa89-488f-80ce-ef7c92597c13','山居十首  其四','薛嵎','宋','宋诗','song-poetry','','[]','前村雨脚收，斜陽掛高樹。',48,'全唐诗/poet.song.221000.json','["前村雨脚收，斜陽掛高樹。", "老翁牽牛歸，頗亦有幽趣。", "山風響茅屋，崖月導芒屨。", "平生江湖心，於此謝馳騖。"]'),
('f4430ebe-dbef-4f55-a059-2606c0f6fcae','山居十首  其五','薛嵎','宋','宋诗','song-poetry','','[]','龍居洞雲深，飛泉瀉絕壁。',48,'全唐诗/poet.song.221000.json','["龍居洞雲深，飛泉瀉絕壁。", "不聞耳邊喧，但覺心境寂。", "富貴由他人，得失俱抱戚。", "孰能全其天，山中樗與櫟。"]'),
('f6f7d347-f219-488a-aa37-ebbe98ef333b','山居十首  其六','薛嵎','宋','宋诗','song-poetry','','[]','午睡不覺長，童子入城迴。',48,'全唐诗/poet.song.221000.json','["午睡不覺長，童子入城迴。", "地爐散微煙，煨芋已成灰。", "獨酌無佳賓，梅花爲吾開。", "須臾山月高，顧影空徘徊。"]'),
('586705be-6175-40bb-af7a-8c3ac5fbaba4','山居十首  其七','薛嵎','宋','宋诗','song-poetry','','[]','木落山轉空，景駛寒亦早。',48,'全唐诗/poet.song.221000.json','["木落山轉空，景駛寒亦早。", "百草無慍容，低頭就枯槁。", "形生復形化，安用置懷抱。", "千古丘跖分，所論非壽夭。"]'),
('c844d945-627f-4fef-8f57-fdaae0bed9c0','山居十首  其八','薛嵎','宋','宋诗','song-poetry','','[]','古調今誰彈，至樂非外假。',48,'全唐诗/poet.song.221000.json','["古調今誰彈，至樂非外假。", "淵明愛無絃，此意知者寡。", "放鶴未歸來，時倚長松下。", "旁觀彼何人，笑我衣裳野。"]'),
('95836899-1d66-40d4-ad30-992498ab6fb2','山居十首  其九','薛嵎','宋','宋诗','song-poetry','','[]','老妻倦縫紉，癡兒厭藜藿。',48,'全唐诗/poet.song.221000.json','["老妻倦縫紉，癡兒厭藜藿。", "一貧誰復言，多累吾已錯。", "山半雲可耕，山下泉可鑿。", "軒冕亦儻來，豈得長如昨。"]'),
('b9631aa7-3157-41f2-92d7-5a26f3ef6f5b','山居十首  其一○','薛嵎','宋','宋诗','song-poetry','','[]','柴門長日關，不礙溪水流。',48,'全唐诗/poet.song.221000.json','["柴門長日關，不礙溪水流。", "桃花樹難尋，悵望迴輕舟。", "雖無武陵源，事與昔人侔。", "已矣勿復言，白首安吾丘。"]'),
('bc1c61a5-c10f-4684-9263-25b34edf1aa8','廉村薛庭芝訴貧於余余亦貧不能周之贈以是詩','薛嵎','宋','宋诗','song-poetry','','[]','兩窮相值愁無計，同是開元補闕孫。',32,'全唐诗/poet.song.221000.json','["兩窮相值愁無計，同是開元補闕孫。", "百世清風於此在，莫將貧悴對人言。"]'),
('c669b2ec-b733-48c2-98a8-21a52464fea1','素上人遊方','薛嵎','宋','宋诗','song-poetry','','[]','山深不可見，一錫又雲飛。',48,'全唐诗/poet.song.221000.json','["山深不可見，一錫又雲飛。", "梵譯通方語，林霜點衲衣。", "神閑生境寂，思苦入吟微。", "寒月空相照，何人夜扣扉。"]'),
('aa623d77-c973-4c7d-bac8-47f7fbf236d5','送蓑衣與陳子淵漫成口號','薛嵎','宋','宋诗','song-poetry','','[]','莎草爲衣葉葉新，已知難上貴官身。',32,'全唐诗/poet.song.221000.json','["莎草爲衣葉葉新，已知難上貴官身。", "野人相贈無他意，從使心親迹更親。"]'),
('19701181-e1bb-4afc-9373-a2105fe0bcd8','自君之出矣三首  其一','薛嵎','宋','宋诗','song-poetry','','[]','自君之出矣，淚對花枝洒。',24,'全唐诗/poet.song.221000.json','["自君之出矣，淚對花枝洒。", "風窗挑夜燈，心在無油瀉。"]'),
('05f50394-1447-4995-bb99-3eeaed0bb4d0','自君之出矣三首  其二','薛嵎','宋','宋诗','song-poetry','','[]','自君之出矣，荏苒度寒燠。',24,'全唐诗/poet.song.221000.json','["自君之出矣，荏苒度寒燠。", "譬彼雙鯉魚，書辭長在腹。"]'),
('48fea12c-f8d9-4757-8836-7aacd61e4d0a','自君之出矣三首  其三','薛嵎','宋','宋诗','song-poetry','','[]','自君之出矣，抱此離恨情。',24,'全唐诗/poet.song.221000.json','["自君之出矣，抱此離恨情。", "春蠶不作絲，纏綿過一生。"]'),
('44d84482-2e6c-4149-844c-cf317da72cd7','越僧一書記索賦二絕 松風閣','薛嵎','宋','宋诗','song-poetry','','[]','何處笙簫起半空，滿山斜日動蛟龍。',32,'全唐诗/poet.song.221000.json','["何處笙簫起半空，滿山斜日動蛟龍。", "老僧無語凭欄久，過盡白雲千萬重。"]'),
('77216db5-8390-490e-ab3d-ddf795710d82','越僧一書記索賦二絕 月泉','薛嵎','宋','宋诗','song-poetry','','[]','月色泉聲境自真，有身終不惹埃塵。',32,'全唐诗/poet.song.221000.json','["月色泉聲境自真，有身終不惹埃塵。", "山中受用祇如此，住者知爲澹泊人。"]'),
('77c52314-817c-4c88-8b48-ce5ca3143dbf','爲鄭菊山賦斗室','薛嵎','宋','宋诗','song-poetry','','[]','居然真樂地，跬步亦徜徉。',48,'全唐诗/poet.song.221000.json','["居然真樂地，跬步亦徜徉。", "大器何曾局，脩程未易量。", "中天應躔象，吾道即宮牆。", "萬斛泉源在，非徒志秕糠。"]'),
('26617c72-78b7-49e4-ab78-1fd9df29152e','松阜弟於寶成寺祖墓之側營創別業爲賦得閑亭詩取又得浮生半日閑之句','薛嵎','宋','宋诗','song-poetry','','[]','陟巘心已清，復此風雨蔽。',216,'全唐诗/poet.song.221000.json','["陟巘心已清，復此風雨蔽。", "高人疏鑿餘，理道頗超詣。", "卜築諧素志，緇侶欣共濟。", "脩竹尚無恙，巢鶴亦數世。", "空山嵐欲滴，近水石可憇。", "春睡朝旭升，夜語孤燭繼。", "高扁出林麓，先壠記苗裔。", "嚴鐘警晨昏，群岫羅扈衛。", "身同野鹿遊，跡許巢父媲。", "蝸角自爲雄，蟻磨卒至斃。", "靡懷半日羨，詎識終老計。", "吾廬並漁村，興往輒鼓枻。", "野衣裁芰荷，敗屋粘薜荔。", "川陸阻會面，歲月迅流逝。", "茲情不可忘，淡交慎勿替。", "及時畢婚嫁，即事無芥蔕。", "相從丘壑真，永使心迹契。", "泉石聞斯言，庶以當盟誓。"]'),
('97827e87-24bd-42f6-815d-48057c3ec99b','項大著挽詩','薛嵎','宋','宋诗','song-poetry','','[]','耻爲恩門屈，寧辭御史遷。',48,'全唐诗/poet.song.221000.json','["耻爲恩門屈，寧辭御史遷。", "力陳歸老疏，自盡讀書年。", "秘府神遊地，浮榮夢覺前。", "世間真不死，未必屬蒼天。"]'),
('177d1935-4012-47f9-99c7-3e744f098e36','劉荆山歸自惟揚新營漁屋退居','薛嵎','宋','宋诗','song-poetry','','[]','謾道歸來晚，閑中日最長。',48,'全唐诗/poet.song.221000.json','["謾道歸來晚，閑中日最長。", "漁翁尊齒序，客子效戎裝。", "野水涵秋霽，風荷動夕陽。", "十年畢婚嫁，亦勝爲人忙。"]'),
('b0f408f2-1926-4105-9d51-81a68ad69994','定菴遠山主','薛嵎','宋','宋诗','song-poetry','','[]','修持功行滿，不墮劫中塵。',48,'全唐诗/poet.song.221000.json','["修持功行滿，不墮劫中塵。", "龍象西天邃，杉松卵塔新。", "臘高同輩盡，歛薄小師貧。", "生滅理無二，交深獨愴神。"]'),
('3e76d5ea-22ec-44b0-af7a-024322f3d7b2','哭槐逕弟','薛嵎','宋','宋诗','song-poetry','','[]','孤僻由天性，看山獨展眉。',48,'全唐诗/poet.song.221000.json','["孤僻由天性，看山獨展眉。", "豈無身後慮，猶課病中詩。", "泉石寧非祟，蒼旻不可知。", "平生唯愛菊，增我九秋悲。"]'),
('4a8b813f-f215-4b9c-92a4-fe550992299e','林氏梅巖','薛嵎','宋','宋诗','song-poetry','','[]','古意元從澹泊來，雲根香雪點磯苔。',64,'全唐诗/poet.song.221000.json','["古意元從澹泊來，雲根香雪點磯苔。", "靜觀造化春長在，不是冰霜凍得開。", "半影落池涵潔白，一峰無路接塵埃。", "逋仙家世君端的，只恐清吟未易陪。"]'),
('62bcb879-3794-4da7-bfd2-33a3c7e4b514','王九山挽詩  其一','薛嵎','宋','宋诗','song-poetry','','[]','古史無完傅，清風獨可模。',48,'全唐诗/poet.song.221000.json','["古史無完傅，清風獨可模。", "從誰問出處，舉世在泥塗。", "氣直於時忤，身榮與道俱。", "士林爲重惜，揮淚奠生芻。"]'),
('11e7a26c-40f8-4a67-929e-13ad6a4eee59','王九山挽詩  其二','薛嵎','宋','宋诗','song-poetry','','[]','修行過衲子，蔬飯幾昏晨。',48,'全唐诗/poet.song.221000.json','["修行過衲子，蔬飯幾昏晨。", "自草休官疏，猶嫌在世身。", "片雲先塚近，寒月萬松鄰。", "爲鬼還應別，平生有善因。"]'),
('933918ef-f0b5-4818-987a-f0ec8031aad3','王九山挽詩  其三','薛嵎','宋','宋诗','song-poetry','','[]','俗論鄙迂儒，公胡獨受欺。',48,'全唐诗/poet.song.221000.json','["俗論鄙迂儒，公胡獨受欺。", "焦桐方入調，夜鵲忽驚枝。", "心事將誰許，身名負己知。", "九原如可作，白首誓爲期。"]'),
('d84bb83c-c284-4d22-b588-76b2f387359c','逢舊友生','薛嵎','宋','宋诗','song-poetry','','[]','交遊半零落，身在復長貧。',48,'全唐诗/poet.song.221000.json','["交遊半零落，身在復長貧。", "對語寒燈盡，相看白髮新。", "兵興無樂土，市近少閑人。", "遥憶桃源路，鳥啼花自春。"]'),
('32e7afc6-9a80-462f-a4d3-4acb3cf70594','和清溪可居壁間韻  其一','薛嵎','宋','宋诗','song-poetry','','[]','松風相對揜重關，何止浮生半日閑。',32,'全唐诗/poet.song.221000.json','["松風相對揜重關，何止浮生半日閑。", "此是仙家真境界，蓬萊猶在有無間。"]'),
('4deaf722-782a-4bb2-976c-b2f461a1f1c7','和清溪可居壁間韻  其二','薛嵎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','日日虛廊步百迴，吟邊時有可人來。',32,'全唐诗/poet.song.221000.json','["日日虛廊步百迴，吟邊時有可人來。", "西湖處士詩名世，老向孤山亦爲梅。"]'),
('7d9ace98-4982-4aeb-90ed-b1c5be0c4230','林景雲令祖夫妻隨其子各居同日葬','薛嵎','宋','宋诗','song-poetry','','[]','真誥巖前舊築居，夫妻雙化是仙期。',64,'全唐诗/poet.song.221000.json','["真誥巖前舊築居，夫妻雙化是仙期。", "至今耕隴桑麻地，全似桃源晉宋時。", "窀穸同晨符吉卜，親朋分夜別靈帷。", "詩書孫子名方盛，錦誥重恩日未遲。"]'),
('90ca0ba0-ef00-42f2-8458-4032c587c4b6','康氏端齋','薛嵎','宋','宋诗','song-poetry','','[]','於焉能取友，人己兩無偏。',48,'全唐诗/poet.song.221000.json','["於焉能取友，人己兩無偏。", "立行有如此，前脩宜比肩。", "吟情近風雅，胸次著林泉。", "愧我全迂僻，交遊又十年。"]'),
('112881b4-0bf5-4119-bbb6-907fedab6ad1','陳子淵台州添倅','薛嵎','宋','宋诗','song-poetry','','[]','高志愛官閑，來從玉筍班。',48,'全唐诗/poet.song.221000.json','["高志愛官閑，來從玉筍班。", "離家買湖石，開印對巾山。", "風月添新句，朋遊記舊顔。", "桃花元有約，猥賤未能攀。"]'),
('1db3b244-c26c-4dd6-98b9-19eae861eeb4','潘氏梅所','薛嵎','宋','宋诗','song-poetry','','[]','種梅營數椽，四壁但蕭然。',48,'全唐诗/poet.song.221000.json','["種梅營數椽，四壁但蕭然。", "清带山林氣，香來筆硯邊。", "雲深天向晚，人立鶴趨前。", "余亦歲寒者，相從恰暮年。"]'),
('52129972-0431-4364-ad9c-a376f10fec29','近買山范灣自營藏地與亡弟草塘君及外家墓塋悉可跂望感事述情繼有是作  其一','薛嵎','宋','宋诗','song-poetry','','[]','因緣還是范灣邊，乾巽峰高四應全。',64,'全唐诗/poet.song.221000.json','["因緣還是范灣邊，乾巽峰高四應全。", "千古青山逢具眼，數莖秋鬢近衰年。", "倒騎黄犢循來路，貪看行龍下遠田。", "慙愧鄰翁爲指說，傳聞此地産英賢。"]'),
('457f4f9a-718e-4671-a0cf-3a71aeb4e300','近買山范灣自營藏地與亡弟草塘君及外家墓塋悉可跂望感事述情繼有是作  其二','薛嵎','宋','宋诗','song-poetry','','[]','外家後事凄凉甚，老婦思親哭最哀。',64,'全唐诗/poet.song.221000.json','["外家後事凄凉甚，老婦思親哭最哀。", "今日青山留我在，他年寒食望甥來。", "極知造物成吾志，可但精靈慰夜臺。", "惆悵昔時原上路，獨餘宿草見春回。"]'),
('f35c0054-5167-4457-af5a-39c2f558c812','近買山范灣自營藏地與亡弟草塘君及外家墓塋悉可跂望感事述情繼有是作  其三','薛嵎','宋','宋诗','song-poetry','','[]','草塘相望隔重雲，愧我爲兄蚤哭君。',64,'全唐诗/poet.song.221000.json','["草塘相望隔重雲，愧我爲兄蚤哭君。", "少日對吟聽夜雨，老來無計撫孤墳。", "泉臺冥漠唯增感，人事安排已十分。", "莫待他年推吉應，如今友愛最先聞。"]'),
('98b1e14f-84f3-410a-bacb-62a39401bf57','近買山范灣自營藏地與亡弟草塘君及外家墓塋悉可跂望感事述情繼有是作  其四','薛嵎','宋','宋诗','song-poetry','','[]','敢慕昔賢居曠達，分甘吟骨寄山阿。',64,'全唐诗/poet.song.221000.json','["敢慕昔賢居曠達，分甘吟骨寄山阿。", "劉伶常備隨身鍤，陶令曾爲自挽歌。", "未必浮生於此悟，算來忙處爲人多。", "北邙原上堪回首，莫枉心情用太過。"]'),
('21b31203-2ffe-4379-99ef-7da737e6bfe9','近買山范灣自營藏地與亡弟草塘君及外家墓塋悉可跂望感事述情繼有是作  其五','薛嵎','宋','宋诗','song-poetry','','[]','十萬買山渾可事，放教身死骨猶香。',64,'全唐诗/poet.song.221000.json','["十萬買山渾可事，放教身死骨猶香。", "不知筋力何年盡，看到杉松幾尺長。", "管郭豈能謀富貴，詩書元自著興亡。", "采薇歌在無人識，千載清風獨首陽。"]'),
('f5ff0d24-387b-442b-a14e-c87635ae9378','近買山范灣自營藏地與亡弟草塘君及外家墓塋悉可跂望感事述情繼有是作  其六','薛嵎','宋','宋诗','song-poetry','','[]','分明來日已無幾，還似參禪未透時。',64,'全唐诗/poet.song.221000.json','["分明來日已無幾，還似參禪未透時。", "吟骨縱清難免死，黄菁多啖亦充饑。", "題詩遣得山精去，近俗偏將古墓夷。", "合眼便爲泉下鬼，此身康濟莫宜遲。"]'),
('b0f77cc8-f9dc-4d1b-a44e-b061e03e9a41','近買山范灣自營藏地與亡弟草塘君及外家墓塋悉可跂望感事述情繼有是作  其七','薛嵎','宋','宋诗','song-poetry','','[]','大有公卿弗似吾，一枝藤上掛葫蘆。',64,'全唐诗/poet.song.221000.json','["大有公卿弗似吾，一枝藤上掛葫蘆。", "旋疏苔石通崖溜，自祝山神保鶴雛。", "休羨銘旌題極品，試將槐樹植三株。", "依然此事憑陰德，從古幽明理不殊。"]'),
('97e7632b-6a15-438d-aee6-4e4c103cf943','近買山范灣自營藏地與亡弟草塘君及外家墓塋悉可跂望感事述情繼有是作  其八','薛嵎','宋','宋诗','song-poetry','','[]','贏得青山終老看，閑身受用不須多。',64,'全唐诗/poet.song.221000.json','["贏得青山終老看，閑身受用不須多。", "風霜落木時將暮，功業無心鏡懶磨。", "道士共聯石鼎句，村童能和草庵歌。", "蓋棺一事安排了，肯信光陰去似梭。"]'),
('17431319-9aaa-47fb-8c2c-b1b48f36fc2a','近買山范灣自營藏地與亡弟草塘君及外家墓塋悉可跂望感事述情繼有是作  其九','薛嵎','宋','宋诗','song-poetry','','[]','山中百事且休聞，也莫參禪莫鍊神。',64,'全唐诗/poet.song.221000.json','["山中百事且休聞，也莫參禪莫鍊神。", "纏樹古藤無了日，隨風亂葉豈由身。", "閑來景物吟方到，靜處工夫識始真。", "想得大槐宮裏夢，日高猶有未醒人。"]'),
('bdd76ead-ca8b-4679-946f-3c1d2c808fd9','近買山范灣自營藏地與亡弟草塘君及外家墓塋悉可跂望感事述情繼有是作  其一○','薛嵎','宋','宋诗','song-poetry','','[]','依然且作住菴看，茆屋三間辦不難。',64,'全唐诗/poet.song.221000.json','["依然且作住菴看，茆屋三間辦不難。", "戶外莫容千駟馬，客床唯置兩蒲團。", "深林藏虎風長怒，短木支門睡自安。", "西北干戈猶未已，偶逢樂土度衰殘。"]'),
('cdc5e23d-44ac-4720-9a3a-98ca38634ff5','高新甫雲崖','薛嵎','宋','宋诗','song-poetry','','[]','步步危機死不知，白雲深處最平夷。',32,'全唐诗/poet.song.221000.json','["步步危機死不知，白雲深處最平夷。", "猨啼鶴唳非無意，纔近高人便入詩。"]'),
('3591da22-6cc8-4397-a535-b3d328025aab','悼薛君載','薛嵎','宋','宋诗','song-poetry','','[]','衣被唯綀褐，長閑未覺貧。',48,'全唐诗/poet.song.221000.json','["衣被唯綀褐，長閑未覺貧。", "將何折君壽，不盡百年身。", "竹樹多於屋，禽魚近得人。", "生無世情戀，寧復怨蒼旻。"]'),
('10bc7509-03eb-4560-aa33-82d465c135e2','石窗通上人南遊并謁劉後村','薛嵎','宋','宋诗','song-poetry','','[]','所師郊與島，知己又應難。',48,'全唐诗/poet.song.221000.json','["所師郊與島，知己又應難。", "羽檄邊烽急，風霜歲事殘。", "出家忘路遠，度海識天寬。", "文暢浮屠者，當時亦慕韓。"]'),
('a610bee4-4022-446c-aef3-92126f429c60','君成弟清溪','薛嵎','宋','宋诗','song-poetry','','[]','孺子歌猶在，滄浪可濯纓。',48,'全唐诗/poet.song.221000.json','["孺子歌猶在，滄浪可濯纓。", "流來如玉潔，止處似心平。", "魚避飛鳬影，荷添落雨聲。", "詩書源更遠，千古媲交情。"]'),
('cdf7d2b1-b5b7-4779-9e4d-be68fdf1614d','哭中師雪崖','薛嵎','宋','宋诗','song-poetry','','[]','衆裏知心少，唯師是故人。',48,'全唐诗/poet.song.221000.json','["衆裏知心少，唯師是故人。", "臨終書未答，昨夜夢全真。", "鶴唳渾如哭，花開不似春。", "近逢同住者，得問病元因。"]'),
('4aee85fc-1f29-4555-803a-e01809e90aef','霽雪亭','薛嵎','宋','宋诗','song-poetry','','[]','千樹玉成林，遠香清可尋。',48,'全唐诗/poet.song.221000.json','["千樹玉成林，遠香清可尋。", "幾疑安道在，直得老逋吟。", "迥與春風異，唯宜晝日陰。", "塵中無此景，羨爾棄華簪。"]'),
('29865c3a-f704-4ab8-86c9-5767420e9be2','方氏墓廬扁曰白雲飛處','薛嵎','宋','宋诗','song-poetry','','[]','諸峰互隠蔽，一望一增悲。',48,'全唐诗/poet.song.221000.json','["諸峰互隠蔽，一望一增悲。", "觸目易成感，思親無盡時。", "松扉陰似雨，翁仲立如癡。", "出岫亦何意，悠然自不知。"]'),
('de1f22b2-2de5-4853-ac3f-6f249f52b789','漁村偶題','薛嵎','宋','宋诗','song-poetry','','[]','莫道柴門窄，斷無車馬聲。',48,'全唐诗/poet.song.221000.json','["莫道柴門窄，斷無車馬聲。", "苦吟成集少，久病見人生。", "花落寒猶在，春陰雨未成。", "漁村名自我，鷗鷺勿相輕。"]'),
('19befed8-b471-42c8-b50c-38794881ea52','唐補闕清風亭','薛嵎','宋','宋诗','song-poetry','','[]','去國遺忠藎，朝盤托諷深。',48,'全唐诗/poet.song.221000.json','["去國遺忠藎，朝盤托諷深。", "因知潔己意，亦是愛君心。", "貌像意全古，子孫貧至今。", "清風如可繼，塊土已埋沉。"]'),
('dc2c4636-f3c6-4292-9737-8583312be72b','寄珂雪屋','薛嵎','宋','宋诗','song-poetry','','[]','積雪覆茅屋，僧居清更清。',48,'全唐诗/poet.song.221000.json','["積雪覆茅屋，僧居清更清。", "浮生千劫盡，長日一燈明。", "野鳥呼能下，山靈避不行。", "舊時江月住，時聽誦經聲。"]'),
('65e014aa-acf5-4d26-a5db-a74c6fbb39b9','賦山雲姪偶耡','薛嵎','宋','宋诗','song-poetry','','[]','扶犂人所賤，何苦事耕耘。',48,'全唐诗/poet.song.221000.json','["扶犂人所賤，何苦事耕耘。", "生意未終息，雨聲曾厭聞。", "詩書長在手，畚鍤豈勞君。", "祇恐青雲上，能將此志分。"]'),
('38b41bca-e4cd-4b14-833d-ed0732ba047e','還甘泉沈氏詩卷','薛嵎','宋','宋诗','song-poetry','','[]','之人吾畏友，相望水東西。',48,'全唐诗/poet.song.221000.json','["之人吾畏友，相望水東西。", "筆下山林趣，詩中五十題。", "讀書長閉戶，自奉只羹藜。", "名字他年出，雙松應共齊。"]'),
('73b26e30-771c-4269-8b06-e27e3819627e','萬象亭','薛嵎','宋','宋诗','song-poetry','','[]','年年此地駐吟鞍，十萬人家指掌寬。',64,'全唐诗/poet.song.221000.json','["年年此地駐吟鞍，十萬人家指掌寬。", "天上星辰依舊遠，山中松桂不知寒。", "月生滄海一輪靜，雲泊闌干片影殘。", "見說亭基從古在，擬將圖志試尋看。"]'),
('fd2fe3b9-0ab5-4134-872e-377cd7883061','朱氏雲壑','薛嵎','宋','宋诗','song-poetry','','[]','舒卷悠悠付太空，居然丘壑具胸中。',64,'全唐诗/poet.song.221000.json','["舒卷悠悠付太空，居然丘壑具胸中。", "人生知己終難必，世上無心自不同。", "片石若浮龍在水，遠峰欲露樹吟風。", "羨君隠處有如此，想見詩成字字工。"]'),
('120ef7a1-c7b2-4ad1-a66d-571ada551bba','本無師與槐徑弟交遊二十年矣古人謂百篇詩盡和一盞酒須分余於二公亦云槐徑既歿本無編其往來之詩號曰雲林酬唱僭述鄙句奉呈','薛嵎','宋','宋诗','song-poetry','','[]','中年爲此別，悲動故交情。',48,'全唐诗/poet.song.221000.json','["中年爲此別，悲動故交情。", "案上雲林卷，山中風木聲。", "夢回驚復喜，詩在死如生。", "幾番西郊路，逢師獨自行。"]'),
('8c335751-c81a-4014-97a1-a70b1ccef080','宣氏梅邊','薛嵎','宋','宋诗','song-poetry','','[]','自入孤山詠，梅花最識詩。',48,'全唐诗/poet.song.221000.json','["自入孤山詠，梅花最識詩。", "喜逢吟苦友，共此歲寒期。", "曙色雪初霽，暗香春未知。", "前村風景別，祇是愛茅茨。"]'),
('d88ec918-1fd7-4f40-878d-6f76df47abf2','耕樂','薛嵎','宋','宋诗','song-poetry','','[]','躬耕樂道真吾事，三聘看來未是榮。',32,'全唐诗/poet.song.221000.json','["躬耕樂道真吾事，三聘看來未是榮。", "時尚可爲君更悟，何妨藜藿度殘生。"]'),
('aa264671-5921-4562-88d7-d040a3f97534','王民山惠詩','薛嵎','宋','宋诗','song-poetry','','[]','民山名字出，朋輩獨推先。',48,'全唐诗/poet.song.221000.json','["民山名字出，朋輩獨推先。", "不奉寒暄問，于今四十年。", "傳來詩似錦，倏去步如仙。", "自古山林士，無營貌亦賢。"]'),
('ba9f6556-a1d6-4cdd-9a71-2a0ec565099f','漁村即事','薛嵎','宋','宋诗','song-poetry','','[]','維舟古渡頭，四望是汀洲。',48,'全唐诗/poet.song.221000.json','["維舟古渡頭，四望是汀洲。", "水闊唯宜夏，荷枯不礙秋。", "困歸牛背穩，曉汲井雲浮。", "獨坐愁無侶，多番爲月留。"]'),
('15e7b90e-22b2-4480-904d-9962fbfe8a49','潘氏可軒','薛嵎','宋','宋诗','song-poetry','','[]','可人居此地，稱此可軒名。',48,'全唐诗/poet.song.221000.json','["可人居此地，稱此可軒名。", "力學倘無倦，終身集大成。", "言辭寓深淺，權度要分明。", "體認工夫到，何妨緩作程。"]'),
('59543351-4161-4071-8322-57b5fa0d03a6','青藜閣爲林景雲賦','薛嵎','宋','宋诗','song-poetry','','[]','九斗峰前太乙臨，星辰亦監此時心。',64,'全唐诗/poet.song.221000.json','["九斗峰前太乙臨，星辰亦監此時心。", "樓高不礙光芒入，坐久忽驚風露深。", "千古聖賢書裏見，吾身學問性中尋。", "夜窗勤苦追先哲，名字何分昔與今。"]'),
('149b9ea5-a456-4feb-8245-b962a173899d','追惜永嘉前政知縣趙大猷時景定改元','薛嵎','宋','宋诗','song-poetry','','[]','興言民父恩猶在，何故年來盡不如。',64,'全唐诗/poet.song.221000.json','["興言民父恩猶在，何故年來盡不如。", "清節苦於爲士日，歸裝輕似到官初。", "月明往事尋思遍，燈下懷人音問疎。", "矯首天朝除目到，放教田里得安居。"]'),
('9a06bd36-84cc-4e86-b5ec-a47c354a003f','高氏石雲','薛嵎','宋','宋诗','song-poetry','','[]','閬仙曾得句，月下自推敲。',48,'全唐诗/poet.song.221000.json','["閬仙曾得句，月下自推敲。", "以此幽閑趣，長爲淡泊交。", "水寒梅照影，霜滑鳥歸巢。", "余亦同懷者，從君結把茅。"]'),
('c4dd8a71-71ab-4e28-b602-2fc133a2ee65','清醒','薛嵎','宋','宋诗','song-poetry','','[]','獨懷忠憤赴湘中，舉國昏昏志不同。',32,'全唐诗/poet.song.221000.json','["獨懷忠憤赴湘中，舉國昏昏志不同。", "漁父笑君君亦笑，煙波相望各西東。"]'),
('6aefc88b-2c1e-4fb9-8ae5-5a7a3457ccad','囊螢  其一','薛嵎','宋','宋诗','song-poetry','','[]','山中不羨青藜貴，清夢何曾到石渠。',32,'全唐诗/poet.song.221000.json','["山中不羨青藜貴，清夢何曾到石渠。", "裁得綀囊連夜喜，兒童也學裹衣裾。"]'),
('7478b563-30d9-463a-9981-62d271bd6734','囊螢  其二','薛嵎','宋','宋诗','song-poetry','','[]','殘星數點照科斗，此事分明屬後生。',32,'全唐诗/poet.song.221000.json','["殘星數點照科斗，此事分明屬後生。", "記得年時頭未雪，夜窗不覺又三更。"]'),
('fa653730-201c-43bf-b793-295284af2a26','謝松岡姪惠詩','薛嵎','宋','宋诗','song-poetry','','[]','韋布名猶盛，詩書不負人。',48,'全唐诗/poet.song.221000.json','["韋布名猶盛，詩書不負人。", "每過臨水宅，長想釣魚身。", "思苦詩難和，歲寒交始真。", "廼翁憐病久，余病復兼貧。"]'),
('70319467-61b8-4576-913c-e3c6dc0026ed','邵氏悅心堂','薛嵎','宋','宋诗','song-poetry','','[]','擾擾利名役，鬢髭霜雪侵。',48,'全唐诗/poet.song.221000.json','["擾擾利名役，鬢髭霜雪侵。", "要知充此性，即是悅吾心。", "有道境常裕，無營味最深。", "紛華安肯羨，出見更酣沈。"]'),
('f3c1f8f9-75f8-429e-835d-34d3a3877d0e','別鶴','薛嵎','宋','宋诗','song-poetry','','[]','見說瀛洲萬里程，相思猶覬下青冥。',64,'全唐诗/poet.song.221000.json','["見說瀛洲萬里程，相思猶覬下青冥。", "已歸天上神仙籍，不就人間飲啄腥。", "昨夜月明如失友，故園籠在且休扃。", "鄰家亦有雛堪待，丹頂微微振薄翎。"]'),
('d67af860-dc2e-4fd1-b9a1-bc1d301f60d9','冬日野步','薛嵎','宋','宋诗','song-poetry','','[]','樹上有禽啼似春，聲高聲下亦何心。',32,'全唐诗/poet.song.221000.json','["樹上有禽啼似春，聲高聲下亦何心。", "幽人拄杖移時立，句句詩中是苦吟。"]'),
('6b31b8d8-675f-46ce-9aa2-58d20748358e','山中梅花  其一','薛嵎','宋','宋诗','song-poetry','','[]','詩人魂在梅花上，不比垂楊管別離。',32,'全唐诗/poet.song.221000.json','["詩人魂在梅花上，不比垂楊管別離。", "野鶴聲聲聲漸遠，定應飛報月明知。"]'),
('a9fd4423-0069-4327-9782-0247b4ed9c52','山中梅花  其二','薛嵎','宋','宋诗','song-poetry','','[]','已有梅花未有詩，青山相對動愁眉。',32,'全唐诗/poet.song.221000.json','["已有梅花未有詩，青山相對動愁眉。", "山翁只在山中住，花落花開總不知。"]'),
('410bcd07-50b1-4049-9299-b8632599d054','山中','薛嵎','宋','宋诗','song-poetry','','[]','長日山中坐，白雲應笑人。',48,'全唐诗/poet.song.221000.json','["長日山中坐，白雲應笑人。", "浮生塵未脫，至老趣難真。", "身在影猶贅，年豐家自貧。", "莫將吟事廢，柳色已知春。"]'),
('49312533-8954-46c8-9fbd-f032b050c6dd','漁父詞七首  其一','薛嵎','宋','宋诗','song-poetry','','[]','蘭芷流來水亦香，滿汀鷗鷺動斜陽。',32,'全唐诗/poet.song.221000.json','["蘭芷流來水亦香，滿汀鷗鷺動斜陽。", "聲欵乃，間鳴榔，儂家只住岸西旁。"]'),
('81f37fbd-078e-43e6-b40c-f6f3b12f4001','漁父詞七首  其二','薛嵎','宋','宋诗','song-poetry','','[]','翁嫗齊眉婦亦賢，小姑顔貌正笄年。',32,'全唐诗/poet.song.221000.json','["翁嫗齊眉婦亦賢，小姑顔貌正笄年。", "頭髮亂，髻鬟偏，愛把花枝立柂前。"]'),
('87ed7c5f-1330-4d0c-802a-b31a5fed88f4','漁父詞七首  其三','薛嵎','宋','宋诗','song-poetry','','[]','湘妃淚染竹痕斑，風雨連朝下釣難。',32,'全唐诗/poet.song.221000.json','["湘妃淚染竹痕斑，風雨連朝下釣難。", "春浪急，石磯寒，買得茅柴味亦酸。"]'),
('2b9ad584-400b-4178-a01c-1363c714f108','漁父詞七首  其四','薛嵎','宋','宋诗','song-poetry','','[]','滿湖飛雪攪長空，急起呼兒上短篷。',32,'全唐诗/poet.song.221000.json','["滿湖飛雪攪長空，急起呼兒上短篷。", "蓑笠具，畫圖同，鐵笛聲長曲未終。"]'),
('f713a29c-8e7e-4cc7-93f1-e4160bc0c497','漁父詞七首  其五','薛嵎','宋','宋诗','song-poetry','','[]','離騷讀罷怨聲聲，曾向江邊問屈平。',32,'全唐诗/poet.song.221000.json','["離騷讀罷怨聲聲，曾向江邊問屈平。", "醒還醉，醉還醒，笑指滄浪可濯纓。"]'),
('5d36023e-962a-4649-abc3-fec5765cc572','漁父詞七首  其六','薛嵎','宋','宋诗','song-poetry','','[]','白髮髼鬆不記年，扁舟泊在荻花邊。',32,'全唐诗/poet.song.221000.json','["白髮髼鬆不記年，扁舟泊在荻花邊。", "天上月，水中天，夜夜煙波得意眠。"]'),
('bf4a89f7-c206-42c6-b43c-19e8c62a16de','漁父詞七首  其七','薛嵎','宋','宋诗','song-poetry','','[]','只有青山可卜鄰，妻兒語笑意全真。',32,'全唐诗/poet.song.221000.json','["只有青山可卜鄰，妻兒語笑意全真。", "休識字，莫嫌貧，方是安閑第一人。"]'),
('40795192-9b83-457a-86e4-e0ae362e77b7','漁村遠望因思槐逕弟同遊之樂','薛嵎','宋','宋诗','song-poetry','','[]','滿山殘雪滿溪雲，唯有沙鷗獨見親。',64,'全唐诗/poet.song.221000.json','["滿山殘雪滿溪雲，唯有沙鷗獨見親。", "往事不堪頻入夢，吟篇無數更愁人。", "扁舟欲渡同誰載，破衲蒙頭近六旬。", "尚擬來生因可結，凄凉何處問蒼旻。"]'),
('c5b522d2-2ac4-4a08-9f4b-caca73fede27','閑居言懷','薛嵎','宋','宋诗','song-poetry','','[]','老子從來不爲名，放教心地到和平。',64,'全唐诗/poet.song.221000.json','["老子從來不爲名，放教心地到和平。", "庭前草色知春近，窗外梅花終夜明。", "紙帳夢回移月影，石溪流斷失灘聲。", "吟邊莫問紅塵事，只住茅茨亦自清。"]'),
('8290ab2e-05a4-42c8-b5c1-da956c7f2d1b','柴門','薛嵎','宋','宋诗','song-poetry','','[]','春風隨處好，吟事又相催。',48,'全唐诗/poet.song.221000.json','["春風隨處好，吟事又相催。", "觸石雲飛去，呼童鶴誤來。", "杖藜無疾步，花地有香埃。", "不許車塵入，柴門只半開。"]'),
('cbae9eb8-ca0c-45bd-b8b5-d0b0b7b26701','獨宿山中  其一','薛嵎','宋','宋诗','song-poetry','','[]','澗水松風聲不斷，白雲飛上屋頭栖。',32,'全唐诗/poet.song.221000.json','["澗水松風聲不斷，白雲飛上屋頭栖。", "山中昨夜孤吟客，只把無眠便作題。"]'),
('7bd8b096-ae26-47ea-864b-e3ea99b93844','獨宿山中  其二','薛嵎','宋','宋诗','song-poetry','','[]','誅茅無地結庵遲，借得人家近翠微。',32,'全唐诗/poet.song.221000.json','["誅茅無地結庵遲，借得人家近翠微。", "何事樹禽驚不起，也應知我久忘機。"]'),
('511acc06-aac2-481e-bdd1-7acb35846894','漁家','薛嵎','宋','宋诗','song-poetry','','[]','生涯漁業在，屋漏旋增茅。',48,'全唐诗/poet.song.221000.json','["生涯漁業在，屋漏旋增茅。", "莫道直鈎拙，翻同稚子敲。", "夜燈切竹火，賓坐具山肴。", "中有白頭者，離騷手自抄。"]'),
('5bad770c-7e68-41b4-b1f5-e8d0458f2d45','題山中井泉','薛嵎','宋','宋诗','song-poetry','','[]','井口依山缺，更無沙礫渾。',48,'全唐诗/poet.song.221000.json','["井口依山缺，更無沙礫渾。", "相傳海眼出，久視石碑存。", "定案星辰位，不多穿鑿痕。", "旱年人盡汲，汲盡復源源。"]'),
('8579fc0b-4dad-49a0-9a0b-6939382c153e','鄭氏時齋','薛嵎','宋','宋诗','song-poetry','','[]','力學競分陰，俄驚歲月深。',48,'全唐诗/poet.song.221000.json','["力學競分陰，俄驚歲月深。", "豈爲科舉地，自遂讀書心。", "名教有餘樂，塵埃不可尋。", "肯同碌碌者，白首尚籯金。"]'),
('4a8b2ad8-5642-48b1-b662-92342cc3f633','松岡過許峰送葬','薛嵎','宋','宋诗','song-poetry','','[]','此行吟更苦，哭舅萬山深。',48,'全唐诗/poet.song.221000.json','["此行吟更苦，哭舅萬山深。", "處士花猶昔，何人詩在今。", "奉親無旅况，對佛動慈心。", "霜夜增寒思，半牀安紙衾。"]'),
('92721a6d-70f0-49b8-9986-9c3004e22c7b','挽陳運管安人孫氏','薛嵎','宋','宋诗','song-poetry','','[]','舅家如母在，慟哭淚沾襟。',48,'全唐诗/poet.song.221000.json','["舅家如母在，慟哭淚沾襟。", "平日經聲斷，茲晨佛力深。", "墓廬猶手構，梱則是夫箴。", "山上半慈竹，從知契夙心。"]'),
('dfaba9ae-bb6e-4494-a827-8793a45f84e1','君譽病愈相訪','薛嵎','宋','宋诗','song-poetry','','[]','有誰憐我老，賢弟獨知心。',48,'全唐诗/poet.song.221000.json','["有誰憐我老，賢弟獨知心。", "月夜空相憶，梅花都未吟。", "愁因失鶴致，貧爲買山深。", "連日勤過記，新篘得共斟。"]'),
('f694ca03-a283-4cb0-86e8-fa897bbe7903','還寓樂姪詩卷','薛嵎','宋','宋诗','song-poetry','','[]','吾詩吟未了，今爾亦工吟。',48,'全唐诗/poet.song.221000.json','["吾詩吟未了，今爾亦工吟。", "筆下心思苦，書中理趣深。", "青燈宜遠到，白日易西沈。", "多謝憐衰疾，連朝獨見臨。"]'),
('0c14e8c4-117b-4372-ba53-c796573e9aa5','園中','薛嵎','宋','宋诗','song-poetry','','[]','莫道趨時拙，書中樂未涯。',48,'全唐诗/poet.song.221000.json','["莫道趨時拙，書中樂未涯。", "荷鋤依樹歇，聯句笑人遲。", "仙去井猶在，年荒草不衰。", "近來筋力減，累失看花期。"]'),
('5de0b312-cb9c-47af-864e-02c029a49dbf','賈鹿岩','薛嵎','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','不是長江派，因何亦好吟。',48,'全唐诗/poet.song.221000.json','["不是長江派，因何亦好吟。", "從知世味淡，自覺野情深。", "科舉無名字，案頭唯古今。", "新銘爲讀盡，可惜老山林。"]'),
('1cd6fdbd-8106-41be-bd94-4d90268e99dd','山中遇雨','薛嵎','宋','宋诗','song-poetry','','[]','草荒泥磴滑，老病厭扶持。',48,'全唐诗/poet.song.221000.json','["草荒泥磴滑，老病厭扶持。", "雨逐雲先後，路隨山險夷。", "天寒禽自浴，屋漏榻頻移。", "吟事愁無緒，梅花意亦悲。"]'),
('ad090f66-5b4e-4b0a-9e47-942ba5901bd6','山居有感','薛嵎','宋','宋诗','song-poetry','','[]','無忮復無求，山林終自由。',48,'全唐诗/poet.song.221000.json','["無忮復無求，山林終自由。", "雪飛猶欠積，雲住欲相留。", "朋友疏因數，功名喜亦憂。", "休休亭記在，此是死前休。"]'),
('de6f484d-e98e-42d0-9940-267bb158b8e8','湖外泛雪','薛嵎','宋','宋诗','song-poetry','','[]','雨雪連朝意未休，支筇難步最高樓。',64,'全唐诗/poet.song.221000.json','["雨雪連朝意未休，支筇難步最高樓。", "梅花不識春風面，野水相平古渡頭。", "船上看山無屋礙，塵中閲世似漚浮。", "一生窮苦緣詩僻，莫把詩窮認作愁。"]'),
('d4d0a46c-a495-4a5b-9a42-970514ec125c','病中感興','薛嵎','宋','宋诗','song-poetry','','[]','風霜歲又除，藜杖步徐徐。',48,'全唐诗/poet.song.221000.json','["風霜歲又除，藜杖步徐徐。", "兒輩憂無藥，牀頭喜有書。", "背因曝日暖，交爲訴貧疎。", "天定由人事，不如深閉廬。"]'),
('61b35e90-bb24-4ab7-b9c7-bbe1137cf154','憶嵇師奧觀梅并貴行弟歿後之思','薛嵎','宋','宋诗','song-poetry','','[]','不到嵇師今幾春，凄凉疋馬去無因。',32,'全唐诗/poet.song.221000.json','["不到嵇師今幾春，凄凉疋馬去無因。", "同遊人葬梅花下，應笑花開不見人。"]'),
('c2caa636-64ce-40b9-9ad7-aadfc4a66cf6','守歲五首  其一','薛嵎','宋','宋诗','song-poetry','','[]','兒輩呼盧不計錢，地爐圍坐笑聲喧。',32,'全唐诗/poet.song.221000.json','["兒輩呼盧不計錢，地爐圍坐笑聲喧。", "老夫自筭吟邊事，栽竹移花近百篇。"]'),
('7d2a673a-3b4f-4deb-af8b-16d0e75a0139','守歲五首  其二','薛嵎','宋','宋诗','song-poetry','','[]','明日焚香叩九關，六旬修未到清閑。',32,'全唐诗/poet.song.221000.json','["明日焚香叩九關，六旬修未到清閑。", "莫憐身在塵中老，雪後騎馿亦看山。"]'),
('41317c74-8979-4b65-883c-b7e88038577b','守歲五首  其三','薛嵎','宋','宋诗','song-poetry','','[]','鶴雛添歲頂微紅，想見瀛洲路亦通。',32,'全唐诗/poet.song.221000.json','["鶴雛添歲頂微紅，想見瀛洲路亦通。", "昨夜柴門長半掩，三更敲盡叫歸籠。"]'),
('34f4bdf9-8e51-4650-ba43-7ac842574ac1','守歲五首  其四','薛嵎','宋','宋诗','song-poetry','','[]','新歲纔餘七日糧，燈前猶自笑人忙。',32,'全唐诗/poet.song.221000.json','["新歲纔餘七日糧，燈前猶自笑人忙。", "茅簷霜下寒衣薄，爇盡蒹葭夜更長。"]'),
('b040313b-5a47-42da-9576-d53759ad67f5','守歲五首  其五','薛嵎','宋','宋诗','song-poetry','','[]','平日過從乏貴遊，更來湖上棹扁舟。',32,'全唐诗/poet.song.221000.json','["平日過從乏貴遊，更來湖上棹扁舟。", "除將兒女年年拜，鄰舍相逢坐即休。"]'),
('56e35ab9-2950-47bf-8db0-3877494b9251','山雲惠二物 梅枝','薛嵎','宋','宋诗','song-poetry','','[]','贈我江南一朶春，獨清滋味自相親。',32,'全唐诗/poet.song.221000.json','["贈我江南一朶春，獨清滋味自相親。", "只愁月下推敲拙，難與梅花作主人。"]'),
('b706d3af-42a2-43ba-884b-4b0dd8e91ffa','山雲惠二物 畫竹','薛嵎','宋','宋诗','song-poetry','','[]','跬步園林種亦難，渭川還有幾千竿。',32,'全唐诗/poet.song.221000.json','["跬步園林種亦難，渭川還有幾千竿。", "山雲遺我冰綃軸，得與梅花相對看。"]'),
('af2383dd-eecd-41d0-8742-9fe7cb7e7e74','漁村有感','薛嵎','宋','宋诗','song-poetry','','[]','小窗長日苦吟聲，獨倚闌干看晚晴。',64,'全唐诗/poet.song.221000.json','["小窗長日苦吟聲，獨倚闌干看晚晴。", "居士莫疑貧可棄，春風不爲病相輕。", "梅邊紙帳重重影，壁上離騷字字清。", "鷗鷺往來情更熟，只消此地度殘生。"]'),
('ecb7540b-2f0a-4b63-8b60-7f15e83f827f','吳樵溪山居','柴望','宋','宋诗','song-poetry','','[]','老子無家計，蕭然屋數間。',48,'全唐诗/poet.song.221000.json','["老子無家計，蕭然屋數間。", "頭邊惟白髮，眼底是青山。", "棋急鳥聲散，琴低鶴睡閒。", "片雲長似伴，朝去暮飛還。"]'),
('eb348710-66b8-43f2-84be-b9406a4dc74b','金臺泊舟','柴望','宋','宋诗','song-poetry','','[]','欲謀歸去計，歸去更匆匆。',48,'全唐诗/poet.song.221000.json','["欲謀歸去計，歸去更匆匆。", "王化何時北，江流日夜東。", "片帆山共水，竟夕雨和風。", "時事只如此，相催成老翁。"]'),
('f7b1edc4-d5b0-445f-a12f-212171fecb3a','宿湖外','柴望','宋','宋诗','song-poetry','','[]','懶入城中去，來維柳下舟。',48,'全唐诗/poet.song.221000.json','["懶入城中去，來維柳下舟。", "空江明月上，殘雨夕陽收。", "好景多歸夜，他鄉易得秋。", "倚梧吟不盡，樽酒更登樓。"]'),
('25ea09e2-9a0a-42e7-bf97-45cd09bfb1fc','山居','柴望','宋','宋诗','song-poetry','','[]','老來無一事，僮與鶴相隨。',48,'全唐诗/poet.song.221000.json','["老來無一事，僮與鶴相隨。", "繞屋疎疎竹，編牆短短籬。", "起來花換影，知已睡多時。", "莫厭山居寂，山人祇自宜。"]'),
('7667e9ac-f945-4d76-8d74-ac54aa133855','詔許出獄呈京尹節齋趙公','柴望','宋','宋诗','song-poetry','','[]','臣子狂愚獻直言，聖明寬大度如天。',64,'全唐诗/poet.song.221000.json','["臣子狂愚獻直言，聖明寬大度如天。", "十封應詔皆焚藁，一片憂時祇似弦。", "數象逢丁陽九厄，元龜爲鑑後千年。", "今朝有旨從天下，不到長沙到席前。"]'),
('266a12a3-a428-4d04-a21a-ce6de16ca06f','靈芝寺別祖席諸友','柴望','宋','宋诗','song-poetry','','[]','落日寒城暮雨餘，滿斟離酒意何如。',64,'全唐诗/poet.song.221000.json','["落日寒城暮雨餘，滿斟離酒意何如。", "見妻還指張儀舌，痛國誰憐賈誼書。", "羸馬病僮旋僱倩，寺禽山獠亦欷歔。", "長安可是深居處，更向深山深處居。"]'),
('c1f2f657-efa2-478c-a33f-396a1fdf0c10','富陽道中','柴望','宋','宋诗','song-poetry','','[]','幾年只向長安去，今日囊書被旨回。',64,'全唐诗/poet.song.221000.json','["幾年只向長安去，今日囊書被旨回。", "馬首獨行秋葉路，鱸魚時共菊花杯。", "黄昏鐘動雁初下，夜半月明潮正來。", "我自不歸歸便得，故園早晚早梅開。"]'),
('758c1d6b-a890-49d2-9db2-b9232876b930','和周居易見寄韻','柴望','宋','宋诗','song-poetry','','[]','十年爲客上長安，人指冰山不會寒。',64,'全唐诗/poet.song.221000.json','["十年爲客上長安，人指冰山不會寒。", "開口盡言投老易，到頭只是挂冠難。", "低棲屋宇居常穩，巧小園池坐儘寬。", "別有前溪魚可釣，也須栽竹傍欄干。"]'),
('ec9a1aab-6e54-4558-8d06-1592ac152343','錢唐','柴望','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不記錢王建國年，尚遺强弩射潮痕。',64,'全唐诗/poet.song.221000.json','["不記錢王建國年，尚遺强弩射潮痕。", "地迴王氣歸吳分，山挾潮聲出海門。", "南渡幾年猶昨日，西湖疎影自黄昏。", "客來獨憑欄干處，時聽漁歌過遠村。"]'),
('fc18bdc8-637c-4f7a-9676-a87d9e185374','越王勾踐墓','柴望','宋','宋诗','song-poetry','','[]','秦望山頭自夕陽，傷心誰復賦凄凉。',64,'全唐诗/poet.song.221000.json','["秦望山頭自夕陽，傷心誰復賦凄凉。", "今人不見亡吳事，故墓猶傳霸越鄉。", "雨打亂花迷複道，鳥翻黄葉下宮牆。", "登臨莫向高臺望，烟樹中原正渺茫。"]'),
('020b48ee-1b02-4e08-8eab-1bd10e7a758d','送馬太初之越','柴望','宋','宋诗','song-poetry','','[]','一去山陰一冉溪，如何還只恁分携。',64,'全唐诗/poet.song.221000.json','["一去山陰一冉溪，如何還只恁分携。", "雨無聊頼人無寐，水又潺湲鳥又啼。", "明日不知君上馬，中宵誰與共聞雞。", "去時應有蘭亭句，爲我臨池援筆題。"]'),
('488dd069-da86-4354-aaca-0caf8e776e82','戒珠寺右軍宅','柴望','宋','宋诗','song-poetry','','[]','蒼樹寒烟兩渺茫，後來誰此弔興亡。',64,'全唐诗/poet.song.221000.json','["蒼樹寒烟兩渺茫，後來誰此弔興亡。", "晉朝風物今流水，蕭寺鐘聲幾夕陽。", "話燕梁空春雨急，愛鵝人去暮山長。", "學書弟子知何在，風過池塘墨尚香。"]'),
('f4253dc6-19fa-4f87-b6ed-4cdab453f821','和王景陽越中寄別韻','柴望','宋','宋诗','song-poetry','','[]','故人書只問平安，已分還山豈願官。',64,'全唐诗/poet.song.221000.json','["故人書只問平安，已分還山豈願官。", "猿鶴不驚松逕夢，貂蟬難換竹皮冠。", "長安落葉秋深見，故國斜陽雨後看。", "莫道剡中吟不盡，不成吟處亦停鞍。"]'),
('124355b8-9494-4897-8fc4-7f4cfbcf1247','金山寺','柴望','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','荻花蘆葉正珊珊，山在長江寺在山。',64,'全唐诗/poet.song.221000.json','["荻花蘆葉正珊珊，山在長江寺在山。", "門逕但從船出入，僧房多住水中間。", "江空落日斜猶照，夜半秋潮去復還。", "吟興未闌天欲曙，一行斜雁起蒼灣。"]'),
('db8004c2-1fc5-4c80-8668-3a134d38c3ca','鳳皇臺','柴望','宋','宋诗','song-poetry','','[]','灑盡梧桐酒一杯，興亡前事獨徘徊。',64,'全唐诗/poet.song.221000.json','["灑盡梧桐酒一杯，興亡前事獨徘徊。", "烏衣冉冉斜陽下，白鷺茫茫江水來。", "鳳去不知經幾載，客來惟只見高臺。", "閒於登眺成孤嘯，五百年間王氣回。"]'),
('8d8b1540-413f-47ee-8677-7ada1337ac5c','石頭城和王寧翁韻','柴望','宋','宋诗','song-poetry','','[]','懷鄉弔古易傷心，絕頂危亭共客臨。',64,'全唐诗/poet.song.221000.json','["懷鄉弔古易傷心，絕頂危亭共客臨。", "朝市曾經兵火後，山川轉覺樹雲深。", "百年歌舞空臺沼，六代豪華漫陸沉。", "惟有亂鴉歸去晚，夕陽無限暮城陰。"]'),
('c2fa533b-5ccb-45da-95e1-ac1e975f125c','多景樓','柴望','宋','宋诗','song-poetry','','[]','早被垂楊繫去舟，五更潮落大江頭。',64,'全唐诗/poet.song.221000.json','["早被垂楊繫去舟，五更潮落大江頭。", "關河北望幾千里，淮海南來第一樓。", "昔日最多風景處，今人偏動黍離愁。", "烟沙澒洞翻蘋末，欲倚西風問仲謀。"]'),
('bfa19c09-b0be-475d-b896-678cc77df06c','山陰蘭亭','柴望','宋','宋诗','song-poetry','','[]','寂寂山陰事已塵，至今亭址尚嶙峋。',64,'全唐诗/poet.song.221000.json','["寂寂山陰事已塵，至今亭址尚嶙峋。", "落花時節朝朝雨，插柳人家處處春。", "曲水自流寒食酒，茂林無復永和人。", "昭陵繭紙今何在，空有梅花點翠珉。"]'),
('68079d0b-b644-4bdd-a4c1-15e5dae047e8','別故人','柴望','宋','宋诗','song-poetry','','[]','便未成名也自歸，不應猿鶴更猜疑。',64,'全唐诗/poet.song.221000.json','["便未成名也自歸，不應猿鶴更猜疑。", "冷看世事頻移局，懶與仙人共弈棋。", "南渡只今惟有酒，西興臨別是誰詩。", "行藏正要知時節，却是時人未得知。"]'),
('2b54a9aa-1881-4f0f-b964-f188b7ae5921','送葉若磯之金陵謁信菴','柴望','宋','宋诗','song-poetry','','[]','一片斜陽落渡頭，青衫烏帽獨登樓。',64,'全唐诗/poet.song.221000.json','["一片斜陽落渡頭，青衫烏帽獨登樓。", "江流建業三千里，山色淮南數百州。", "都督正開羊祜府，誰人得上李膺舟。", "此行不爲揚州鶴，一字猶堪萬戶侯。"]'),
('c023ec8b-3414-40c5-ace4-99aa3bd26842','呈中書權直程滄洲','柴望','宋','宋诗','song-poetry','','[]','玉旨傳宣夜直扉，制麻侵曉進呈歸。',64,'全唐诗/poet.song.221000.json','["玉旨傳宣夜直扉，制麻侵曉進呈歸。", "三槐龍影連青瑣，千柳鶑聲度紫薇。", "袖惹爐香飄霧靄，硯傳盤露映旌旗。", "承恩更賜金蓮炬，猶勝清光太乙藜。"]'),
('32398785-c6ed-43ad-8094-bd9e7837b1e3','富春嚴子陵祠','柴望','宋','宋诗','song-poetry','','[]','桑田何處海漫漫，耕壟傳聞建武間。',64,'全唐诗/poet.song.221000.json','["桑田何處海漫漫，耕壟傳聞建武間。", "真主不緣符白水，先生安可飯青山。", "至今衰草遺寒燒，此日秋江起暮鷳。", "萬里崎嶇祠下路，不知行役幾人閒。"]'),
('b8055bb6-29cb-4bfc-8c2a-9ff69a985bcd','歸來','柴望','宋','宋诗','song-poetry','','[]','歸計年來付酒杯，任他猿鶴自相猜。',64,'全唐诗/poet.song.221000.json','["歸計年來付酒杯，任他猿鶴自相猜。", "東家種竹西鄰看，前日移花昨夜開。", "鐘送夕陽歸草木，風吹凉月上樓臺。", "老來嬾聽他家曲，惟看柴門長綠苔。"]'),
('0949a9ad-fe41-40e7-b68c-a1c7be113475','越山','柴望','宋','宋诗','song-poetry','','[]','吳越山分兩岸青，遥遥帆影是西興。',64,'全唐诗/poet.song.221000.json','["吳越山分兩岸青，遥遥帆影是西興。", "江花歷亂如紅雨，雲樹高低似畫屏。", "錢氏古鄉迷鳥道，越王芳草上諸陵。", "已知太乙臨吳分，曉看祥烏夜看星。"]'),
('b8c05388-ae02-4ae7-be39-00f0664afb88','寄徐編校','柴望','宋','宋诗','song-poetry','','[]','近傳丹詔下彤墀，夜鶴寒猿也自疑。',64,'全唐诗/poet.song.221000.json','["近傳丹詔下彤墀，夜鶴寒猿也自疑。", "江上晚風終自急，山中白石最相宜。", "潮生潮滅鷗先見，花落花開蝶未知。", "懷玉山人如問我，爛柯山下看圍棋。"]'),
('bef5f5c0-0ebf-44ae-9d35-be1a0c86e4a0','重到都門傚轆轤體','柴望','宋','宋诗','song-poetry','','[]','兩年不作京華夢，重到湖山事已非。',64,'全唐诗/poet.song.221000.json','["兩年不作京華夢，重到湖山事已非。", "柳外晚風寒食節，花間天氣雨晴時。", "闌干獨憑鶑飛去，簾幙低垂燕未歸。", "欲託焦桐理心事，滿庭芳草又斜暉。"]'),
('920f8535-4dad-4e3f-a2ce-7111f7dcaa83','金陵秋賦別江壽翁','柴望','宋','宋诗','song-poetry','','[]','憶向西風折翅歸，每忻黄菊滿疎籬。',64,'全唐诗/poet.song.221000.json','["憶向西風折翅歸，每忻黄菊滿疎籬。", "十書詣闕無知己，千里離家有路歧。", "歲月易驚孤客夢，文章難比少年時。", "荻花蘆葉休凄怨，自有新開竇桂枝。"]'),
('055ccfba-9c16-4898-8a49-9544ee146621','奇氣樓','柴望','宋','宋诗','song-poetry','','[]','此齋全占崧高勝，更盡樓前第一奇。',64,'全唐诗/poet.song.221000.json','["此齋全占崧高勝，更盡樓前第一奇。", "芳草碧連天水處，數峰青斷暮烟時。", "山川不逐陰晴換，宇宙閒看歲月移。", "琴已嬾彈書嬾讀，一簾花影詠春遲。"]'),
('239c8347-0752-400e-ba7a-1567ecef8948','高齋晚望','柴望','宋','宋诗','song-poetry','','[]','纔是青山便卜鄰，世情那得較紛紜。',64,'全唐诗/poet.song.221000.json','["纔是青山便卜鄰，世情那得較紛紜。", "露含遠岫分爲雨，烟起人家去作雲。", "柳色晴光扶檻入，鶑聲人語隔窗聞。", "高齋獨捲重簾坐，花落棋床日未曛。"]'),
('169cab63-cf90-4670-be81-4fb4d26582d1','西湖','柴望','宋','宋诗','song-poetry','','["\u897f\u6e56"]','年年柳眼青歸處，門外遊人可自閒。',64,'全唐诗/poet.song.221000.json','["年年柳眼青歸處，門外遊人可自閒。", "天氣又晴晴又雨，樓臺依寺寺依山。", "酒邊歌拍穿花外，船上簫聲落水間。", "光景留連空自惜，鷓鴣啼罷暮城關。"]'),
('d6d3a0e1-02ab-4efa-84d0-e274df9f2d65','客中夜雨','柴望','宋','宋诗','song-poetry','','[]','離情先怯向邊州，寒葉敲窗更報秋。',64,'全唐诗/poet.song.221000.json','["離情先怯向邊州，寒葉敲窗更報秋。", "幾點攪殘千里夢，一聲滴作兩鄉愁。", "苦緣楊柳沾離席，偏傍梧桐濺小樓。", "惟有孤燈照明滅，夜深無語攬重裘。"]'),
('13305df7-86e8-408e-860c-cf08587f5efc','江心寺','柴望','宋','宋诗','song-poetry','','[]','寺比金焦徹夜開，一山恰似小蓬萊。',64,'全唐诗/poet.song.221000.json','["寺比金焦徹夜開，一山恰似小蓬萊。", "塔分兩岸波中影，潮長三門石上苔。", "遺老爲言前日事，上皇曾渡此江來。", "中流滾滾英雄恨，輸與高僧入定回。"]'),
('b3c35bcf-424f-4b05-9ccf-5d606163f105','重題黄鶴樓','柴望','宋','宋诗','song-poetry','','[]','自從崔顥題詩後，更有何人弔禰衡。',64,'全唐诗/poet.song.221000.json','["自從崔顥題詩後，更有何人弔禰衡。", "芳草不知鸚鵡恨，晴天惟見漢陽城。", "樓頭月落酒方醒，岸口風高雁正鳴。", "五百年前黄鶴去，閒尋鷗鷺訂詩盟。"]'),
('196dbf0b-32fa-404a-9947-879e2341f9c9','送朱南山開蜀閫','柴望','宋','宋诗','song-poetry','','[]','殿上傳宣內引官，一封歷歷奏忠肝。',64,'全唐诗/poet.song.221000.json','["殿上傳宣內引官，一封歷歷奏忠肝。", "八千里路先聲至，百萬都人夾道觀。", "節度晉公先授鉞，淮陰韓信舊登壇。", "擎天正要中流柱，莫擬人間蜀道難。"]'),
('d8b61f19-1053-4ab5-9e41-e9a7e40bef29','別永嘉使君趙致軒','柴望','宋','宋诗','song-poetry','','[]','一番出處計何如，流泊中川不爲漁。',64,'全唐诗/poet.song.221000.json','["一番出處計何如，流泊中川不爲漁。", "落日凄凉秋老矣，西風浩蕩客歸歟。", "吟成白髮逢知己，費盡黄金買古書。", "明發灞橋橋上路，藉君帆力更吹噓。"]'),
('61e9f0e0-8e5b-43e7-95a4-5e6610cdb831','蘄州別友','柴望','宋','宋诗','song-poetry','','[]','客中逢客上夷陵，輾轉凄凉睡不成。',64,'全唐诗/poet.song.221000.json','["客中逢客上夷陵，輾轉凄凉睡不成。", "無酒送君之遠道，有誰吹角向江城。", "白髮亂生人漸老，青燈相對雨無情。", "詰朝共發蘄州路，知到江山更幾程。"]'),
('75dfb7ed-5cdd-4fb4-aea6-437266573f80','送監丞弟元亨參江陵閫','柴望','宋','宋诗','song-poetry','','[]','北虜纔聞郭子儀，上流决有退師期。',64,'全唐诗/poet.song.221000.json','["北虜纔聞郭子儀，上流决有退師期。", "諸公但釃臨江酒，老子祇圍別墅棋。", "露布夜傳誅韃靼，蠟丸便遞破符離。", "書生已辦平淮表，先寄鶺鴒原上詩。"]'),
('8c9d9256-e804-4752-8a0b-3e26b5723cd7','即事','柴望','宋','宋诗','song-poetry','','[]','澒洞風塵莽未明，天翻地覆劫將盈。',64,'全唐诗/poet.song.221000.json','["澒洞風塵莽未明，天翻地覆劫將盈。", "翠華海上知何似，白首山中空自驚。", "哭向鶑花非世界，夢迷弓劍繞皇陵。", "誰知薇蕨同盃酒，爲酹興亡終古靈。"]'),
('69203ea6-dc65-4812-815c-9028c7c2e887','和通判弟隨亨書感韻','柴望','宋','宋诗','song-poetry','','[]','風沙萬里夢堪驚，地老天荒只此情。',64,'全唐诗/poet.song.221000.json','["風沙萬里夢堪驚，地老天荒只此情。", "世上但知王蠋義，人間惟有伯夷清。", "堂前歸燕春何處，花外啼鵑月幾更。", "莫話凄凉當日事，劍歌泪盡血霑纓。"]'),
('e4f7dba6-2cf5-43bd-a059-ad7093ad4da8','中秋待月用弟察推元彪韻','柴望','宋','宋诗','song-poetry','','[]','待月南樓月不明，百年虛負此宵情。',64,'全唐诗/poet.song.221000.json','["待月南樓月不明，百年虛負此宵情。", "浮陰亂向空中起，圓影偏從塞外清。", "江國瀟瀟凄露氣，山城處處動笳聲。", "何人獨抱琵琶坐，淚滴冰絃暗恨生。"]'),
('49685f82-3092-458c-8b4b-df3a53542bbb','夢傅說','柴望','宋','宋诗','song-poetry','','[]','傅說爲霖寤寐中，高宗一念與天通。',32,'全唐诗/poet.song.221000.json','["傅說爲霖寤寐中，高宗一念與天通。", "後來亦有君王夢，不是陽臺便月宮。"]'),
('346d41bb-2b66-4130-83bb-4fb73b5c3fb5','西施','柴望','宋','宋诗','song-poetry','','[]','十二金釵對對鋪，三千粉黛膩如酥。',32,'全唐诗/poet.song.221000.json','["十二金釵對對鋪，三千粉黛膩如酥。", "君王莫道六宮醜，一箇西施已壞吳。"]'),
('defd8810-ce96-410e-96a5-bf6d1dfbe68c','范蠡','柴望','宋','宋诗','song-poetry','','[]','五月菰蒲八月秋，年年清酒酹江頭。',32,'全唐诗/poet.song.221000.json','["五月菰蒲八月秋，年年清酒酹江頭。", "伍胥忿怒三閭怨，爭似鴟夷一釣舟。"]'),
('151cf139-c8f4-4887-807a-00758dfcfad0','長城','柴望','宋','宋诗','song-poetry','','[]','漠漠沙場萬里遥，千夫一日起臨洮。',32,'全唐诗/poet.song.221000.json','["漠漠沙場萬里遥，千夫一日起臨洮。", "若無道德爲干櫓，更是秦人築欠高。"]'),
('5d94dfb1-6b76-4003-89d7-9476b53377fc','沛中歌','柴望','宋','宋诗','song-poetry','','[]','秦時日月漢山河，家計今誰與仲多。',32,'全唐诗/poet.song.221000.json','["秦時日月漢山河，家計今誰與仲多。", "天子不知天下貴，酒中惟唱沛中歌。"]'),
('26c6abb8-1122-4bf1-b8de-6b74e8e21240','雲夢','柴望','宋','宋诗','song-poetry','','[]','紀生尚可稱皇帝，韓信何妨作假王。',32,'全唐诗/poet.song.221000.json','["紀生尚可稱皇帝，韓信何妨作假王。", "今日僞遊真是僞，只因一躡誤高皇。"]'),
('7959d63b-bdc5-4267-a4bc-f4b255a94549','長生','柴望','宋','宋诗','song-poetry','','[]','武皇何事駕虛空，金闕求仙路未通。',32,'全唐诗/poet.song.221000.json','["武皇何事駕虛空，金闕求仙路未通。", "王母不來方士去，茂陵可是廣寒宮。"]'),
('7207961d-a4ad-48ea-935b-e286a1b9483e','蘇武','柴望','宋','宋诗','song-poetry','','[]','十九年間不辱君，論功何獨後諸臣。',32,'全唐诗/poet.song.221000.json','["十九年間不辱君，論功何獨後諸臣。", "若教倒數凌烟像，也是當時第一人。"]'),
('82b5cf09-a1ad-4360-a8cd-7a1d5e252dbe','子陵臺','柴望','宋','宋诗','song-poetry','','[]','曾與劉郎共起居，如何不肯受除書。',32,'全唐诗/poet.song.221000.json','["曾與劉郎共起居，如何不肯受除書。", "最憐人笑先生錯，正好爲官却釣魚。"]'),
('1fd158c0-7a94-46c1-a3a1-30e07c9d68b0','昭陽殿','柴望','宋','宋诗','song-poetry','','[]','禍水流來漢火亡，白頭宮女恨昭陽。',32,'全唐诗/poet.song.221000.json','["禍水流來漢火亡，白頭宮女恨昭陽。", "至今人見飛來燕，猶爲君王暗斷腸。"]'),
('347805b7-76c2-4e9e-b5c1-fa0a2a8e3a1e','淝水','柴望','宋','宋诗','song-poetry','','[]','想見西風對壘時，目中先已料安危。',32,'全唐诗/poet.song.221000.json','["想見西風對壘時，目中先已料安危。", "淮淝百萬兵雖衆，未抵東山一局棋。"]'),
('840213d4-9c99-4ec6-905c-13df9d953ec9','除夕對梅','柴望','宋','宋诗','song-poetry','','[]','青春無復駐年華，幾度江梅暗憶家。',32,'全唐诗/poet.song.221000.json','["青春無復駐年華，幾度江梅暗憶家。", "惆悵新愁添白髮，鬢邊如雪映寒花。"]'),
('b3669b2b-17c7-4141-b979-71b95489937c','上忠齋丞相  其一','柴望','宋','宋诗','song-poetry','','[]','世事篙人一葉舟，長歌短棹發中流。',32,'全唐诗/poet.song.221000.json','["世事篙人一葉舟，長歌短棹發中流。", "今朝正得東風便，纔是西風便轉頭。"]'),
('e78567f1-9a4b-4d63-99a1-3d27b8fdc9b7','上忠齋丞相  其二','柴望','宋','宋诗','song-poetry','','[]','爛柯山下採樵民，盡日觀棋局局新。',32,'全唐诗/poet.song.221000.json','["爛柯山下採樵民，盡日觀棋局局新。", "黑白兩般都著過，後來一著要高人。"]'),
('8a6644b9-9356-484f-9395-9bb52a292a9a','上忠齋丞相  其三','柴望','宋','宋诗','song-poetry','','[]','江南江北路迢迢，往事東風恨未消。',32,'全唐诗/poet.song.221000.json','["江南江北路迢迢，往事東風恨未消。", "昨夜杜鵑啼不了，始知春在洛陽橋。"]'),
('6807dcbe-070a-4c34-ac63-1ee1d05632f6','上忠齋丞相  其四','柴望','宋','宋诗','song-poetry','','[]','九陌紅塵撲帽紗，囊書幾度進官家。',32,'全唐诗/poet.song.221000.json','["九陌紅塵撲帽紗，囊書幾度進官家。", "近來不甚知時事，只是栽桑不種花。"]'),
('3b523014-ff52-4039-86dc-2ba38acffc54','塞下行贈韋士穎歸鄂渚上江陵謁閫相','柴望','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長安二月春正濃，長江二月風正急。',392,'全唐诗/poet.song.221000.json','["長安二月春正濃，長江二月風正急。", "城頭楊柳雪絮飛，道傍黏雨沱潦濕。", "邯鄲誰家俠少年，上馬意氣揮金鞭，下馬掃筆大如椽。", "興來一石未能醉，劇飲數斗口流涎。", "玉山跌倒扶未起，金鞭留當酒家裏。", "隔樓彷彿畫眉人，相邀夜宿鴛鴦被。", "睡魔不醒五更鐘，笛聲吹斷相思淚。", "嘐嘐鳴雞將度關，欲去未去踟躕間。", "道逢項莊把劍舞，樓上美人歌玉環。", "劃然掣電蛟龍怒，便指南樓問歸路。", "二千三百里更長，爾備衣糧我屝屨。", "青衫著破不堪典，典到青衫共誰語。", "世上豈無虬髯漢，散財結客千千萬。", "豈無燕昭萬黄金，築作高臺禮瓌彥。", "秦坑漢駡不肯收，自是一番遭薄賤。", "唐人科舉更糊名，天下英雄消沮盡。", "生兒不學去封侯，錐毛弄禿成霜鬢。", "世無荆軻樊於期，只今誰復是男兒。", "我聞兵凶戰危事，愁殺天上蚩尤旗。", "人心承平易思亂，中原塊土急驅漢。", "蔡城未下闢未誅，機來一髮不容間。", "三邊未即妖祲清，天河何時能洗兵。", "送君不作斷腸客，三尺一騎君西征。", "臨岐酌酒再三語，今日君王自神武。"]'),
('2f3762f8-4381-48a7-ab3e-e31ef46abd1b','白雲莊四首 掬泉軒','柴望','宋','宋诗','song-poetry','','[]','好山深處靜開軒，目送孤雲手弄泉。',64,'全唐诗/poet.song.221000.json','["好山深處靜開軒，目送孤雲手弄泉。", "枕石堂無金玉富，濯纓家有子孫賢。", "初尋舊隠逢三伏，已發新吟僅百篇。", "聞說夜分煩暑散，凉飈渾似素秋天。"]'),
('845d2a70-fc32-4af3-8487-2c4516f02740','白雲莊四首 平溪堂','柴望','宋','宋诗','song-poetry','','[]','亭號休休古退藏，豈如溪上搆虛堂。',64,'全唐诗/poet.song.221000.json','["亭號休休古退藏，豈如溪上搆虛堂。", "坐邀城市真瀟灑，却謂江湖太渺茫。", "下筆新題無俗事，携筇野服是家常。", "臨流最有清風快，未見古人心已凉。"]'),
('094e4420-5d08-49b5-acbe-241456da5a0d','白雲莊四首 晚望臺','柴望','宋','宋诗','song-poetry','','[]','治圃我依浮石灘，築臺君占白雲山。',64,'全唐诗/poet.song.221000.json','["治圃我依浮石灘，築臺君占白雲山。", "三秋一日登臨外，百里同風咫尺間。", "峯黛陰晴常黯黯，溜琴朝夕自潺潺。", "休官誰道何曾見，林下如今兩處閒。"]'),
('0d915c28-27f0-43e5-9dc4-fa02627e8f0f','白雲莊四首 嬾歸閣','柴望','宋','宋诗','song-poetry','','[]','溪流回合逗方池，軒檻前臨面翠微。',64,'全唐诗/poet.song.221000.json','["溪流回合逗方池，軒檻前臨面翠微。", "紫陌紅塵行不顧，白雲青嶂坐忘歸。", "方榮即隠誰能繼，未老休官世所稀。", "我昔凌雲登閣會，主翁留飲見蟾暉。"]'),
('6567e761-f76c-4d2d-9ebd-6ace4e18218b','月夜溪莊訪舊','柴望','宋','宋诗','song-poetry','','[]','山山明月路，何處認梅花。',48,'全唐诗/poet.song.221000.json','["山山明月路，何處認梅花。", "石色冷如水，溪流白似沙。", "清吟幽客夢，華髮故人家。", "相見即歸去，已應河漢斜。"]'),
('40844f4c-c457-4ea1-b1ed-521b57de5e3a','客中九日','潘璵','宋','宋诗','song-poetry','','[]','破帽西風急，寒窗敗葉飛。',48,'全唐诗/poet.song.221000.json','["破帽西風急，寒窗敗葉飛。", "重陽今日是，三徑幾時歸。", "簷上多黄菊，門前少白衣。", "吟情淡如水，一雁叫斜暉。"]'),
('ec9ac930-72d5-4b6c-b7f9-12ecca686fef','東吳府僉見山覓酒','潘璵','宋','宋诗','song-poetry','','[]','火龍走日爍炎天，久渴羈腸擬吸川。',32,'全唐诗/poet.song.221000.json','["火龍走日爍炎天，久渴羈腸擬吸川。", "見說藍橋風月好，願分清致到吟邊。"]'),
('0c052bfd-73fb-4e71-aedc-34c57c76ea36','憶舍弟','潘璵','宋','宋诗','song-poetry','','[]','汝向下邳去，吾猶上國居。',48,'全唐诗/poet.song.221000.json','["汝向下邳去，吾猶上國居。", "幾番曾入夢，十月不收書。", "血滿干戈地，塵飛盜賊墟。", "無人問消息，生死竟何如。"]'),
('83765bed-782e-4784-a705-3a6aae052fc8','贈道士王玉壺','潘璵','宋','宋诗','song-poetry','','[]','屨不染凡塵，雲深竹屋春。',48,'全唐诗/poet.song.221000.json','["屨不染凡塵，雲深竹屋春。", "安心能學道，屋指別無人。", "丹熟玄機透，琴清古樂真。", "前緣君悟否，老子是龍身。"]'),
('10c17df3-2ac5-453a-8b0a-1fdf05594dac','贈白雲道人','潘璵','宋','宋诗','song-poetry','','[]','白雲堆裏縛茅廬，活計無多樂有餘。',64,'全唐诗/poet.song.221000.json','["白雲堆裏縛茅廬，活計無多樂有餘。", "午竈旋添燒藥火，夜檠頻勘養生書。", "門無過客常籠鶴，園鑿新池學釣魚。", "身遠利名心似水，夢閑時復到華胥。"]'),
('beb5f14c-1791-460a-b407-25a6e67540c3','寄翁石龜','潘璵','宋','宋诗','song-poetry','','[]','慣呼風月入毫端，人作神仙以上看。',64,'全唐诗/poet.song.221000.json','["慣呼風月入毫端，人作神仙以上看。", "天賦此清梅亦遜，地因所寓稿隨刊。", "符分半刺于今易，詩得全名自古難。", "洗去淫哇追大雅，能於文海障狂瀾。"]'),
('19cf513b-df66-4556-9c89-39cd0d190a23','寄適園朱表兄','潘璵','宋','宋诗','song-poetry','','[]','適園分袂後，又復半年餘。',48,'全唐诗/poet.song.221000.json','["適園分袂後，又復半年餘。", "笑我多行役，無書話起居。", "溪山雖地隔，兄弟可情疎。", "辦得歸耕計，相依結小廬。"]'),
('4b91bcdf-c5cf-4067-b469-e49a41c44458','酬朱適園訪見詩','潘璵','宋','宋诗','song-poetry','','[]','曾同山友過江湄，何處清游晚未歸。',64,'全唐诗/poet.song.221000.json','["曾同山友過江湄，何處清游晚未歸。", "沽酒□羊來好語，開籠放鶴在何時。", "雲方卷葉收春雨，柳未吹花點客衣。", "京洛相逢宜少駐，東風杖屨好追隨。"]'),
('cd37be6a-8ede-40b0-8dec-5117392b5a5d','薝蔔花','潘璵','宋','宋诗','song-poetry','','[]','未說司花刻玉工，人知名與佛相同。',32,'全唐诗/poet.song.221000.json','["未說司花刻玉工，人知名與佛相同。", "可憐結了黄金子，依舊身歸色界中。"]'),
('1d649c25-3a32-4553-b364-6a67d96b1683','梅花二首  其一','潘璵','宋','宋诗','song-poetry','','[]','雪中獨愛此花開，莫笑花飛委綠苔。',32,'全唐诗/poet.song.221000.json','["雪中獨愛此花開，莫笑花飛委綠苔。", "骨裏有香吹不散，明年依舊領春回。"]'),
('34b15f0a-262d-4576-8c2f-41c8884fd595','梅花二首  其二','潘璵','宋','宋诗','song-poetry','','[]','冰玉丰姿夐絕塵，山林誰伴歲寒盟。',64,'全唐诗/poet.song.221000.json','["冰玉丰姿夐絕塵，山林誰伴歲寒盟。", "臘前有雪曾相約，天下無花似此清。", "不待春風施造化，只嫌晚角說平生。", "月香水影吾家事，却被詩人掠美名。"]'),
('b2b03dd9-1a02-45c8-9aa0-defb6b0904de','湖舡分得行字韻','潘璵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三月鶑花爛熳春，尋芳誰不趁清明。',64,'全唐诗/poet.song.221000.json','["三月鶑花爛熳春，尋芳誰不趁清明。", "要爲終日看山計，只買扁舟載酒行。", "老柳半枯存古意，浮雲多變類人情。", "何時結屋西湖上，雨笠煙蓑寄此生。"]'),
('975a2a8d-0979-4d04-b9de-df6fd1fd55e7','枕上聞鍾','潘璵','宋','宋诗','song-poetry','','[]','酒醒殘月明，欹枕聽鍾聲。',48,'全唐诗/poet.song.221000.json','["酒醒殘月明，欹枕聽鍾聲。", "風露秋將晚，家山夢輒驚。", "客塵侵老鬢，官職借虛名。", "却羨僧無事，此心如水清。"]'),
('c1994bc9-6a0a-44b0-93ee-1fc2bd2ea907','聽彈歸去來辭','潘璵','宋','宋诗','song-poetry','','[]','淵明昔賦歸去辭，後世寄聲焦桐絲。',32,'全唐诗/poet.song.221000.json','["淵明昔賦歸去辭，後世寄聲焦桐絲。", "先生彈罷和者誰，春山花落啼子規。"]'),
('746c845d-6db9-48cb-915f-46721b4582f2','曹娥堰打船','潘璵','宋','宋诗','song-poetry','','[]','曹娥廟前路，平日幾經行。',48,'全唐诗/poet.song.221000.json','["曹娥廟前路，平日幾經行。", "浦淺舟難入，月斜潮始生。", "牛隨堰索轉，犬吠燎盆明。", "上得官河去，心安睡可成。"]'),
('a7100546-1608-442c-8777-9018d66fdd95','停鞍','潘璵','宋','宋诗','song-poetry','','[]','古驛晚停鞍，西風客帽寒。',48,'全唐诗/poet.song.221000.json','["古驛晚停鞍，西風客帽寒。", "山昏雲氣濕，秋老葉聲乾。", "昔爲作詩苦，今嗟行路難。", "鈴音邊報急，醉裏亦眉攢。"]'),
('a43e1bf4-3060-4f8b-864c-b8364265bf47','看劍有感','潘璵','宋','宋诗','song-poetry','','[]','開匣看長劍，功名志莫酬。',48,'全唐诗/poet.song.221000.json','["開匣看長劍，功名志莫酬。", "中原何日復，世事與誰謀。", "豪傑多相忘，干戈卒未休。", "斜陽照青野，雁過亦含愁。"]'),
('1e26baf2-163b-49d8-bf58-3a9aa0b51694','捲簾','潘璵','宋','宋诗','song-poetry','','[]','捲簾迎霽色，雙鵲噪庭柯。',48,'全唐诗/poet.song.221000.json','["捲簾迎霽色，雙鵲噪庭柯。", "時節清明過，園林綠蔭多。", "拂鸞揮畫扇，織翠試輕羅。", "欲困思煎茗，敲門有客過。"]'),
('d479365b-7702-4b65-8c4e-fdcf0ae0ab68','覽鏡','潘璵','宋','宋诗','song-poetry','','[]','覽鏡顔如改，登樓足尚疲。',48,'全唐诗/poet.song.221000.json','["覽鏡顔如改，登樓足尚疲。", "惜於多病裏，過了少年時。", "對月能忘酒，看花間有詩。", "獨餘豪氣在，頻把劍塵吹。"]'),
('34353ad9-9668-4b97-98ef-49d3664f7382','書道者庵','潘璵','宋','宋诗','song-poetry','','[]','心與道相安，幽居遠市廛。',48,'全唐诗/poet.song.221000.json','["心與道相安，幽居遠市廛。", "分花栽別圃，煮茗試新泉。", "地僻全成隠，身閑半是仙。", "金丹非易鍊，此法向誰傳。"]'),
('5f957726-c21b-4b50-aa4a-622fa9719589','道宮夜醮','潘璵','宋','宋诗','song-poetry','','[]','五雲宮闕擁霓旌，子夜謄章扣玉清。',32,'全唐诗/poet.song.221000.json','["五雲宮闕擁霓旌，子夜謄章扣玉清。", "星月滿壇塵不動，天風吹落步虛聲。"]'),
('049c170d-fa26-4394-a43d-f51f5240d1b3','梨山李王祠','潘璵','宋','宋诗','song-poetry','','[]','白玉樓成閲幾春，今瞻祠貌儼如生。',64,'全唐诗/poet.song.221000.json','["白玉樓成閲幾春，今瞻祠貌儼如生。", "一麾出守唐朝舊，八字封王宋爵榮。", "花發梨山存故蹟，水流柘浦響清聲。", "傳聞有禱須形夢，能使人知桂籍名。"]'),
('6a50182e-f669-4049-9580-c5dd3e11f80e','招信道上','潘璵','宋','宋诗','song-poetry','','[]','歲晚行人少，兵餘敗□多。',48,'全唐诗/poet.song.221000.json','["歲晚行人少，兵餘敗□多。", "邊風鳴曉雁，淮水浴天鵝。", "昔夢所不到，今來無奈何。", "翩然策歸騎，烟月自漁蓑。"]'),
('15b6a80b-bdfb-43fb-bf95-f9e4384a55c8','湖邊','潘璵','宋','宋诗','song-poetry','','[]','久不到湖邊，春風憶去年。',48,'全唐诗/poet.song.221000.json','["久不到湖邊，春風憶去年。", "看來遊覽地，難值艷陽天。", "花柳矜新態，溪山際宿緣。", "逢僧知寺近，索茗且譚禪。"]'),
('fddf1fc5-efbf-437b-b445-3a4f54ee2e4d','和潮韻','潘璵','宋','宋诗','song-poetry','','[]','海若驅車到浙江，西風吹起水雲鄉。',64,'全唐诗/poet.song.221000.json','["海若驅車到浙江，西風吹起水雲鄉。", "雷轟萬鼓不成雨，雪駕千峯祇薦凉。", "犀手謾持吳弩射，貂璫空走伍祠香。", "登樓且作川鯨飲，總付興亡與夕陽。"]'),
('4ea5efb0-744e-4daa-9888-71c20ef0c783','荷葉浦','潘璵','宋','宋诗','song-poetry','','[]','殘照明衰草，斜風掠小船。',48,'全唐诗/poet.song.221000.json','["殘照明衰草，斜風掠小船。", "雖過荷葉浦，不是藕花天。", "雁影浮寒水，鴉聲落暮煙。", "年豐時節好，清興滿吟邊。"]'),
('b9167d6d-b8c9-404d-aa1a-f4b3bf896701','九里松路上','潘璵','宋','宋诗','song-poetry','','[]','聯騎松邊路，天將曉色分。',48,'全唐诗/poet.song.221000.json','["聯騎松邊路，天將曉色分。", "澗鳴泉濺石，山暗樹棲雲。", "詩夢迎風醒，鍾聲想寺聞。", "只嫌攪清思，烏鵲噪紛紛。"]'),
('7279f338-6f00-4689-8873-f9a870b26f87','四聖觀御園海棠花','潘璵','宋','宋诗','song-poetry','','[]','燕子來時春政好，御園賸拆海棠花。',32,'全唐诗/poet.song.221000.json','["燕子來時春政好，御園賸拆海棠花。", "如今翠輦游觀少，一片東風屬道家。"]'),
('730d7924-0f47-4970-bf87-f457c182063a','山圃梅','潘璵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','舊種梅盈圃，山居未是貧。',48,'全唐诗/poet.song.221000.json','["舊種梅盈圃，山居未是貧。", "臘前春訊息，林下玉精神。", "水月西湖夢，風霜晚歲身。", "分明隠君子，不肯惹紅塵。"]'),
('8e1d9586-d94b-4ddd-a787-c8a4671a8829','春花吟','潘璵','宋','宋诗','song-poetry','','[]','春未來時花未覺，春欲去時花又落。',96,'全唐诗/poet.song.221000.json','["春未來時花未覺，春欲去時花又落。", "莫言世事無始終，春亦於花太情薄。", "我今問花并問春，司花司春者何人。", "空中髣髴有神語，此當問之於大鈞。", "不如再作問鈞賦，賦成直上天門去。", "扣天乞與花長春，免使花飛怨春暮。"]'),
('a0eda96a-9069-4654-a33f-299257358dc9','晚菊','潘璵','宋','宋诗','song-poetry','','[]','可惜重陽已過期，黄花無數繞山籬。',32,'全唐诗/poet.song.221000.json','["可惜重陽已過期，黄花無數繞山籬。", "政緣懶作趨時態，多少幽香人不知。"]'),
('323e3273-9c67-476c-a441-af112192d321','採桑曲','潘璵','宋','宋诗','song-poetry','','[]','東採桑，西採桑，春風陌上羅裙香。',40,'全唐诗/poet.song.221000.json','["東採桑，西採桑，春風陌上羅裙香。", "爲怕蠶饑急歸去，回頭忽見薄情郎，如何富貴却相忘。"]'),
('92b58d4a-9338-48d9-8ef7-f413b16c672b','愛柳','潘璵','宋','宋诗','song-poetry','','[]','萬紫千紅錦織成，一宵風雨盡飄零。',32,'全唐诗/poet.song.221000.json','["萬紫千紅錦織成，一宵風雨盡飄零。", "爭如楊柳全春色，不管春歸色自青。"]'),
('8e13d097-c0fb-42a2-8678-432fb843d945','移種菖蒲','潘璵','宋','宋诗','song-poetry','','[]','誰剪蒼龍髯，種之水邊石。',144,'全唐诗/poet.song.221000.json','["誰剪蒼龍髯，種之水邊石。", "不與草爭春，四時挺幽碧。", "余心具靜觀，而愛此正色。", "一朝移香根，古瓷手親植。", "疏之以泠風，沐之以甘澤。", "得此伴閑身，凡花何足惜。", "呼童汛浄室，寘彼芝蘭側。", "如參物外人，利名念俱釋。", "如親詩中仙，冷澹趣相得。", "人物本一體，清濁霄壤隔。", "物以類而聚，人於交貴擇。", "人爲物之靈，詎可乏真識。"]'),
('f2b4ad9a-31c6-46ff-b507-4e69e7c825de','鳩','潘璵','宋','宋诗','song-poetry','','[]','斑斑羽拂曉煙青，一樣東風兩樣聲。',32,'全唐诗/poet.song.221000.json','["斑斑羽拂曉煙青，一樣東風兩樣聲。", "計拙不如鴟婦巧，綢繆桑戶趁天晴。"]'),
('759d0b3e-1317-4202-9056-9168e11b9465','雁','潘璵','宋','宋诗','song-poetry','','[]','歲歲來賓似有期，此心非戀稻粱肥。',32,'全唐诗/poet.song.221000.json','["歲歲來賓似有期，此心非戀稻粱肥。", "不憐不带中原信，空對西風作字飛。"]'),
('08a670a7-3b04-4594-9385-245fc26511f4','聽子規有感','潘璵','宋','宋诗','song-poetry','','[]','客邊聽子規，忍見百花飛。',48,'全唐诗/poet.song.221000.json','["客邊聽子規，忍見百花飛。", "喚得春先去，如何汝未歸。", "蜀山仍舊在，世事覺今非。", "只合三緘口，空林伴夕暉。"]'),
('c7e37520-0f24-4719-b947-76be169c9838','嘲杜鵑','潘璵','宋','宋诗','song-poetry','','[]','把握年光屬大鈞，花開花落不由春。',32,'全唐诗/poet.song.221000.json','["把握年光屬大鈞，花開花落不由春。", "杜鵑若是知機早，歸去何須苦勸人。"]'),
('c9c7fbf9-fc06-4583-97df-da9c6a322105','聽雁有感','潘璵','宋','宋诗','song-poetry','','[]','怕聽雲間雁，新愁上客眉。',48,'全唐诗/poet.song.221000.json','["怕聽雲間雁，新愁上客眉。", "尖風欺破褐，落日迫殘棋。", "菊老休賒酒，梅開又費詩。", "鴒原千里隔，誰與話心期。"]'),
('fba1b1aa-2fcb-4f5a-8bc0-8f1e2506c706','嘲雁','潘璵','宋','宋诗','song-poetry','','[]','羽族無如爾列行，於時底事較炎凉。',64,'全唐诗/poet.song.221000.json','["羽族無如爾列行，於時底事較炎凉。", "應嫌塞北多風雪，却向江南戀稻粱。", "春到但知歸計急，火明不料禍機藏。", "自從寄了蘇卿信，此後傳書竟渺茫。"]'),
('e2f4459a-29ac-41c2-ac7c-a005baf2aa76','丈亭','潘璵','宋','宋诗','song-poetry','','[]','今古此行路，往來無了期。',48,'全唐诗/poet.song.221000.json','["今古此行路，往來無了期。", "荒亭塵壓旁，廢廟土侵碑。", "日落空江暮，山遥去鳥遲。", "待潮潮未長，沽醉且吟詩。"]'),
('55813e14-92b9-41a5-9d11-92459b75a9fd','小窗','潘璵','宋','宋诗','song-poetry','','[]','小小明窗瞰水開，惜花常是手親栽。',64,'全唐诗/poet.song.221000.json','["小小明窗瞰水開，惜花常是手親栽。", "春山欲曉聽鶑語，社雨纔晴認燕來。", "自滌硯磚閑試墨，笑持茗椀勝銜杯。", "有時細鍊推敲字，搔首斜陽立幾回。"]'),
('959e66db-ee6d-4df7-b745-dcbec4ff92be','田家','潘璵','宋','宋诗','song-poetry','','[]','田事收成了，倉箱積萬千。',48,'全唐诗/poet.song.221000.json','["田事收成了，倉箱積萬千。", "鷄鳴秋屋外，牛卧夕陽邊。", "溪樹爭收果，村醪不值錢。", "幸無征役苦，一醉樂豐年。"]'),
('332336aa-cd23-4c94-b2d7-e4b576ae8d78','野人家二首  其一','潘璵','宋','宋诗','song-poetry','','[]','枯藤伴椶屨，行到野人家。',48,'全唐诗/poet.song.221000.json','["枯藤伴椶屨，行到野人家。", "細雨肥梅實，輕風動菜花。", "村深難貰酒，客至旋煎茶。", "笑說生涯事，栽桑與種麻。"]'),
('c75212dd-0be1-492b-9bac-b94eaeb38a21','野人家二首  其二','潘璵','宋','宋诗','song-poetry','','[]','映門綠葉長桑麻，滿地深黄菜著花。',32,'全唐诗/poet.song.221000.json','["映門綠葉長桑麻，滿地深黄菜著花。", "祇道春風戀城市，也留情向野人家。"]'),
('06de64d9-670e-4bbe-b253-bfddd98f612a','華藏雲海亭','潘璵','宋','宋诗','song-poetry','','[]','一亭突兀出湖邊，慣與漁翁繫釣舡。',64,'全唐诗/poet.song.221000.json','["一亭突兀出湖邊，慣與漁翁繫釣舡。", "吳越興亡今已矣，山川流峙只依然。", "詩情空寄千年恨，眼力誰窮萬里天。", "獨有緇郎閑似我，却於鷗鷺結清緣。"]'),
('48108daf-7e94-49f2-9fdc-8be361ce69ec','冷泉亭和賈秋壑韻','潘璵','宋','宋诗','song-poetry','','[]','重到古招提，青松舊□圍。',48,'全唐诗/poet.song.221000.json','["重到古招提，青松舊□圍。", "泉聲流澗遠，亭影带雲微。", "小雨隨風去，殘花逐絮飛。", "白猿呼不應，人世幾斜暉。"]'),
('333dedbe-2c8d-4ba9-b976-6258fbc0e291','山居苦','潘璵','宋','宋诗','song-poetry','','[]','鑿破碧雲開牖戶，花多留得春長久。',32,'全唐诗/poet.song.221000.json','["鑿破碧雲開牖戶，花多留得春長久。", "種蔬種豆了生涯，心閑只與琴爲友。"]'),
('e813fcf4-d740-44a7-8c06-e665f215ffa9','湖居','潘璵','宋','宋诗','song-poetry','','[]','旋營小屋並湖濱，最喜閑身葉樣輕。',64,'全唐诗/poet.song.221000.json','["旋營小屋並湖濱，最喜閑身葉樣輕。", "俗子過門令我病，好山到眼覺心清。", "新開白地多栽竹，怕惹紅塵少入城。", "魚鳥忘機自飛泳，酒邊儘可助吟情。"]'),
('22beaf80-7d65-4a3e-a0b7-3f8dd46eacec','王巖幽隠居','潘璵','宋','宋诗','song-poetry','','[]','一片清閑福，山間結小廬。',48,'全唐诗/poet.song.221000.json','["一片清閑福，山間結小廬。", "此身爲隠計，有地學農鋤。", "午飲煎溪茗，朝羹摘野蔬。", "無人知姓字，可以避徵書。"]'),
('00d72e66-c7a3-4834-83c3-cf241dc3384d','山處','潘璵','宋','宋诗','song-poetry','','[]','浮雲富貴不關心，只向閑中寄此生。',64,'全唐诗/poet.song.221000.json','["浮雲富貴不關心，只向閑中寄此生。", "山色四時仁者靜，梅花萬古聖之清。", "慣臨風月搜吟趣，無復江湖夢客程。", "獨愛鄰僧常過我，一甌茶罷事棋枰。"]'),
('dc8742e0-de43-4286-9356-1fe9466b2020','山館','潘璵','宋','宋诗','song-poetry','','[]','山館坐秋雨，風吹霽景開。',48,'全唐诗/poet.song.221000.json','["山館坐秋雨，風吹霽景開。", "夕陽明遠水，落葉走空階。", "白髮人誰健，黄花節又催。", "看雲動孤酌，聊以尉吟懷。"]'),
('9b26d005-375b-4fae-837f-cbdf30cff5bf','秋日閑居二首  其一','潘璵','宋','宋诗','song-poetry','','[]','詩困權時卧竹窗，夢閑隨雁到衡陽。',32,'全唐诗/poet.song.221000.json','["詩困權時卧竹窗，夢閑隨雁到衡陽。", "覺來落日窺簾影，茶鼎松風潑鼻香。"]'),
('5b7ba0fa-4a53-4d86-a8e8-db8b09016850','秋日閑居二首  其二','潘璵','宋','宋诗','song-poetry','','[]','西風挾雨過江來，水樹煙村罨畫開。',32,'全唐诗/poet.song.221000.json','["西風挾雨過江來，水樹煙村罨畫開。", "待得夜晴窗有月，橫斜祇欠數枝梅。"]'),
('f08bb4cd-cb26-4acb-9c37-f8960f6490ea','秋日江居','潘璵','宋','宋诗','song-poetry','','[]','家枕滄江住，西風捲暮秋。',48,'全唐诗/poet.song.221000.json','["家枕滄江住，西風捲暮秋。", "雲行天欲動，潮長屋如浮。", "落葉懸漁網，斜陽滿客舟。", "吟成誰管領，拍手喚沙鷗。"]'),
('72a7d364-8e63-470c-a6c5-10192b69099c','秋日山居','潘璵','宋','宋诗','song-poetry','','[]','數椽依碧嶂，飛瀑濺藤蘿。',48,'全唐诗/poet.song.221000.json','["數椽依碧嶂，飛瀑濺藤蘿。", "地僻行人少，夜凉明月多。", "生涯安澹薄，樂事在吟哦。", "病後惟便睡，秋蛩聒砌莎。"]'),
('f2e9495c-1a0b-4255-b4ec-f8a26bc3353f','橫舟亭','潘璵','宋','宋诗','song-poetry','','[]','與世浮沉者，中流幾失維。',48,'全唐诗/poet.song.221000.json','["與世浮沉者，中流幾失維。", "此舟聊寓意，之子免乘危。", "夜雨蓬爲屋，秋風鈞不絲。", "莫嫌長艤岸，終有濟川時。"]'),
('d9c92a12-2019-44e5-a989-6dcec1ad7a44','閑居','潘璵','宋','宋诗','song-poetry','','[]','厭於奔走樂閑居，湖海交游任闊疎。',64,'全唐诗/poet.song.221000.json','["厭於奔走樂閑居，湖海交游任闊疎。", "燕去又爲千里客，雁來誰寄一行書。", "青山對面如相識，白髮無情亦懶梳。", "屋外有園三數畝，春風儘可學耕鋤。"]'),
('538d3731-e34f-4f7a-aef5-13b5616f1913','休倚樓','潘璵','宋','宋诗','song-poetry','','[]','碧天如水片雲收，雁雁西風字字秋。',32,'全唐诗/poet.song.221000.json','["碧天如水片雲收，雁雁西風字字秋。", "江上有樓休獨倚，夕陽衰草幾多愁。"]'),
('8101c88c-9c7a-408b-b411-55a9b1d074d6','登樓','潘璵','宋','宋诗','song-poetry','','[]','凉桐葉葉按秋聲，搔首危樓百感生。',32,'全唐诗/poet.song.221000.json','["凉桐葉葉按秋聲，搔首危樓百感生。", "天欲盡頭煙水闊，雁拖殘日下蕪城。"]'),
('3e656e79-4330-4cd2-9f09-aadda0082332','怕上樓','潘璵','宋','宋诗','song-poetry','','[]','憑高多感慨，怕上夕陽樓。',48,'全唐诗/poet.song.221000.json','["憑高多感慨，怕上夕陽樓。", "雲閣四山雨，江分兩岸秋。", "雁來驚客意，棗熟動邊愁。", "醉裏看長劍，英雄志未酬。"]'),
('0f8f4016-6928-4692-a2e8-31bc9233b192','飲張弌齋月臺','潘璵','宋','宋诗','song-poetry','','[]','同上最高臺，山頭晚色開。',48,'全唐诗/poet.song.221000.json','["同上最高臺，山頭晚色開。", "風纔驅雨去，月漸出雲來。", "世事悲秋扇，吟情付酒杯。", "誰家砧杵動，寒計又相催。"]'),
('cc1af998-cfdd-487c-b4a8-7428c6d2f943','書寓居壁','潘璵','宋','宋诗','song-poetry','','[]','家枕官河住，樓閑春已深。',48,'全唐诗/poet.song.221000.json','["家枕官河住，樓閑春已深。", "水風清燕語，簾日碎桐陰。", "煮茗降書困，焚香啟道心。", "浮雲輕富貴，城市即山林。"]'),
('d0a5e3f8-7fbf-4f83-969d-9fce59062be9','小窗即事','潘璵','宋','宋诗','song-poetry','','[]','小窗秋色靜，雲影弄斜陽。',48,'全唐诗/poet.song.221000.json','["小窗秋色靜，雲影弄斜陽。", "山带雨餘翠，菊存霜後香。", "詩情多冷澹，酒態强軒昂。", "近得梅爲友，相看風味長。"]'),
('b95a27b5-6e7d-4ffb-88f7-1592a272e491','倚欄','潘璵','宋','宋诗','song-poetry','','[]','酒醒思往事，搔首倚危欄。',48,'全唐诗/poet.song.221000.json','["酒醒思往事，搔首倚危欄。", "夜靜風鳴樹，天凉月滿山。", "客情憐去燕，秋思入幽蘭。", "撫劍發長嘯，此身空自閑。"]'),
('fb7566ee-29af-4f8d-a8cc-cbafbe4bd09b','湖上寺','潘璵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖風物好，每被寺僧分。',48,'全唐诗/poet.song.221000.json','["西湖風物好，每被寺僧分。", "榻卧通宵月，窗開疊嶂雲。", "天寬多境界，地靜隔囂氛。", "憶昔陪清話，平生所未聞。"]'),
('22828192-d498-4712-8fa0-57eb0ea78427','送僧鐵山見趙山臺','潘璵','宋','宋诗','song-poetry','','[]','山臺慣與吟僧接，新剖澄江太守符。',64,'全唐诗/poet.song.221000.json','["山臺慣與吟僧接，新剖澄江太守符。", "前日相逢曾有約，今番一見必如初。", "固知海裏難爲水，須認衣中自藴珠。", "握手只譚風與月，莫因名利復躊躇。"]'),
('ec78ef34-40fb-4b66-8bb0-e8566fba2b18','書蘭莫德全壁','潘璵','宋','宋诗','song-poetry','','[]','誰謂居廛身未清，在家心似出家僧。',32,'全唐诗/poet.song.221000.json','["誰謂居廛身未清，在家心似出家僧。", "銅壺慣買梅花插，相對無言悟小乘。"]'),
('746fa7cf-6674-40ad-97d4-d980b0ef2d54','寺中','潘璵','宋','宋诗','song-poetry','','[]','春深寺逾靜，雲伴小窗閑。',48,'全唐诗/poet.song.221000.json','["春深寺逾靜，雲伴小窗閑。", "客思落花裏，雞聲疎竹間。", "晝全無一事，身似坐空山。", "幽意何人會，吟僧時往還。"]'),
('6ff1a959-909c-4855-ba4c-9a2d5a9763aa','讀少陵近體詩','潘璵','宋','宋诗','song-poetry','','[]','少陵近體詩，其間備衆體。',48,'全唐诗/poet.song.221000.json','["少陵近體詩，其間備衆體。", "鍊語發英華，立意爲根柢。", "如擊常山蛇，應處貫首尾。", "今人一體看，而不究其理。"]'),
('371e678a-f656-4e5a-9392-c04aaed012d9','書紅塵蘭若吟卷','潘璵','宋','宋诗','song-poetry','','[]','家住東風花柳邊，客來試茗學談禪。',32,'全唐诗/poet.song.221000.json','["家住東風花柳邊，客來試茗學談禪。", "有時病酒關門睡，夢到維摩丈室前。"]'),
('240fe37b-c6ed-4c3d-bd95-87c5bc5ea946','送鄭渭濱歸里','潘璵','宋','宋诗','song-poetry','','[]','十年學道客長安，鍊得丹成返故山。',64,'全唐诗/poet.song.221000.json','["十年學道客長安，鍊得丹成返故山。", "賸带錦囊詩料去，肯嫌黄葉路程寒。", "梅邊月照人千里，竹下雲封屋兩間。", "此後旦評聲價重，不將舊日阿蒙看。"]'),
('1a21c1ec-7e20-4a80-9df4-7900c55e43cd','送柴仲山歸里','潘璵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','長臺在何處，俄聽話歸期。',48,'全唐诗/poet.song.221000.json','["長臺在何處，俄聽話歸期。", "雪霽千山月，梅開一路詩。", "京塵隨地盡，春色到家知。", "欲把西湖酒，重來是幾時。"]'),
('2156c154-a3a3-454a-9c81-28a8ca4d21ac','送朱靜佳簿君歸','潘璵','宋','宋诗','song-poetry','','[]','武夷山下路，此去幾時程。',48,'全唐诗/poet.song.221000.json','["武夷山下路，此去幾時程。", "檢曆冬將暮，驅車月正明。", "客邊聊話別，吟裏莫寒盟。", "只怕除書到，中途趣入京。"]'),
('ccf26173-8669-4c72-8936-7f234f3f0720','送吟卷還趙萬里','潘璵','宋','宋诗','song-poetry','','[]','吟中蜚雋聲，太白是前身。',48,'全唐诗/poet.song.221000.json','["吟中蜚雋聲，太白是前身。", "風月無非我，江山得主人。", "冰梭織古錦，廟瑟奏陽春。", "洗眼觀新稿，客懷清絕塵。"]'),
('7bfa104b-7da8-4f26-8eae-9ccfec4c0e74','送胡月山遊浙西','潘璵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖摽雋名，誰不締吟盟。',48,'全唐诗/poet.song.221000.json','["西湖摽雋名，誰不締吟盟。", "長說貧爲累，猶嫌思未清。", "殘編饑鼠齧，破壁亂蛩鳴。", "一棹松江去，故人應動情。"]'),
('3802606f-ed4e-479e-996a-83a43093431c','送宣昭子遊淮','潘璵','宋','宋诗','song-poetry','','[]','幾年携劍過邊城，非但譚兵善用兵。',64,'全唐诗/poet.song.221000.json','["幾年携劍過邊城，非但譚兵善用兵。", "果是胸中抱材氣，肯於紙上立功名。", "事當著力機須敏，人匪知心語莫輕。", "况有故交能刮目，此行端不負平生。"]'),
('1f6f066a-dad3-49f8-8e8a-1f06b2577f50','遊丹山','孫子秀','宋','宋诗','song-poetry','','[]','四明洞天居第九，巨靈擘石開窗牖。',96,'全唐诗/poet.song.221000.json','["四明洞天居第九，巨靈擘石開窗牖。", "捫蘿陟巘不憚勞，同行况遇忘年友。", "老苔護石蒼虎閑，飛瀑懸巖玉龍吼。", "豁然人與境俱勝，醉歌拍缶忘升斗。", "固知壺中別有天，未必醉翁真在酒。", "徘徊步月澹忘歸，世事浮雲竟何有。"]'),
('25581e7d-778a-4e61-8198-97cf95c1ff3a','早春遊東山石洞','孫子秀','宋','宋诗','song-poetry','','[]','穹石丹崖出，攢峰萬壑回。',48,'全唐诗/poet.song.221000.json','["穹石丹崖出，攢峰萬壑回。", "古苔陰洞寂，新雨綠波開。", "渡絕移叢篠，飛春泛落梅。", "東山有夙尚，且盡手中杯。"]'),
('dfbb184c-a857-46f8-b7f3-74aa4dc5f0b1','句','陳仲微','宋','宋诗','song-poetry','','[]','死爲異國他鄉鬼，生是江南直諫臣。',16,'全唐诗/poet.song.221000.json','["死爲異國他鄉鬼，生是江南直諫臣。"]'),
('c634e6bf-9806-47f5-8b74-911fc6073b48','趙子固水仙圖','程驤','宋','宋诗','song-poetry','','[]','幾日東風雨乍晴，獨騎官馬繞湖行。',32,'全唐诗/poet.song.221000.json','["幾日東風雨乍晴，獨騎官馬繞湖行。", "詩成酒力都消盡，人與仙花一樣清。"]'),
('bca64f91-7ee9-4100-b824-5be182959a50','游洞霄登蓬山隠居','魏克愚','宋','宋诗','song-poetry','','[]','仙境孰爲真，蓬山隠獨清。',48,'全唐诗/poet.song.221000.json','["仙境孰爲真，蓬山隠獨清。", "樹林陰上下，樓觀影崢嶸。", "雨送流泉響，禽供搗藥聲。", "何須天柱頂，身已在空明。"]'),
('6ab374a4-41ad-4c37-b81d-a30c6fee141f','遊洞霄登秀樓','魏克愚','宋','宋诗','song-poetry','','[]','暝色秀林霏，危樓挹翠微。',48,'全唐诗/poet.song.221000.json','["暝色秀林霏，危樓挹翠微。", "靜中知必壽，樂矣自忘歸。", "道話清堪對，塵襟凈欲飛。", "金丹在何許，我欲扣玄機。"]'),
('4818512b-1dca-4438-921d-258e982fcd04','杏花','厲文翁','宋','宋诗','song-poetry','','[]','杏花菖葉漸爛斑，率屬劭農入祖關。',32,'全唐诗/poet.song.221000.json','["杏花菖葉漸爛斑，率屬劭農入祖關。", "昔日郎君方彩袖，今朝太守已蒼顔。"]'),
('9847f0fb-6678-41af-b94c-fc3c1a2cf37b','庭竹','厲文翁','宋','宋诗','song-poetry','','[]','渭川未暇栽千畝，庭檻聊須種數根。',32,'全唐诗/poet.song.221000.json','["渭川未暇栽千畝，庭檻聊須種數根。", "敢愛深秋群木脫，獨欺風雨戰黄昏。"]'),
('8b16671a-3add-4f6b-b918-2c1c57a7ebd7','茶','厲文翁','宋','宋诗','song-poetry','','[]','海濱魚鹽勝耕稼，嘗呼父老采丁寧。',48,'全唐诗/poet.song.221000.json','["海濱魚鹽勝耕稼，嘗呼父老采丁寧。", "江鄉魚茗尤逐末，爲分利害別重輕。", "拔茶種桑何苦口，崇陽因得良吏名。"]'),
('372aa332-1ffe-4bd8-af1e-396ba3e1b0b3','無題','厲文翁','宋','宋诗','song-poetry','','[]','灧澦拓瞿唐，二孤障瀾蠡。',24,'全唐诗/poet.song.221000.json','["灧澦拓瞿唐，二孤障瀾蠡。", "大哉神禹功，天地相終始。"]'),
('ca4cc718-5cf1-4659-83bc-1e45266ca943','句  其一','厲文翁','宋','宋诗','song-poetry','','[]','暮雲春雪江南北，回首人生嘆路歧。',16,'全唐诗/poet.song.221000.json','["暮雲春雪江南北，回首人生嘆路歧。"]'),
('0746a251-1d9f-49a8-a79d-a94a45a62b50','句  其二','厲文翁','宋','宋诗','song-poetry','','[]','翠草庭前生意足，甘棠堤上去思多。',16,'全唐诗/poet.song.221000.json','["翠草庭前生意足，甘棠堤上去思多。"]'),
('d31e8439-4937-4fdf-878f-22bd563de5d6','句  其三','厲文翁','宋','宋诗','song-poetry','','[]','蒼蕪萬頃渺無邊，鞭石飛梁接市廛。',16,'全唐诗/poet.song.221000.json','["蒼蕪萬頃渺無邊，鞭石飛梁接市廛。"]'),
('40ede3b8-50fd-4268-aece-ee6fb7e5c4c6','句  其四','厲文翁','宋','宋诗','song-poetry','','[]','且喜卧龍常自在，新詩特地報平安。',16,'全唐诗/poet.song.221000.json','["且喜卧龍常自在，新詩特地報平安。"]'),
('cd5307dc-0179-4b65-9180-f8d102b55a66','句  其五','厲文翁','宋','宋诗','song-poetry','','[]','若見集英門外柳，爲言曾惹御爐香。',16,'全唐诗/poet.song.221000.json','["若見集英門外柳，爲言曾惹御爐香。"]'),
('7a921044-1fa7-412c-932e-40718039da11','遊金石臺','家坤翁','宋','宋诗','song-poetry','','[]','廬陵遊樂夕陽山，太守何人若是班。',64,'全唐诗/poet.song.221000.json','["廬陵遊樂夕陽山，太守何人若是班。", "三島幻成一丘小，五峯對峙兩溪環。", "竹間庭院鄰翁卜，木杪樓臺仙者寰。", "紫笑扶疎枝幹老，春來得興頗開顔。"]'),
('eba7773f-be61-4894-a8a3-2b88b63ba06d','次曾南豐韻','家坤翁','宋','宋诗','song-poetry','','[]','憶昔詩豪爲寫真，至今光景尚如新。',64,'全唐诗/poet.song.221000.json','["憶昔詩豪爲寫真，至今光景尚如新。", "亭中客鬢幾人老，山下靈根千歲春。", "倏歘相逢皆召杜，舂容莫逆少雷陳。", "我來隨分重知見，似與夫君夙有因。"]'),
('a2058c5a-d02c-41e9-a0cf-85c2fc7db26b','創建魁星閣','何萬選','宋','宋诗','song-poetry','','[]','天開奎壁作靈神，傑構凌霄景運新。',64,'全唐诗/poet.song.221000.json','["天開奎壁作靈神，傑構凌霄景運新。", "乍向魚洲排雁塔，更看虎阜躍龍津。", "山林風俗如鄒魯，翰苑文章邁漢秦。", "此後鰲頭誇遂水，應知魁閣瑞光頻。"]'),
('503e0f02-6f19-48f8-9a22-d5cbd0c72b12','宿淮陰縣作','陳羽','宋','宋诗','song-poetry','','[]','秋燈點點淮陰市，楚客連檣宿淮水。',32,'全唐诗/poet.song.221000.json','["秋燈點點淮陰市，楚客連檣宿淮水。", "夜深風起魚鼈腥，韓信祠堂月明裏。"]'),
('ba76aab4-1691-459c-9a3a-d5b7904af45e','城下聞夷歌','陳羽','宋','宋诗','song-poetry','','[]','犍爲城下䍧牱路，空冢灘西賈客舟。',32,'全唐诗/poet.song.221000.json','["犍爲城下䍧牱路，空冢灘西賈客舟。", "此夜可憐江上月，夷歌銅鼓不勝愁。"]'),
('af517a96-3331-4ee0-9427-5ba0a0f6d921','梓州與溫商夜別','陳羽','宋','宋诗','song-poetry','','[]','鳳凰城裏花時別，玄武江邊月下逢。',64,'全唐诗/poet.song.221000.json','["鳳凰城裏花時別，玄武江邊月下逢。", "客舍莫辭先買酒，相門曾忝共登龍。", "近風騷屑千家竹，隔水悠揚五夜鐘。", "明日又行西蜀路，不堪天際遠山重。"]'),
('860395a6-dced-4625-9c7e-34a435310726','廣陵秋夜月','陳羽','宋','宋诗','song-poetry','','[]','霜落寒空月上樓，月中歌吹滿揚州。',32,'全唐诗/poet.song.221000.json','["霜落寒空月上樓，月中歌吹滿揚州。", "相看醉舞倡樓月，不覺隋家陵樹秋。"]'),
('a24c9e86-27b8-4c0f-a7fc-98996764ab9c','春暖','陳羽','宋','宋诗','song-poetry','','[]','東風吹暖氣，消散入晴天。',24,'全唐诗/poet.song.221000.json','["東風吹暖氣，消散入晴天。", "漸變池塘色，欲生楊柳煙。"]'),
('dbbaea5b-706a-4cdb-83ea-4d913c531ea8','隠居','陳羽','宋','宋诗','song-poetry','','[]','稚子新能編笋笠，山妻舊解補荷衣。',32,'全唐诗/poet.song.221000.json','["稚子新能編笋笠，山妻舊解補荷衣。", "秋山隔岸清猿叫，湖水當門白鳥飛。"]'),
('519b9ba0-22c4-4ef4-a6d5-8b933bcda7b8','姑蘇臺覽古','陳羽','宋','宋诗','song-poetry','','[]','憶昔吳王爭霸日，歌謠滿耳上蘇臺。',32,'全唐诗/poet.song.221000.json','["憶昔吳王爭霸日，歌謠滿耳上蘇臺。", "三千宮女看花處，人靜臺空花自開。"]'),
('b75ff6a7-e3a9-4604-8022-cce34de309c5','吳城覽古','陳羽','宋','宋诗','song-poetry','','[]','吳王舊國水烟空，香徑無人蘭葉紅。',32,'全唐诗/poet.song.221000.json','["吳王舊國水烟空，香徑無人蘭葉紅。", "春色似憐歌舞地，年年先發館娃宮。"]'),
('dfb14be1-aae3-43c9-8710-61a4ce837e49','句','陳羽','宋','宋诗','song-poetry','','[]','中朝駙馬何平叔，南國佳人陸士龍。',16,'全唐诗/poet.song.221000.json','["中朝駙馬何平叔，南國佳人陸士龍。"]'),
('c5e6bee6-0e08-4f06-bfd0-8c589dd5c020','光風霽月亭','呂人龍','宋','宋诗','song-poetry','','[]','江邊回首見崢嶸，砥柱頹波氣象獰。',64,'全唐诗/poet.song.221000.json','["江邊回首見崢嶸，砥柱頹波氣象獰。", "三面好山俱覿面，一泓寒綠不聞聲。", "月從康節詩邊吐，風向包羲易裏生。", "如此生涯天未老，更須著脚外間行。"]'),
('291e9bd6-d442-4bd0-8e4f-b604bb69e2b2','上融堂','呂人龍','宋','宋诗','song-poetry','','[]','直道人間未可孤，朝廷有意用真儒。',64,'全唐诗/poet.song.221000.json','["直道人間未可孤，朝廷有意用真儒。", "故將通鑑煩司馬，不使春秋欠董狐。", "握節米豬高節不，盜名齊豹得名無。", "若商敗狄鏖秦事，先軫何嘗是匹夫。"]'),
('05b6cb53-488b-4449-85fe-b3d2a58b4a3b','題釣臺  其一','呂人龍','宋','宋诗','song-poetry','','[]','釣臺還是先生物，洛汭今非漢帝家。',32,'全唐诗/poet.song.221000.json','["釣臺還是先生物，洛汭今非漢帝家。", "過客不知興廢事，又馳車馬入京華。"]'),
('293aeb79-0ad4-4b23-a265-115c829a999f','題釣臺  其二','呂人龍','宋','宋诗','song-poetry','','[]','萬古寒潭數曲山，紅塵不到白鷗閒。',32,'全唐诗/poet.song.221000.json','["萬古寒潭數曲山，紅塵不到白鷗閒。", "先生自是生涯淡，却厭浮雲滿世間。"]'),
('9b5d2290-d73e-46cf-ba4b-7518cea088d2','春歸','呂人龍','宋','宋诗','song-poetry','','[]','過却清明艷冶天，梨花飛雪柳森烟。',32,'全唐诗/poet.song.221000.json','["過却清明艷冶天，梨花飛雪柳森烟。", "欲憑鶑燕留春住，無奈東風信杜鵑。"]'),
('d46efbee-3ea3-4254-b490-0eafb3194e67','宿建興寺','呂人龍','宋','宋诗','song-poetry','','[]','路入招提晚更深，萬山秋老薄寒生。',32,'全唐诗/poet.song.221000.json','["路入招提晚更深，萬山秋老薄寒生。", "芙容枝上無多雨，自把孤懷滴到明。"]'),
('55877b51-3b16-4eb9-9340-1f4b1b6456d8','壽右丞相  其一','冰壺','宋','宋诗','song-poetry','','[]','東方正氣毓元身，夙稟春陽澤物心。',64,'全唐诗/poet.song.221000.json','["東方正氣毓元身，夙稟春陽澤物心。", "應昴酇侯依漢日，騎箕傅說作商霖。", "地隆鼎鉉關三極，風動笙鏞叶八音。", "稽首君親同介壽，鄖山鄞水等高深。"]'),
('c782e4c0-c2f9-4aa8-874e-0e2b2f885684','壽右丞相  其二','冰壺','宋','宋诗','song-poetry','','[]','淳祐更絃第二春，順開黄道對昌辰。',64,'全唐诗/poet.song.221000.json','["淳祐更絃第二春，順開黄道對昌辰。", "貔貅不動紅塵騎，鴻雁于歸青野人。", "千載龍雲符氣運，一堂魚水會精神。", "地寒燕谷須鈞播，揮手東風造化仁。"]'),
('50e3a85c-26ae-42e1-a642-1d803d093a6d','和靜照詩韻  其一','釋妙弘','宋','宋诗','song-poetry','','[]','莫辭迢遞供杯茶，香噴雲腴映彩霞。',32,'全唐诗/poet.song.221000.json','["莫辭迢遞供杯茶，香噴雲腴映彩霞。", "兩兩夢中休說夢，覺來渾是夢中花。"]'),
('b1c760e3-7602-4fb5-b36d-89626609fde6','和靜照詩韻  其二','釋妙弘','宋','宋诗','song-poetry','','[]','尋幽覓勝到天台，觸目風光剪剪開。',32,'全唐诗/poet.song.221000.json','["尋幽覓勝到天台，觸目風光剪剪開。", "欲問曇猷舊遺跡，千山排闥送青來。"]'),
('ed50f757-c96a-40c0-87bc-2be413863c57','和靜照詩韻  其一','釋普濟','宋','宋诗','song-poetry','','[]','各逞神通現瑞茶，非雲非雪亦非霞。',32,'全唐诗/poet.song.221000.json','["各逞神通現瑞茶，非雲非雪亦非霞。", "夢中說夢非見見，報道從來眼不花。"]'),
('5ec5c487-bd13-4c89-a4e4-c88aee04b6fd','和靜照詩韻  其二','釋普濟','宋','宋诗','song-poetry','','[]','半千尊者眼如眉，一一從頭爲點開。',32,'全唐诗/poet.song.221000.json','["半千尊者眼如眉，一一從頭爲點開。", "踏斷石橋成兩段，方知親過一回來。"]'),
('2da61966-b3c0-495d-a8b3-57f3da1b89a3','比梅三絕  其一','潘桂','宋','宋诗','song-poetry','','[]','鐵肝迂叟秉剛腸，只有梅花可比方。',32,'全唐诗/poet.song.221000.json','["鐵肝迂叟秉剛腸，只有梅花可比方。", "任意東風染紅紫，自留冰雪臘前香。"]'),
('f7671c9d-3036-4649-b6a3-8b9e9a7819f3','比梅三絕  其二','潘桂','宋','宋诗','song-poetry','','[]','功名高並蜀山蒼，已矣封州道路長。',32,'全唐诗/poet.song.221000.json','["功名高並蜀山蒼，已矣封州道路長。", "歲晚凜然何所似，暗香疏影正昏黄。"]'),
('f8e913b7-4427-4da8-a8dc-463da913048a','比梅三絕  其三','潘桂','宋','宋诗','song-poetry','','[]','千枝枯瘁剩殘葩，雪虐風饕壓不斜。',32,'全唐诗/poet.song.221000.json','["千枝枯瘁剩殘葩，雪虐風饕壓不斜。", "人道梅花似潘子，如何自不比梅花。"]'),
('d0449d4b-d3d7-41f9-80cb-26c5ba0f48b8','墨梅  其一','家鉉翁','宋','宋诗','song-poetry','','[]','非香之香，非色之色。',20,'全唐诗/poet.song.221000.json','["非香之香，非色之色。", "伴我孤吟，風清月白。"]'),
('31463a8c-4565-4c2e-9211-6d720df3e6a1','墨梅  其二','家鉉翁','宋','宋诗','song-poetry','','[]','冰崖孤芳，雪林早春。',20,'全唐诗/poet.song.221000.json','["冰崖孤芳，雪林早春。", "伴我讀易，見天地心。"]'),
('355c9bba-f3ef-4a6a-b2bd-0c4bdf091900','風雨歸舟圖  其一','家鉉翁','宋','宋诗','song-poetry','','[]','挂帆涉滄波，瞬息三萬里。',24,'全唐诗/poet.song.221000.json','["挂帆涉滄波，瞬息三萬里。", "蓬萊有會期，莫爲風雨止。"]'),
('65b0f379-c8ee-4842-91bb-869a37ee4645','風雨歸舟圖  其二','家鉉翁','宋','宋诗','song-poetry','','[]','前津風色惡，斷岸寄孤艇。',24,'全唐诗/poet.song.221000.json','["前津風色惡，斷岸寄孤艇。", "輸他田舍翁，午酲猶未醒。"]'),
('1f73a2f7-4ca5-4e4f-87f0-2964b0dbccd9','中秋日客退獨坐偶成','家鉉翁','宋','宋诗','song-poetry','','[]','春月令人悅，秋月令人悲。',48,'全唐诗/poet.song.221000.json','["春月令人悅，秋月令人悲。", "人意自悲歡，夫豈月所爲。", "炯然此方寸，圓明貫四時。", "閉門獨自賞，無盈亦無虧。"]'),
('8f4ce860-5551-4294-89f4-9ac75bcdc1e7','東方職生之地而異端之書指爲地下獄余竊非之','家鉉翁','宋','宋诗','song-poetry','','[]','五行木維仁，四德春維元。',120,'全唐诗/poet.song.221000.json','["五行木維仁，四德春維元。", "混淪判八極，維東最爲尊。", "萬形囿大化，生生此其門。", "茲爲九州鎮，豈以三望論。", "彼爲異端說，怪誕驚愚昏。", "妄指陽明地，同彼長夜閽。", "愚人戢冥威，奔走不憚煩。", "頑夫驚罪福，未死先飛魂。", "年年春向晚，時事羞蘋蘩。", "我在神即在，帝顧良亦繁。"]'),
('8d7bed04-2e45-4bb5-981e-bf5a8413e105','萱草篇','家鉉翁','宋','宋诗','song-poetry','','[]','詩人美萱草，蓋謂憂可忘。',216,'全唐诗/poet.song.221000.json','["詩人美萱草，蓋謂憂可忘。", "人子惜此花，植之盈北堂。", "庶以悅親意，豈特憐芬芳。", "使君有慈母，星髮壽且康。", "晨昏謹色養，彩服戲其傍。", "燕喜酌春酒，歡然釂金觴。", "物理似有助，叢萱忽非常。", "競吐栗玉艷，欲奪金芝光。", "秀本自稠疊，駢枝亦熒煌。", "乃知風人意，比興宜成章。", "東野情思苦，少憂多悲傷。", "謂此兒女花，莫能解剛腸。", "斯言雖有激，疑其未通方。", "憂心無時已，徒枉憔悴鄉。", "寓物儻適意，何須動悲凉。", "况復循吏政，和聲入封疆。", "撫俗時用乂，事親日尤長。", "萱草歲歲盛，此樂安可量。"]'),
('7597a3d2-8acc-475f-8486-bd27d3d79032','孔同知孔聖之裔垂念逆旅用意勤甚詩以謝之','家鉉翁','宋','宋诗','song-poetry','','[]','巖巖魯山高，可望不可即。',204,'全唐诗/poet.song.221000.json','["巖巖魯山高，可望不可即。", "袖有一瓣香，無路瞻聖域。", "朅來高河陽，乃在天壤北。", "離羣久索居，心茅殆欲塞。", "人言聖哲孫，來憑貳車式。", "洙源分派清，龜蒙見孤崱。", "願傚陳亢問，少祛樊須惑。", "莫爲徐羣先，未遂儀封識。", "良朋忽踵門，厚意傳矜惻。", "分我纖纊溫，賁我素絲緎。", "寒谷回春溫，古道見顔色。", "洪惟夫子牆，如天有辰極。", "六經恢衣被，萬化視法則。", "嗟我早端誠，求道未有得。", "暮年遭時屯，願躋愈自力。", "聖壁多舊藏，聞孫世秉德。", "稽首求一言，書紳永爲式。"]'),
('3a16f7ae-25aa-4069-b915-c820f1c6931b','圯上行','家鉉翁','宋','宋诗','song-poetry','','[]','三代以還惟有漢，六經之外更無書。',166,'全唐诗/poet.song.221000.json','["三代以還惟有漢，六經之外更無書。", "漢家自繼商周統，經術當傳孔孟餘。", "天生偉人元氣會，莘畝說岩乃其徒。", "掃除申商斥儀衍，混合宇宙需吾儒。", "便應平躋古王佐，小却亦稱大丈夫。", "云何赤帝應運起，乃以黄石爲先驅。", "太公六韜豈不善，顛秦蹶項或所需。", "繄欲上嘉羲黄媲隆古，詩書禮樂不可一日無。", "惜哉子房遯世早，不及遺經細探討。", "使公得與齊魯兩生遊，吾知漢道同商周。"]'),
('b6f41259-daa6-456f-be3f-28a5fc9a112a','三山吳履道承出示理皇御書唐人詩恭題其後','家鉉翁','宋','宋诗','song-poetry','','[]','先君曩侍緝熙殿，拜賜天畫盈筐箱。',98,'全唐诗/poet.song.221000.json','["先君曩侍緝熙殿，拜賜天畫盈筐箱。", "帝書超軼鍾王上，不與歐柳論低昂。", "孤臣流落濱九死，老眼尚能識偏傍。", "旅簷驚見亟再拜，拜起不覺涕淚滂。", "幾擬從君換此寶，囊空無物可以將。", "待歸從君乞模本，刻之琬琰永爲子孫藏。"]'),
('5764353e-3bda-42fe-b8a6-bc98e4a5ffff','元和修復馬政圖','家鉉翁','宋','宋诗','song-poetry','','[]','君不見明皇開元初，前驅萬騎雲煙鋪。',135,'全唐诗/poet.song.221000.json','["君不見明皇開元初，前驅萬騎雲煙鋪。", "中年不戒履霜漸，乃以牧權付之營州軋犖奴。", "驅我天閑入鼠穴，八坊奇産空無餘。", "元和天子奮威斷，收拾舊物還中區。", "向來汧渭孳生處，猶有牧人自營牧與芻。", "爭持私牽應詔書，願備法駕王前驅。", "詩翁感歎成八解，何人畫工畫爲圖。", "此圖似是八之一，元和舊事猶可識。"]'),
('d2ed5229-e86c-4eb9-a16c-b6dc2a339b35','題蔣同知所藏馬圖前後凡五','家鉉翁','宋','宋诗','song-poetry','','[]','行而前者驪與皇，從而後者騂與駒。',72,'全唐诗/poet.song.221000.json','["行而前者驪與皇，從而後者騂與駒。", "匪雙匪駟良馬五，畫出人間五馬圖。", "祝君出典大藩牧，願君旗旄旌節耀前驅。", "古來共說人生五馬貴，况復盛年勁氣綠鬢長眉鬚。"]'),
('aa0a9740-765d-4c6c-b823-9c7ef1349891','保定士人以所藏太白像見示筆意甚奇爲題此李去非好吟太白之裔歟書一本送之','家鉉翁','宋','宋诗','song-poetry','','[]','晨興有客訪我來，光采燄燄出屋上。',150,'全唐诗/poet.song.221000.json','["晨興有客訪我來，光采燄燄出屋上。", "銜袖疑有希世珍，徐而出之岸然長庚相。", "高標直欲干青冥，逸氣可以走象罔。", "傳來定非凡俗工，應有高人得之自夢想。", "願君寶藏勿輕畀，瓣薌朝夕勤嚮仰。", "可以長君胸次之瑰奇，可以助君詩情之豪暢。", "儻來萬事付浮雲，眼中隨地得真賞。", "他年若遇天台坐忘真，便應驂鸞御鶴朝神清，一洗人間千劫塵中塵。"]'),
('0a336c70-04b4-41a9-b819-6b46c3b2a2d4','韓京叔古木寒泉圖','家鉉翁','宋','宋诗','song-poetry','','[]','朝來我夢三偉人，振袂而入清風生。',98,'全唐诗/poet.song.221000.json','["朝來我夢三偉人，振袂而入清風生。", "掃門坐需佳客至，鄰叟醉墨俄然成。", "古木昂藏出澗壑，下臨百丈寒泉清。", "高冠長劍萬夫望，其傍那有鋤笠兩耦耕。", "歲寒坐對亦已久，東風看取岩穴春。", "卧龍騰驤碧落上，南山夜半雷雨驚。"]'),
('3f485126-6b6b-4176-9738-398412408387','題陳子新所藏雲山小景漁磯二士','家鉉翁','宋','宋诗','song-poetry','','[]','道人胸次絕塵滓，能得工夫無盡意。',132,'全唐诗/poet.song.221000.json','["道人胸次絕塵滓，能得工夫無盡意。", "醉中引興春山青，醒來弄翰秋風起。", "晦明變幻在毫端，倏忽煙波幾千里。", "少年我嘗識其人，不見于今垂五紀。", "此圖似是夫君筆，餘子紛紛溟涬耳。", "黄沙蒼茫雪苑冬，旅窗展玩萬慮空。", "恍如身在苕源東，攝衣步上雲山最高峰。", "二客追隨不能及，相與指點平沙明月中。"]'),
('8696ac58-1db0-4ee9-ba52-e9eb50733fcc','雪中梅竹圖','家鉉翁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅兄乃我義理朋，竹友從我林壑遊。',226,'全唐诗/poet.song.221000.json','["梅兄乃我義理朋，竹友從我林壑遊。", "青青不受塵土涴，皜皜肯與紅紫侔。", "別來天涯今幾載，老大相逢俱白頭。", "玉龍排空展鱗鬣，天姥振佩鏘琳璆。", "古心姱節自爲伴，嚴氣正性誰能儔。", "兒童莫作飛絮看，道眼無以空花求。", "花飛絮舞兩值遇，殆天之合非人謀。", "嬌禽謾誇顔色好，弱羽難禁寒風遒。", "寄爾南枝尺寸地，莫與鶩羣爲輩流。", "何人畫工巧位置，使我坐對消閒愁。", "却風吹灰萬象改，平生故交還在不。", "綈袍猶思見范叔，雪堂賸欲逢元修。", "故山自有歸隠處，琅玕成林雪成塢。", "會當見汝面目真，西湖西畔踏雪尋故人。"]'),
('fd630582-b9cc-4d21-a38c-4afe12e32e0d','趙提舉求作字余辭以不能工仍作詩謝之','家鉉翁','宋','宋诗','song-poetry','','[]','少年振臂入場屋，寸晷謾書誇拙速。',130,'全唐诗/poet.song.221000.json','["少年振臂入場屋，寸晷謾書誇拙速。", "中年收斂歸法度，不能爲顔僅爲谷。", "晚歲頗爲憂患困，弱腕不禁事物逐。", "要之作字非所長，空腔僅存十年讀。", "有客來從析津頭，翰墨多藏玉韞匵。", "從我乞書戲我耳，爲君小試知君蹙。", "長箋浄練雪不如，牆角鼠芒嗟已禿。", "此邦椽筆廣文翁，何用更向寒汀索野鶩。"]'),
('b69c0d0a-ad4f-4fea-97b2-b1aff2e3957e','辛巳正月十六日張雲齋過訪郭舜元高飛卿持草書黄庭來會作上元歌','家鉉翁','宋','宋诗','song-poetry','','[]','市人歡呼賞元夕，羈人掩關玩周易。',183,'全唐诗/poet.song.221000.json','["市人歡呼賞元夕，羈人掩關玩周易。", "易中具足光明燈，一燈散作千百億。", "粵從上元甲子到於今，經幾上元此燈炯炯如一日。", "靜思此理發長嘯，短檠孤坐看虛碧。", "廣文先生乃我義理朋，從我求觀無盡燈。", "我燈無盡易無盡，五行陰陽太極惟一心。", "東鄰有客好奇逸，袖出異書光芒與我易相射。", "平生但識羲孔元之元，不省虛皇大道玄中玄。", "我欲與君互酬答，各妙其妙勿以言語傳。", "會得易中極玄中玄，與子日日張燈作上元。"]'),
('2c4fe8b3-0b58-42d5-a9ca-e7857b8560cf','南至前一日蔣君伯祿携山谷草字來示上有南軒題跋亦南至前一日異哉','家鉉翁','宋','宋诗','song-poetry','','[]','羲之趁姿媚，魯公尚氣節。',96,'全唐诗/poet.song.221000.json','["羲之趁姿媚，魯公尚氣節。", "黄家妙畫兼數體，圜轉之中有卓絕。", "天涯明日一陽生，茅齋孤坐晝掩門。", "有客袖示三四紙，如覩天上五色雲。", "嗟余老矣豈能事書法，有會心處賞之不能輟。", "此書當與造化侔，生意浩然不可遏。"]'),
('eb9d8b7d-e12c-423a-944b-7b91112eb490','六月菊以夏中破萼至秋晚枝條雖蒼勁而花色灼然鮮明貫暑寒而不改菊中之貞士也余以比之商山四皓爲之賦','家鉉翁','宋','宋诗','song-poetry','','[]','九月菊偏與秋霜宜，六月不受炎暑欺。',213,'全唐诗/poet.song.221000.json','["九月菊偏與秋霜宜，六月不受炎暑欺。", "秋霜似同君子操，歲寒相遇長相好。", "暑不與貞士謀，楊燥怒煌如相仇。", "要之二菊所遭有難易，夏居其難秋若居其易。", "君不見當年秦焰焦中州，儒壇處處同荒丘。", "獨餘商山老人在，高卧林泉節不改。", "平生不識咸陽門，晚隨幣聘來漢京。", "欲興詩書談王道，再使風俗還歸治古淳。", "我評此花似此老，傲暑凌寒無不可。", "種之階庭今幾年，我自識花花識我。", "粵從夏五開敷到殘秋，更與黄花爲輩儔。", "嗟哉黄花非輩儔，老行難逐少年遊。", "此菊當爲菊中第一流。"]'),
('5d075134-dcd7-49f7-be17-9ec25fbd5c05','過沛題旅壁','家鉉翁','宋','宋诗','song-poetry','','[]','單呂早識隆準公，擇壻能得人中龍。',134,'全唐诗/poet.song.221000.json','["單呂早識隆準公，擇壻能得人中龍。", "云何託女不託宗，歡娛未了萬事空。", "沛人猶言令善相，善相如此術亦窮。", "高皇先識萬物表，芟刈羣雄如薙草。", "孽女近在目睫間，濫觴不戒使滔天。", "向非遺後餘此二三老，安知北軍袒右與袒左。", "嗟哉塗山啟夏任啟周，女德王功相匹休。", "令名堂堂照千古，不似沛中呂氏女。"]'),
('c6f62a6c-5829-413d-ac8e-7c7b894c0bbb','牡丹坪詩','家鉉翁','宋','宋诗','song-poetry','','[]','洛花古來稱第一，金爲之相玉爲質。',134,'全唐诗/poet.song.221000.json','["洛花古來稱第一，金爲之相玉爲質。", "畫堂深處養根荄，麗日光中見顔色。", "人力栽培儻未周，本然之天從而失。", "我家大峨峰頂牡丹坪，傲雪凌霜知幾春。", "冬深突兀層崖上，春來爛漫紅雲生。", "相傳皇人煉丹處，帝勅六丁爲守護。", "天葩只合奉天人，那許移根到下處。", "吁嗟皇人長與花爲主，世上紅紫紛紛何足數。"]'),
('3b1692e3-6ae6-4470-be21-656b552e544d','假館詩','家鉉翁','宋','宋诗','song-poetry','','[]','江南遺老瀛邊客，來時鬢斑今雪白。',243,'全唐诗/poet.song.221000.json','["江南遺老瀛邊客，來時鬢斑今雪白。", "幾年坐困市井塵，五遷來到詩書宅。", "中州典型尚未艾，故家文獻宛如昔。", "主人盛年兀老蒼，古心不爲名利役。", "晝閒對客無俗談，夜燈從容須挾冊。", "有疑必問問必中，講學定知有源脈。", "世人騖外如輪雲，君心向道堅金石。", "念我南冠久縶維，分我三間明月席。", "綈袍厚德更高古，冬有纖纊夏有綌。", "我衰擬作菟裘藏，感君推田城西陌。", "今年不歸明年復不歸，病骨嶔𡼭會當化爲原上骼。", "擬從諸君豫乞石一方，他年埋之塚前三四尺。", "上書宋使姓某其名某，下書人是西州之西老逢掖。", "平生著書苦不多，可傳者見之春秋與周易。"]'),
('d7ef7866-0b86-4e19-8750-8e35317bd95b','爲景山題','家鉉翁','宋','宋诗','song-poetry','','[]','先天而生者道之初，後天而存者道之壽。',222,'全唐诗/poet.song.221000.json','["先天而生者道之初，後天而存者道之壽。", "人能知道爲可貴，斯能與道同其久。", "粵從羲黄迄孔孟，大原千古垂不朽。", "書以道事萬化源，易以明理羣經首。", "詩三百所蔽思無邪，禮三千主敬內自守。", "我性其性天其天，念茲在茲謹所授。", "紛華過眼空中雲，綺麗墮前苗之莠。", "德人澄心制萬變，仁壽天爵我固有。", "福惟自求命自作，慾浄理明鑑無垢。", "勿貳以二參以三，環堵中間維道囿。", "存之又存悟本元，心與道一逢原在左右。", "惟茲皇覽揆度辰，臨陽浸長泰道亨。", "爲君大書湯盤九字銘，願君進德日新又新與歲而俱新。"]'),
('c0b12feb-037c-4328-bdee-5bc3c94d2834','聞楊和卿在館中讀易不去手贈以詩','家鉉翁','宋','宋诗','song-poetry','','[]','人人讀醫經，知尊黄與岐。',152,'全唐诗/poet.song.221000.json','["人人讀醫經，知尊黄與岐。", "楊子讀醫經，乃以羲文周孔而爲歸。", "易中有妙義，醫中之奧與易相表裏。", "六十四卦字字是心法，八十一篇篇篇具易理。", "神聖工巧莫向外邊求，潔凈精微只此本心是。", "君觀恒卦字之文，左心右日合而成。", "心體湛然絕纖翳，日新又新常惺惺。", "要之醫經本自易經出，前聖作之後聖述。", "子以醫心會易心，三部九候中間有太極。"]'),
('3162776e-4a6a-4bd0-987e-5feb19233dcc','伯成嘗受學于河朔前輩鶴鳴翁其學亦宗濂洛贈以詩勉其自拔于流俗','家鉉翁','宋','宋诗','song-poetry','','[]','南方共宗鶴山老，北方亦有鶴鳴翁。',134,'全唐诗/poet.song.221000.json','["南方共宗鶴山老，北方亦有鶴鳴翁。", "鶴山道脈接濂洛，鶴鳴之派應與鶴山同。", "九臯清聞猶歷耳，誰謂九原不可起。", "詵詵高弟今幾人，衣鉢傳來二三子。", "遺書定知滿筐箱，夜光煒煜照行李。", "在陰有鳴須有和，乘軒可貴未可喜。", "君不見遼東仙子丁令威，向神清而上刷羽儀。", "萬人拭目看孤飛，鳧鷖紛紛那能隨。"]'),
('49eb498d-3e15-46f1-a97e-4221418cbe64','九日偶成呈彥舉','家鉉翁','宋','宋诗','song-poetry','','[]','高陽今日是重陽，與客憑高送一觴。',128,'全唐诗/poet.song.221000.json','["高陽今日是重陽，與客憑高送一觴。", "白首相逢俱老大，黄花隨地看芬芳。", "故園三徑都荒了，目斷晴空歸路渺。", "人生暮景更天涯，眼中愁緒知多少。", "寒風蕭蕭吹我衣，酒闌莫遣帽簷欹。", "我歌老圃秋容句，君誦淵明歸去辭。", "我歌君和日欲夕，我醉君扶君須力。", "明年此會還相憶，江東暮雲千里隔。"]'),
('e42a5d83-7944-46a2-97d2-459c7d9d2fa8','贈談故人高鵬舉','家鉉翁','宋','宋诗','song-poetry','','[]','東鄰歌呼閙如市，西隣笙簫正鼎沸。',102,'全唐诗/poet.song.221000.json','["東鄰歌呼閙如市，西隣笙簫正鼎沸。", "高生擇術頗可人，夜闌挑燈說書史。", "說出忠臣烈士報國心，四座聞者爲墮淚。", "聞君年少曾讀書，壯大無成乃與優伶俱。", "左手執籥右秉翟，念到簡兮應嗟吁。", "他年了却官中呼，仍作書生挾冊歸里閭。"]'),
('26c355d4-10b1-4cfc-9ab5-cec6f36d4b27','贈河間隠者苑君年八十有一','家鉉翁','宋','宋诗','song-poetry','','[]','海上有三山，瀛洲居其一。',146,'全唐诗/poet.song.221000.json','["海上有三山，瀛洲居其一。", "何年飛來神州赤縣東，其上至今猶有神仙宅。", "龐眉皓首方瞳翁，喬松羨門乃其匹。", "深衣大带儒中仙，不讀黄庭讀周易。", "乾元用九獨探數之原，九九妙契乾策八十一。", "萬事萬物從此始，衍之又衍至於千百億。", "壽翁以金書玉籙長生符，不若壽翁以邵子先天周子一太極。", "梅邊生意浩無窮，坐閲人間蟠桃幾回實。"]'),
('3792e43f-9300-4d6b-972b-1d73f40dcde3','送陳真谷赴邢州幕','家鉉翁','宋','宋诗','song-poetry','','[]','嗟余仗節五寒暑，豈不欲歸迷歸路。',144,'全唐诗/poet.song.221000.json','["嗟余仗節五寒暑，豈不欲歸迷歸路。", "天涯獲識我輩人，乃是三生林壑侶。", "病身不死頼公藥，僦屋無人因公戶。", "蕭然一身水上萍，惟公爲我北道主。", "前晨除書到里門，雖爲公喜惜公去。", "明朝欲別更悽然，誰爲我依有文度。", "公身方健供時需，人生富貴在遲暮。", "衣錦歸來定何年，我帆已落吳松浦。", "再見便作來生期，臨分哽咽不得語。"]'),
('65567621-0573-4957-ad03-41f0bae7082d','陳子新前後十年叶贊府寮修明學政講堂成以詩美之','家鉉翁','宋','宋诗','song-poetry','','[]','子産存鄭校，僖公修泮宮。',239,'全唐诗/poet.song.221000.json','["子産存鄭校，僖公修泮宮。", "彼皆在其位，夫豈難爲功。", "是邦學政久墜地，過者千百但吁愾。", "有美君子逢掖生，無位乃能行其志。", "手披荆榛植棟宇，春秋祠事廼有所。", "衮章巍巍耀城闕，黌舍煌煌列籩俎。", "爾來幾及一星周，欲緒前功誰與主。", "治中別駕我輩人，惟君復能贊其成。", "大厦聿新來衆雋，講席備設招諸生。", "衆人所迂君所急，胸次抱負誰能識。", "後先幾年惟一心，興頹舉廢多其力。", "我來是邦知君久，負荷萬鈞綽其有。", "更從興學知君深，少覘用世經綸手。", "君不見新甫之柏徂徠松，可棟可楹皆在雪霜後。", "願培遠業待時需，令名與學千載垂不朽。"]'),
('74871311-0d0e-43f1-b5a6-fa4b42a5c791','朱信叔洛陽人往佐長安省幕','家鉉翁','宋','宋诗','song-poetry','','[]','洛陽中州中，長安中州雄。',186,'全唐诗/poet.song.221000.json','["洛陽中州中，長安中州雄。", "大山巨澤九土鎮，三光五嶽淑景通。", "君居洛南雅是溫石輩，今佐大幕全護咸秦衝。", "高懷頗堪陪坐嘯，逸氣直上干青空。", "籌帷暇日頻訪古，溪山好處須從容。", "秦宮漢苑久已成陳跡，寒烟茂樹倏忽迷西東。", "車鄰激壯滿汧渭，周雅博大基鎬豐。", "請君收取入筆硯，可以陶寫詩書胸。", "由秦而西是爲入蜀道，乘興一登岷峨矗天峯。", "我家正住岷峨下，定有鄉人故老諏衰蹤。", "爲言仗節瀛海上，齒髮衰謝氣如虹。"]'),
('873413f1-df12-402d-8938-52c931799841','劉文蔚久苦目眚昨日乘凉來過共談先天圖義一夕翳去明現閭里以爲異事因詩紀之','家鉉翁','宋','宋诗','song-poetry','','[]','心以靜而虛，眼以動而應。',268,'全唐诗/poet.song.221000.json','["心以靜而虛，眼以動而應。", "心如明月懸太空，眼如當戶掛清鏡。", "月光不受微雲干，鏡光或爲塵土暝。", "學問之道貴澄源，源之既澄流自正。", "但令心體常如月體明，寒風暑暄豈能爲我病。", "吾友平生讀書眼，炯然不與事物競。", "外圜偶被輕埃薄，靈府不摇中自定。", "杜門息交踰三旬，强本勝邪在一靜。", "昨日扶杖過我蝸角廬，共談壁上先天內外圖。", "窮探羲孔象中意，不與異說論懸殊。", "高談亹亹竟日暮，睛光灧灧生清矑。", "夜歸不煩炬火照，入門索觀細字書。", "晨興宿霧盡掃却，銀海爛爛可以貫碧虛。", "神耶天耶孰能詰，心耶眼耶萬變同一樞。", "里人共傳先生有良劑，爭持病目求我滌懵瞇。", "先生無藥亦無方，請將心來爲君洗。"]'),
('bd1787a8-6184-4bbf-8b93-af2da54d3c08','贈雲山逸人劉巨川瞽而談命','家鉉翁','宋','宋诗','song-poetry','','[]','世人具眼知多少，見山不知雲山好。',123,'全唐诗/poet.song.221000.json','["世人具眼知多少，見山不知雲山好。", "斯人背境自觀心，識破雲山千萬層。", "須知萬物備於我，高下散殊何往而非道。", "善觀物者觀以心，目所未見心已瞭。", "聞君學易多歷年，妙處能探造化先。", "維艮之背不與事物對，物具一極常與此心會。", "君知雲山雲山亦知君，是之謂行其庭不見其人。"]'),
('8fc9f017-8448-4387-9f86-307d703335a7','贈談命王逸民','家鉉翁','宋','宋诗','song-poetry','','[]','逸民古稱避世士，不以功名累其意。',120,'全唐诗/poet.song.221000.json','["逸民古稱避世士，不以功名累其意。", "有人向彼話窮通，拂衣歸來洗其耳。", "君字逸民見君心，云胡乃以談天爲己事。", "要令世間競進人，稍知山林巖壑味。", "吁嗟逸民莫學商山翁，商山卒爲三聘起。", "成都卜隠老君平，身處澗槃名聲動朝市。", "案頭周易是本經，未來千載瞭然在胸次。"]'),
('a10f01db-fae8-4ffc-bff8-e23860b384b0','歲暮傳易終成長吟書送景山茂實','家鉉翁','宋','宋诗','song-poetry','','[]','易乎易，萬古傳來惟一易。',176,'全唐诗/poet.song.221000.json','["易乎易，萬古傳來惟一易。", "羲文之心即是周孔心，問誰要於心外尋脚跡。", "畫之前，妙處難爲言。", "畫之後，乾坤實居萬化先。", "誰將乾坤大父母，下與五十六卦爲等伍。", "既道先天一字無，云何却以後天混入先天圖。", "嗟吁平生粗知讀周易，只向本本原原認太極。", "一易之外更無之，嗟哉何人更以三爲七。", "欲知玄，問子雲。", "欲知包，問子平。", "欲知筮，當叩焦與京。", "要識乾坤真面目，請將四聖之經閉戶十年讀。"]'),
('719a7119-28e9-43e6-8217-01b4cd46f19f','謝舜元以墨竹爲贈','家鉉翁','宋','宋诗','song-poetry','','[]','我家苕源山深處，萬竹森森飽風雨。',164,'全唐诗/poet.song.221000.json','["我家苕源山深處，萬竹森森飽風雨。", "一從脚踏黄沙堆，不見此君四寒暑。", "夜來有夢到家山，蒼筠翠榦猶依然。", "覺來欲賦不得賦，誰能爲我傳其天。", "東鄰蕭然歲寒客，寓意於物無留跡。", "當年親識洋州孫，寫得寒梢數千尺。", "憐我卧疴少佳悰，卷送四壁泠然風。", "筆端妙處奪天巧，與我胸中生意俱無窮。", "高陽臺下見此兩奇特，子新之梅舜元竹。", "後先俱爲洞山來，夜夜白虹貫茅屋。"]'),
('f0e0a2e0-0ea1-4350-8957-efa319f9a25c','謝劉仲寬惠茶','家鉉翁','宋','宋诗','song-poetry','','[]','憶昨中原全盛時，五方貢茶走京師。',194,'全唐诗/poet.song.221000.json','["憶昨中原全盛時，五方貢茶走京師。", "建溪頭綱最先到，天子特命開經闈。", "儒臣講畢上命坐，瀹茗初試瓊甌甆。", "雲章昭回耀几席，羣公進謝因進規。", "我生也後不及見，耳聞盛事長嗟咨。", "十年流落古瀛下，誰謂荼苦甘如飴。", "蓬山偉人國俊彥，哀此下土南冠羈。", "肯分錫賫賁衰朽，定知眷奬超凡私。", "公才雅在嚴徐右，公學獨出河汾師。", "穹班近聞長祕府，奎壁分野生光輝。", "儒臣見用天下福，講席宏開太平期。", "蒼崖赤子望蘇息，霖雨八荒捨公而其誰。"]'),
('3e73f48e-0cac-4848-8fef-4a791836fe8a','爲旃檀像賦','家鉉翁','宋','宋诗','song-poetry','','[]','稽首古旃檀，曾共釋迦語。',183,'全唐诗/poet.song.221000.json','["稽首古旃檀，曾共釋迦語。", "旃檀釋迦面目本來同，真身幻身何事相爾汝。", "如人對鏡照形像，拱兮揖兮若賓主。", "須臾人去鏡亦空，爾影我形兩無覩。", "木人漂流宇宙間，神通妙用歸何許。", "萬人從渠索釋迦，求福有時與福遇。", "佛如明月行太空，向曙俄然不知處。", "癡人競向波間覓，波間本非月所住。", "真邪幻邪兩忘言，如來無來亦無去。", "君不見佛書九譯來中原，妙處乃以無言傳。", "莫道旃檀有口不解說，非說之說三十二相全。"]'),
('46f2a2c7-f635-4cd1-ad9b-e4febea15750','見星行贈武春卿','家鉉翁','宋','宋诗','song-poetry','','[]','天星之熒熒兮，歷幾千萬年光景常如新。',247,'全唐诗/poet.song.221000.json','["天星之熒熒兮，歷幾千萬年光景常如新。", "人心之存存兮，特宇宙一粟粒乃能與天星同其明。", "天象此以爲象兮，維實理之著見。", "人心此以爲心兮，乃妙用之流行。", "微雲去來等妄幻，本體湛虛絕纖塵。", "是故善觀心者感星而自悟，境與心會不知星之爲我我之爲星。", "嗟爾甘石氏之爲學，仰測璇象若尺之有寸寸之有分。", "但能以常數而窺陳跡，不能外躔郭而探造化之所以神。", "我欲與君陵太虛而步碧落，稽首再拜謁帝庭。", "仰瞻天辰上曜之正色，次閲蒼龍赤鳥兔龜形。", "願求天光灑我昏濁質，使我自心圜明瑩徹，會萬象而涵太清。", "歸來跳出陰陽五行外，初筮再三閉口勿復論。"]'),
('8b49de81-a02d-4ff0-ab74-0d753a191af4','寄洞霄道友清溪翁','家鉉翁','宋','宋诗','song-poetry','','[]','漢家中郎年七十，霜鬢垂垂人不識。',160,'全唐诗/poet.song.221000.json','["漢家中郎年七十，霜鬢垂垂人不識。", "冬深破屨踏層冰，暑到露頭走赤日。", "窮堅老壯本分事，百年未死爲形役。", "洞天九鎖鬰嵯峨，古來相傳神仙宅。", "我嘗結茅天柱前，屐齒蒼苔印行跡。", "劫火洞然城郭非，清境不壞還如昔。", "安期羨門我輩人，圓嶠方壺一咫尺。", "夢魂幾度如相逢，別來已久知相憶。", "願分仙家九轉丹，服之身輕生羽翼。", "周遊八表任去來，跳出陰陽寒暑域。"]'),
('bc0c7e23-5d2e-4b08-a90d-77737e76c3c7','前歲上元與趙任卿寓臨安追逐甚樂今年同在建溪任卿先赴郡席小雪忽作且知早筵遂散獨坐無聊因得二詩却寄  其一','家鉉翁','宋','宋诗','song-poetry','','[]','山城燈火已蕭然，掃巷遊人更雪天。',64,'全唐诗/poet.song.221000.json','["山城燈火已蕭然，掃巷遊人更雪天。", "厭聽落梅翻永夜，喜看飛絮卜豐年。", "狂隨戲蝶裝羅髻，巧逐纖腰上舞筵。", "明日瑶階對瓊樹，會須微月與爭妍。"]'),
('4c6824ca-513e-452a-abc3-6ad38e017082','前歲上元與趙任卿寓臨安追逐甚樂今年同在建溪任卿先赴郡席小雪忽作且知早筵遂散獨坐無聊因得二詩却寄  其二','家鉉翁','宋','宋诗','song-poetry','','[]','沙河紅燭暮爭然，花市清簫夜徹天。',64,'全唐诗/poet.song.221000.json','["沙河紅燭暮爭然，花市清簫夜徹天。", "客舍風光如昨夢，帝城歌酒又經年。", "老僧强作琉璃供，上客先逢玳瑁筵。", "不許裴郎同夜飲，新粧月底爲誰妍。"]'),
('d3291fa8-46d4-4531-aa7d-049c652e0c33','和唐壽隆上元三首  其一','家鉉翁','宋','宋诗','song-poetry','','[]','滿城和氣在春臺，玉漏沉沉鐵鎖開。',64,'全唐诗/poet.song.221000.json','["滿城和氣在春臺，玉漏沉沉鐵鎖開。", "明月誰知千里共，華燈同照萬人來。", "市橋未漲丰容柳，江路猶殘的皪梅。", "欲與先生拚醉賞，未須歸去隠蒿萊。"]'),
('9c2c69c0-851d-4ed1-b383-1d332de6c4fb','和唐壽隆上元三首  其二','家鉉翁','宋','宋诗','song-poetry','','[]','明月升天鏡上臺，燈如蓮沼萬枝開。',64,'全唐诗/poet.song.221000.json','["明月升天鏡上臺，燈如蓮沼萬枝開。", "恨無立部歌仍舞，空有遊人往更來。", "秀如王子登門竹，味勝曹公止渴梅。", "已向歌謠挹和氣，預知豐歲變汙萊。"]'),
('6f575cf9-cf0c-4363-aaf3-99e4611598ad','和唐壽隆上元三首  其三','家鉉翁','宋','宋诗','song-poetry','','[]','幾年蹤跡遠中臺，夢想傳柑宴斚開。',64,'全唐诗/poet.song.221000.json','["幾年蹤跡遠中臺，夢想傳柑宴斚開。", "懶擁牙旗穿市去，縱看玉李墮天來。", "從教獨照青藜炬，莫使輕吹畫角梅。", "也有江風浮彩巘，坐令形勢卷東萊。"]'),
('267144d3-a8c2-4642-860d-0ac0d8d1e61c','題渤海高夫人行實','家鉉翁','宋','宋诗','song-poetry','','[]','當年初賦柏舟詩，正是中原板蕩時。',64,'全唐诗/poet.song.221000.json','["當年初賦柏舟詩，正是中原板蕩時。", "手挾雛孤歷關險，身邊鴈影到天涯。", "五遷纔定霜侵鬢，百歲何曾笑展眉。", "爲報兒孫須努力，墓前他日要豐碑。"]'),
('dc587012-f86b-4a10-b1dc-ab53995ba320','挽劉文蔚  其一','家鉉翁','宋','宋诗','song-poetry','','[]','五年瀛下寄閒身，耐久交朋喜有君。',64,'全唐诗/poet.song.221000.json','["五年瀛下寄閒身，耐久交朋喜有君。", "竟日坐談唯在道，有時遊戲亦論文。", "高風每欲追鵬運，雅志那能混鶩羣。", "留得浩然英氣在，便將生死付朝曛。"]'),
('1d6025c0-cee0-4269-829b-ba3e7836123b','挽劉文蔚  其二','家鉉翁','宋','宋诗','song-poetry','','[]','先天妙義說來多，聖處工夫幾切磋。',64,'全唐诗/poet.song.221000.json','["先天妙義說來多，聖處工夫幾切磋。", "一點英靈長不昧，平生學力定難磨。", "暮春風景堪聞瑟，塵世紛華付擲梭。", "聞道南行緣底事，要從濂洛溉餘波。"]'),
('e72c78e1-86dc-4cb6-8146-d358f5f0a2be','九日登瀛臺','家鉉翁','宋','宋诗','song-poetry','','[]','此地無山喜有臺，南瞻北眺兩宜哉。',64,'全唐诗/poet.song.221000.json','["此地無山喜有臺，南瞻北眺兩宜哉。", "衰翁無事日傾倒，佳客何人時一來。", "孤鶴飛鳴知我在，征鴻嘹唳爲誰哀。", "老來萬事如歸宿，不爲憂愁强把杯。"]'),
('d5f1f690-f8b3-495f-acad-6f861d0d9e1e','西州舊俗每當立春前後以巢菜作餠互相招邀名曰東坡餠頃在燕嘗有詩云西州最重眉山餠冬後春前無別羞今度燕山試收拾中間惟欠一元修元修即巢菜之別號蓋豌豆菜也東坡故人巢元修嘗致其種於黄岡下因得名元修南方有之燕中無此種余來河間再見立春感舊事用前韻  其一','家鉉翁','宋','宋诗','song-poetry','','[]','朔風吹我過瀛州，釜甑生塵轉可羞。',32,'全唐诗/poet.song.221000.json','["朔風吹我過瀛州，釜甑生塵轉可羞。", "聊向春前尋故事，定知食餠記前修。"]'),
('755866d5-0fc7-4e7a-9cc9-db8bb907750f','西州舊俗每當立春前後以巢菜作餠互相招邀名曰東坡餠頃在燕嘗有詩云西州最重眉山餠冬後春前無別羞今度燕山試收拾中間惟欠一元修元修即巢菜之別號蓋豌豆菜也東坡故人巢元修嘗致其種於黄岡下因得名元修南方有之燕中無此種余來河間再見立春感舊事用前韻  其二','家鉉翁','宋','宋诗','song-poetry','','[]','我家自貴東坡餠，不爲人間肉食羞。',32,'全唐诗/poet.song.221000.json','["我家自貴東坡餠，不爲人間肉食羞。", "聞道西山薇蕨長，摘來我可輩元修。"]'),
('808d6c62-1a5d-40a4-b6b7-7f4156145ca3','西州舊俗每當立春前後以巢菜作餠互相招邀名曰東坡餠頃在燕嘗有詩云西州最重眉山餠冬後春前無別羞今度燕山試收拾中間惟欠一元修元修即巢菜之別號蓋豌豆菜也東坡故人巢元修嘗致其種於黄岡下因得名元修南方有之燕中無此種余來河間再見立春感舊事用前韻  其三','家鉉翁','宋','宋诗','song-poetry','','[]','凄凉如在黄岡下，苦淡從教鄰壁羞。',32,'全唐诗/poet.song.221000.json','["凄凉如在黄岡下，苦淡從教鄰壁羞。", "擬向城隅問耕稼，鋤犂闕壞不堪修。"]'),
('4affa41e-2b6d-4fba-8e4b-c5c4e936a751','春欲暮雪作不已簡子新  其一','家鉉翁','宋','宋诗','song-poetry','','[]','一任西園雪作堆，陽和已自徧根荄。',32,'全唐诗/poet.song.221000.json','["一任西園雪作堆，陽和已自徧根荄。", "春光只在花梢裏，更倩君詩爲一催。"]'),
('16dd61f9-effa-47f9-8d21-877f82d657e7','春欲暮雪作不已簡子新  其二','家鉉翁','宋','宋诗','song-poetry','','[]','社後春光正可人，眼中物物露精神。',32,'全唐诗/poet.song.221000.json','["社後春光正可人，眼中物物露精神。", "雪花底事猶飛舞，要與梨花分半春。"]'),
('4c22dd19-6cb8-40de-a12e-51a21d3670c7','春欲暮雪作不已簡子新  其三','家鉉翁','宋','宋诗','song-poetry','','[]','乍暖輕寒春正深，晚雲猶解作同雲。',32,'全唐诗/poet.song.221000.json','["乍暖輕寒春正深，晚雲猶解作同雲。", "從教門外雪三尺，認取沂邊春十分。"]'),
('b8aa4e6f-8947-4af9-8e64-896a0e911313','春欲暮雪作不已簡子新  其四','家鉉翁','宋','宋诗','song-poetry','','[]','庭前草色渾未露，塢外桃花肯破顔。',32,'全唐诗/poet.song.221000.json','["庭前草色渾未露，塢外桃花肯破顔。", "七十日春閒過了，半分春色尚猶慳。"]'),
('9616dcab-00d0-4cbb-a766-6acc474f1ef5','春欲暮雪作不已簡子新  其五','家鉉翁','宋','宋诗','song-poetry','','[]','和平心事春三月，淡泊生涯水一杯。',32,'全唐诗/poet.song.221000.json','["和平心事春三月，淡泊生涯水一杯。", "老矣只餘歸夢在，世間萬事付心灰。"]'),
('b4e9bc22-5035-441e-85bf-869289612d22','中秋月蝕邦人鳴鉦救月不約而齊中原舊俗猶有存者感而有作  其一','家鉉翁','宋','宋诗','song-poetry','','[]','風掃沈陰萬象開，斷雲扶月出陽臺。',32,'全唐诗/poet.song.221000.json','["風掃沈陰萬象開，斷雲扶月出陽臺。", "萬人拭目看天眼，蟇蝕何曾蝕得來。"]'),
('f67b020a-27e9-4a86-8076-2f04af5f4ff2','中秋月蝕邦人鳴鉦救月不約而齊中原舊俗猶有存者感而有作  其二','家鉉翁','宋','宋诗','song-poetry','','[]','大化周流不暫停，從來息處見其生。',32,'全唐诗/poet.song.221000.json','["大化周流不暫停，從來息處見其生。", "冰輪萬古長如此，本體何曾有晦明。"]'),
('fd0675a7-be18-40d9-8f68-29b7e4ab3f58','中秋日菊盛開  其一','家鉉翁','宋','宋诗','song-poetry','','[]','蓓蕾黄花當徑開，朣朧佳月出雲來。',32,'全唐诗/poet.song.221000.json','["蓓蕾黄花當徑開，朣朧佳月出雲來。", "中秋見菊從前少，端爲瀛公詩句催。"]'),
('e19df813-1750-4f2c-bfda-26ff8aaf64bc','中秋日菊盛開  其二','家鉉翁','宋','宋诗','song-poetry','','[]','天宇高寒露欲零，城頭月色正亭亭。',32,'全唐诗/poet.song.221000.json','["天宇高寒露欲零，城頭月色正亭亭。", "諸公定有驚人句，施與波神月下聽。"]'),
('22e7ec91-8745-4909-8c49-9536d6bde403','中秋日菊盛開  其三','家鉉翁','宋','宋诗','song-poetry','','[]','年年菊占晚秋清，今夕東籬放早英。',32,'全唐诗/poet.song.221000.json','["年年菊占晚秋清，今夕東籬放早英。", "月共黄花如有約，花開半夜月偏明。"]'),
('1d68e4e0-920a-4b9a-8971-9736f9049872','九日即事雪中見菊  其一','家鉉翁','宋','宋诗','song-poetry','','[]','瀛海茫茫又晚秋，瀛山漠漠幾浮漚。',32,'全唐诗/poet.song.221000.json','["瀛海茫茫又晚秋，瀛山漠漠幾浮漚。", "人間底事登高處，來上元龍百尺樓。"]'),
('c1414749-e560-48be-bbd8-8e850febd7f8','九日即事雪中見菊  其二','家鉉翁','宋','宋诗','song-poetry','','[]','怪得西風吹袂凉，客中又過一重陽。',32,'全唐诗/poet.song.221000.json','["怪得西風吹袂凉，客中又過一重陽。", "今年喜見東籬雪，要與黄花共晚香。"]'),
('0639b196-b287-4d71-b52a-58fec09a5131','九日即事雪中見菊  其三','家鉉翁','宋','宋诗','song-poetry','','[]','九月黄花正是時，誰催青女試瑰琦。',32,'全唐诗/poet.song.221000.json','["九月黄花正是時，誰催青女試瑰琦。", "冰天雪夜無人問，玉質金相我自知。"]'),
('41b33d23-a953-4d6b-8817-13dd28479c58','晚步','家鉉翁','宋','宋诗','song-poetry','','[]','閉門自要身心斂，出戶方知天地寬。',32,'全唐诗/poet.song.221000.json','["閉門自要身心斂，出戶方知天地寬。", "晚步中庭人不識，道余癡想白雲端。"]'),
