('f6f7355a-84c4-48c4-9e0f-665a95d25ec1','詠紅梨花','家鉉翁','宋','宋诗','song-poetry','','[]','萬玉林中慣識君，霜天月夜富精神。',32,'全唐诗/poet.song.221000.json','["萬玉林中慣識君，霜天月夜富精神。", "誰將紅粉涴顔色，却與夭桃鬭莫春。"]'),
('d53dd2e5-0dd7-4ac1-81be-01103e9446e3','人有畫花中四倫者偶記毗陵舊詩即題其上  其一','家鉉翁','宋','宋诗','song-poetry','','[]','萬紅深處一花王，猶带姚家宮樣黄。',32,'全唐诗/poet.song.221000.json','["萬紅深處一花王，猶带姚家宮樣黄。", "物物有君還有佐，殿春須屬召公棠。"]'),
('db9bc74f-a7b7-48f8-8c34-1581aae7cf3f','人有畫花中四倫者偶記毗陵舊詩即題其上  其二','家鉉翁','宋','宋诗','song-poetry','','[]','扶疎桂樹月中生，誰遣人間伴大椿。',32,'全唐诗/poet.song.221000.json','["扶疎桂樹月中生，誰遣人間伴大椿。", "桂欲芳時椿正老，等閒相伴八千春。"]'),
('ae665e67-85dd-44fb-83d5-32c1855b00fa','人有畫花中四倫者偶記毗陵舊詩即題其上  其三','家鉉翁','宋','宋诗','song-poetry','','[]','佩玉垂紳廊廟人，幽花小草豈其倫。',32,'全唐诗/poet.song.221000.json','["佩玉垂紳廊廟人，幽花小草豈其倫。", "須知四海皆兄弟，淡泊論交處處親。"]'),
('7c531f41-3a69-4230-af3e-66df41b906a2','人有畫花中四倫者偶記毗陵舊詩即題其上  其四','家鉉翁','宋','宋诗','song-poetry','','[]','夭桃艷杏得春饒，澗草林花品亦殽。',32,'全唐诗/poet.song.221000.json','["夭桃艷杏得春饒，澗草林花品亦殽。", "誰似三君丈人行，萬山深處自論交。"]'),
('fd3d9bbb-0fac-4e84-acb3-0dcbf4792a84','寄江南故人','家鉉翁','宋','宋诗','song-poetry','','[]','曾向錢唐住，聞鵑憶蜀鄉。',24,'全唐诗/poet.song.221000.json','["曾向錢唐住，聞鵑憶蜀鄉。", "不知今夕夢，到蜀到錢唐。"]'),
('31315cfc-ec4d-4b46-8c2f-f27d4a0296c5','題梅竹圖','家鉉翁','宋','宋诗','song-poetry','','[]','余家乎岷之下兮，有梅蕭蕭，有竹森森。',88,'全唐诗/poet.song.221000.json','["余家乎岷之下兮，有梅蕭蕭，有竹森森。", "今洎乎瀛之野兮，秋草萋萋，黄沙冥冥。", "有懷彼美兮在天一垠，夢不可即兮聊因其似而記其真。", "真兮似兮，豈墨君筆史之可尋。", "皓兮蒼兮，吾獨想其歲寒之心。"]'),
('06cab19e-a45f-46a1-8dfb-5ebcad29b25f','題雪花達摩布衣偈','家鉉翁','宋','宋诗','song-poetry','','[]','拈花公案且莫道，西來正被拈花惱。',96,'全唐诗/poet.song.221000.json','["拈花公案且莫道，西來正被拈花惱。", "一花開後幾花開，微笑不禁成絕倒。", "歸去來，人未老，掉下從前舊草鞋。", "衲被蒙頭面壁坐，提起不直一落索。", "放下大地無處著，從來被他礙手脚。", "爲君索火當街燒，布袋依前是彌勒。"]'),
('7f651fb3-096a-4a9d-adc6-f21eba627998','鳴絃齋','家鉉翁','宋','宋诗','song-poetry','','[]','徽金軫玉七絃存，流水音中政事分。',32,'全唐诗/poet.song.221000.json','["徽金軫玉七絃存，流水音中政事分。", "直自武城曾聽後，至今方始得重聞。"]'),
('5f368b53-1182-43fc-aff1-5e5c14d1dc88','鯨川八景 東城春早','家鉉翁','宋','宋诗','song-poetry','','[]','陽回冰底見雲堆，春意東來梅已知。',32,'全唐诗/poet.song.221000.json','["陽回冰底見雲堆，春意東來梅已知。", "待得東城花柳放，早春已是得春遲。"]'),
('481aee6a-982d-404a-9d7f-8e431992f588','鯨川八景 西園秋暮','家鉉翁','宋','宋诗','song-poetry','','[]','九九中間易道在，天心惟許菊花知。',32,'全唐诗/poet.song.221000.json','["九九中間易道在，天心惟許菊花知。", "一年好景君須識，都在西園把菊時。"]'),
('0554ccc4-3e52-4c15-a27c-31d545968102','鯨川八景 冰岸水燈','家鉉翁','宋','宋诗','song-poetry','','[]','華燈萬炬照沉淵，移得星辰下九天。',32,'全唐诗/poet.song.221000.json','["華燈萬炬照沉淵，移得星辰下九天。", "莫言燃犀當日事，川靈今夜亦歡然。"]'),
('bfb4cff7-b61e-4592-a495-6dc57211b512','鯨川八景 沙堤風柳','家鉉翁','宋','宋诗','song-poetry','','[]','突兀長堤一望問，幾人東去復西還。',32,'全唐诗/poet.song.221000.json','["突兀長堤一望問，幾人東去復西還。", "堤邊日日辦迎送，風自翩翻柳自閑。"]'),
('ae1f77f2-48a9-47d3-8657-cb23199fed53','鯨川八景 戍樓殘照','家鉉翁','宋','宋诗','song-poetry','','[]','盧龍久已屬神州，誰認歌樓作戍樓。',32,'全唐诗/poet.song.221000.json','["盧龍久已屬神州，誰認歌樓作戍樓。", "莫說關頭興廢事，江山猶有石郎羞。"]'),
('94002bca-f5e9-4af9-8e3a-c65dfbaa0234','鯨川八景 客船晚煙','家鉉翁','宋','宋诗','song-poetry','','[]','去棹來帆一聚塵，箇中那復有詩情。',32,'全唐诗/poet.song.221000.json','["去棹來帆一聚塵，箇中那復有詩情。", "晚來應是盧仝過，留得茶煙一抹橫。"]'),
('518f61c5-2d9c-4fdc-add9-c8654375a475','鯨川八景 蓮塘雨聲','家鉉翁','宋','宋诗','song-poetry','','[]','贏得荷風伴晚凉，夜闌急雨到陂塘。',32,'全唐诗/poet.song.221000.json','["贏得荷風伴晚凉，夜闌急雨到陂塘。", "茅簷似減三分暑，鼻觀俄然失却香。"]'),
('cd052124-ba76-4d75-8bbd-4f48f46286f7','九日登瀛臺和昔人韻二首','家鉉翁','宋','宋诗','song-poetry','','[]','屋角東邊十仞臺，龍蟠虎踞亦奇哉。',64,'全唐诗/poet.song.221000.json','["屋角東邊十仞臺，龍蟠虎踞亦奇哉。", "四時長是几案物，九日仍煩杖屨來。", "樂事無窮誰共管，孤雲在望我堪哀。", "夢隨鴻鵠南飛去，岑下長號酹一杯。"]'),
('a77ff013-6668-4408-be31-0490e4b39a21','寂照石佛','家鉉翁','宋','宋诗','song-poetry','','[]','溪上石人何往矣，山中石佛是其疇。',32,'全唐诗/poet.song.221000.json','["溪上石人何往矣，山中石佛是其疇。", "若教石佛能談妙，應有石人來點頭。"]'),
('7be78ee0-85aa-455a-af6b-a4c21a4fec04','宿半塘寺','趙與訔','宋','宋诗','song-poetry','','[]','夜宿半塘寺，惟聞塔上鈴。',48,'全唐诗/poet.song.221000.json','["夜宿半塘寺，惟聞塔上鈴。", "老僧行道影，童子頌經聲。", "竹密風猶勁，窗幽月愈明。", "瓦爐香斷處，一榻灑然清。"]'),
('f25ae5f6-bbd7-4d3d-b69c-dd8af3ba3760','句','吳釿','宋','宋诗','song-poetry','','[]','阮籍摩挲青眼舊，鄒陽感慨白頭新。',16,'全唐诗/poet.song.221000.json','["阮籍摩挲青眼舊，鄒陽感慨白頭新。"]'),
('1f995404-ad10-4134-af03-46406b229be3','遊道巖觀  其一','鄧希恕','宋','宋诗','song-poetry','','[]','乘雲不到玉皇家，巖上仙桃幾度花。',32,'全唐诗/poet.song.221000.json','["乘雲不到玉皇家，巖上仙桃幾度花。", "今日喜偕三益友，看來丹竈煉黄芽。"]'),
('fc209c83-f71e-4943-8a20-a4981d3dc863','遊道巖觀  其二','鄧希恕','宋','宋诗','song-poetry','','[]','石敲新火煮雲腴，細講濂溪太極圖。',32,'全唐诗/poet.song.221000.json','["石敲新火煮雲腴，細講濂溪太極圖。", "此去不知千載後，有人來講此圖無。"]'),
('edc69b98-87e2-49f4-bc38-0f6cc9a0e6b8','句','鄧希恕','宋','宋诗','song-poetry','','[]','龜鶴與羣同壽雋，貂蟬相映半時賢。',16,'全唐诗/poet.song.221000.json','["龜鶴與羣同壽雋，貂蟬相映半時賢。"]'),
('f474c70f-f927-4796-9fe7-d6d03b348721','汎沅湘闚九疑寄題江華杜□杳重建寒亭','徐銓孫','宋','宋诗','song-poetry','','[]','山水因人勝，窮搜喜得君。',48,'全唐诗/poet.song.221000.json','["山水因人勝，窮搜喜得君。", "石根瞿令字，亭背次山文。", "湍激堪臨渴，松陰可避曛。", "相望餘一舍，猛□杖□雲。"]'),
('0b4a7ce2-e7fe-4683-a7d0-ea690a3d7225','挽故知容州朝請陶公章二首  其一','危驂','宋','宋诗','song-poetry','','[]','今代平塘老，前身靖節翁。',48,'全唐诗/poet.song.221000.json','["今代平塘老，前身靖節翁。", "直心行杲日，清德照寒空。", "樂道簞瓢外，歸真軀殻中。", "政應高扁墓，百世使聞風。"]'),
('1ef4ac23-9c48-45e9-96a8-53f6cd6022c1','挽故知容州朝請陶公章二首  其二','危驂','宋','宋诗','song-poetry','','[]','巴陵三載掾，太半並棠陰。',48,'全唐诗/poet.song.221000.json','["巴陵三載掾，太半並棠陰。", "僕守濂溪訓，公推靖獻心。", "迨更深夜簀，茹納惜時金。", "引領西山路，天風淚滿襟。"]'),
('e0994e2a-ee69-4e77-badf-7b4f705419dc','鄉飲酒倡和詩','曾穎茂','宋','宋诗','song-poetry','','[]','異席賓階愧上西，喜觀微俗頓風移。',64,'全唐诗/poet.song.221000.json','["異席賓階愧上西，喜觀微俗頓風移。", "一堂酬酢古冠屨，千里循良世鼎彝。", "詩繼紹興賢守句，教明直講太平儀。", "遼遼曠典今重舉，從此愚夫可與知。"]'),
('3d49eff6-523b-4cdb-987d-da4360571d23','讀明妃引','陳僴','宋','宋诗','song-poetry','','[]','驪山舉燧因褒姒，蜀道蒙塵爲太真。',32,'全唐诗/poet.song.221000.json','["驪山舉燧因褒姒，蜀道蒙塵爲太真。", "能遣明妃嫁夷狄，畫工原是漢忠臣。"]'),
('819d6043-3ae1-46e8-9ae5-66016f394760','□韻呈徐□勘□□□','杜汪','宋','宋诗','song-poetry','','[]','規廣前賢迹，相期幸有君。',48,'全唐诗/poet.song.221000.json','["規廣前賢迹，相期幸有君。", "搜奇辱佳句，紀實待高文。", "古木風長悄，陰崖日易曛。", "何時陪勝賞，舉手上霄雲。"]'),
('ff023867-6ed2-46b4-a4bc-d5803576cc3b','集杜工部句詠寒亭','杜汪','宋','宋诗','song-poetry','','[]','湖南清絕地，長夏想爲情。',48,'全唐诗/poet.song.221000.json','["湖南清絕地，長夏想爲情。", "六月風日冷，炎天冰雪生。", "蓬萊如可到，心迹喜雙清。", "去郭軒楹敞，幽居不用名。"]'),
('87dcbd1c-7298-4baf-9e8b-fac3b333702c','集工部句題暖谷','杜汪','宋','宋诗','song-poetry','','[]','作尉窮谷僻，官高何足論。',24,'全唐诗/poet.song.221000.json','["作尉窮谷僻，官高何足論。", "溫溫有風味，憶昔李公存。"]'),
('76ad3f40-4180-415c-9ad9-562e689cf385','促織歌','賈似道','宋','宋诗','song-poetry','','[]','新蟲調理要相當，殘暑盆窩須近凉。',288,'全唐诗/poet.song.221000.json','["新蟲調理要相當，殘暑盆窩須近凉。", "漸到秋深畏風冷，不宜頻浴恐防傷。", "養時盆罐須寬闊，下食依時要審詳。", "水食調勻蛩必旺，看時切莫對陽光。", "水時併盡方堪鬭，不可傷饑患飽忙。", "盆內土須蚯蚓糞，相宜蓋爲按陰陽。", "如此宿蟲無姤色，仍將宿水換新漿。", "假如草葉供蟲嚙，齒軟仍知牙更僵。", "過籠窩罐安排固，行動提携總不妨。", "酒後切忌將來看，壯氣沖傷走跳狂。", "誤放橘橙充食物，食之蟲腹反爲殃。", "安頓必須清凈處，油烟熏損不剛强。", "過期未鬭頻頻看，仍復收拾用意藏。", "倘或打食口齒謾，必須醫損按前方。", "不察强弱當場鬭，必是遭輸笑不良。", "蓋盆謹慎休留隙，免使奔逃意下慌。", "看取調養依斯譜，蟲體無傷齒更剛。", "堪憐一種清幽物，歲歲三秋聲韻長。"]'),
('e62ef982-2c10-49a1-a19a-3d7559775be1','論形','賈似道','宋','宋诗','song-poetry','','[]','鉗象蜈蚣鉗，嘴象獅子嘴。',37,'全唐诗/poet.song.221000.json','["鉗象蜈蚣鉗，嘴象獅子嘴。", "頭象蜻蜓頭，腿象蚱蜢腿。", "顔色要相當，毛張栻斯爲美。"]'),
('18d9d4db-6d22-4eab-8d98-1678611ed5f6','論頭  其一','賈似道','宋','宋诗','song-poetry','','[]','大頭圓結菢，腦搭淺無多。',24,'全唐诗/poet.song.221000.json','["大頭圓結菢，腦搭淺無多。", "絲路根根透，光明亮不摩。"]'),
('d0171103-0145-4bef-8483-f8f0433cbbee','論頭  其二','賈似道','宋','宋诗','song-poetry','','[]','昏小腦搭重，路粗半節兒。',24,'全唐诗/poet.song.221000.json','["昏小腦搭重，路粗半節兒。", "棠梨三角額，此等不須題。"]'),
('c6d5a41c-c1e9-4013-894c-f6d5c62866f3','論臉  其一','賈似道','宋','宋诗','song-poetry','','[]','五色諸蟲臉，鋤彎注地長。',24,'全唐诗/poet.song.221000.json','["五色諸蟲臉，鋤彎注地長。", "再如鍋底黑，此物號强良。"]'),
('a3252048-6944-4d6a-889e-9c73c2d16b71','論臉  其二','賈似道','宋','宋诗','song-poetry','','[]','酒醉貓兒臉，花花白路紋。',24,'全唐诗/poet.song.221000.json','["酒醉貓兒臉，花花白路紋。", "此般生像者，棄物不須論。"]'),
('8235733c-2c57-4d46-9946-76c115afba5a','論項  其一','賈似道','宋','宋诗','song-poetry','','[]','項似蜻蜓樣，毛丁又起班。',24,'全唐诗/poet.song.221000.json','["項似蜻蜓樣，毛丁又起班。", "更兼形色正，打遍世無雙。"]'),
('bc5e5fe0-b691-4b03-89d4-dad5beb5d3f3','論項  其二','賈似道','宋','宋诗','song-poetry','','[]','緊隘花班項，無毛黑漆光。',24,'全唐诗/poet.song.221000.json','["緊隘花班項，無毛黑漆光。", "縱有完顔勇，終須受禍殃。"]'),
('e6d02d8f-bd66-4c43-865b-9740da95cc43','論項  其三','賈似道','宋','宋诗','song-poetry','','[]','青項堆青鈿，白毛根閃青。',48,'全唐诗/poet.song.221000.json','["青項堆青鈿，白毛根閃青。", "朱砂火盆底，桃皮等類形。", "白腐冬瓜大，寬臊壘起星。", "毛丁有肐𦞂，入手不當輕。"]'),
('dce9ebc8-7ea6-4a2a-ba80-bdf14f4c2f3d','論項  其四','賈似道','宋','宋诗','song-poetry','','[]','鱉小更短促，無毛一片光。',24,'全唐诗/poet.song.221000.json','["鱉小更短促，無毛一片光。", "這般生像者，不養又何妨。"]'),
('dc8075f7-096c-4545-9318-3e5e5eb8b22c','論翅  其一','賈似道','宋','宋诗','song-poetry','','[]','紫翅青金翅，木翅與油單。',48,'全唐诗/poet.song.221000.json','["紫翅青金翅，木翅與油單。", "黑色全如墨，梅花兩瓣攢。", "鬆闊偕長短，蓑衣得更難。", "遮身不見節，薄縐另相看。"]'),
('c0f310a8-8271-4940-b31d-c8144d090b33','論翅  其二','賈似道','宋','宋诗','song-poetry','','[]','膏藥積不縐，鬆短闊長同。',24,'全唐诗/poet.song.221000.json','["膏藥積不縐，鬆短闊長同。", "金紫須長翅，其餘只在中。"]'),
('d6f72a02-13ff-4227-95ef-14033102220e','論腿  其一','賈似道','宋','宋诗','song-poetry','','[]','大腿圓長健，小脚粗鐵線。',24,'全唐诗/poet.song.221000.json','["大腿圓長健，小脚粗鐵線。", "班白黄色真，此名金不換。"]'),
('067bafe0-6216-44ac-a924-d6e1a48d63f3','論腿  其二','賈似道','宋','宋诗','song-poetry','','[]','短鱉兼窮細，屁勳青黑同。',24,'全唐诗/poet.song.221000.json','["短鱉兼窮細，屁勳青黑同。", "只好留牆壁，何須問主公。"]'),
('54dd5de5-fcc3-4ff5-bff5-0183bf3c999b','論肉  其一','賈似道','宋','宋诗','song-poetry','','[]','紫黑蒼黄肉，青白勝鵝梨。',24,'全唐诗/poet.song.221000.json','["紫黑蒼黄肉，青白勝鵝梨。", "黑青肉亦白，淡黄白亦宜。"]'),
('46c4e08b-f729-4e04-a095-93c8103eb237','論肉  其二','賈似道','宋','宋诗','song-poetry','','[]','肉色欠純正，腰上多紅鈴。',24,'全唐诗/poet.song.221000.json','["肉色欠純正，腰上多紅鈴。", "月頭紅白間，百戰不能贏。"]'),
('caddb63b-6494-406e-96da-cc998146136f','論蝴蜂形','賈似道','宋','宋诗','song-poetry','','[]','貌若蝴蜂腿脚纖，細腰項緊兩頭尖。',32,'全唐诗/poet.song.221000.json','["貌若蝴蜂腿脚纖，細腰項緊兩頭尖。", "遍身黄色金紋理，百口之中一口鉗。"]'),
('db8c4f52-02b2-424a-a9e0-a16e84c1d238','論螻蟈形','賈似道','宋','宋诗','song-poetry','','[]','螻蟈之形最難相，牙長腿短頭尖亮。',32,'全唐诗/poet.song.221000.json','["螻蟈之形最難相，牙長腿短頭尖亮。", "尾豁過肩三二分，正是雌頭拖肚樣。"]'),
('01168891-819d-471c-9967-d680609865f2','論蜘蛛形','賈似道','宋','宋诗','song-poetry','','[]','身材局促似蜘蛛，且喜牙長六足鋪。',32,'全唐诗/poet.song.221000.json','["身材局促似蜘蛛，且喜牙長六足鋪。", "羽翼不長肩蓋盡，等閑覓得夜明珠。"]'),
('d58febc3-91af-480f-8179-bebe56f64ca3','論螳螂形  其一','賈似道','宋','宋诗','song-poetry','','[]','首短身長何足用，羽翅好是航船𦨴。',32,'全唐诗/poet.song.221000.json','["首短身長何足用，羽翅好是航船𦨴。", "若還六足盡尖長，此是螳螂最堪用。"]'),
('aa8df72e-86ea-44fe-ba6f-aa9ade2d1e21','論螳螂形  其二','賈似道','宋','宋诗','song-poetry','','[]','身狹牙尖大肚皮，脚前喬立仰頭窺。',32,'全唐诗/poet.song.221000.json','["身狹牙尖大肚皮，脚前喬立仰頭窺。", "此蛩不問青黄色，鬭到深秋必定輸。"]'),
('efe5a3e3-9404-41dd-a2b8-35b9fca225f2','論蚱蜢形','賈似道','宋','宋诗','song-poetry','','[]','頭大肩尖腿脚長，秀釘模樣最難當。',32,'全唐诗/poet.song.221000.json','["頭大肩尖腿脚長，秀釘模樣最難當。", "側生身分高而厚，鬭到秋深贏滿場。"]'),
('b7ab9c5a-4722-482d-b906-ab68cc7bd9f4','論玉蜂形','賈似道','宋','宋诗','song-poetry','','[]','尖翅名呼是玉蜂，千中難遇實難逢。',32,'全唐诗/poet.song.221000.json','["尖翅名呼是玉蜂，千中難遇實難逢。", "如君遇著須不避，不比尋常是毒蟲。"]'),
('8da3b578-a658-4786-8ca0-2137d1cce643','論棗核形','賈似道','宋','宋诗','song-poetry','','[]','身如棗核兩頭尖，左右觀來是塊磚。',32,'全唐诗/poet.song.221000.json','["身如棗核兩頭尖，左右觀來是塊磚。", "往來千遍無辭口，一秋咬敗萬千千。"]'),
('bba54edb-d136-4056-a4aa-2b24ebbc7a62','論竈雞形','賈似道','宋','宋诗','song-poetry','','[]','頭尖項細肚皮拖，白翅生來滿背鋪。',32,'全唐诗/poet.song.221000.json','["頭尖項細肚皮拖，白翅生來滿背鋪。", "腿脚不長身懶擁，當頭金線叫嘍囉。"]'),
('72aa8546-14cf-4cee-8eff-a61e15477cf3','論蟑螂形','賈似道','宋','宋诗','song-poetry','','[]','易名寬翅號蟑螂，翅闊頭尖牙用長。',32,'全唐诗/poet.song.221000.json','["易名寬翅號蟑螂，翅闊頭尖牙用長。", "身要匾攤脚要細，只許英雄三二番。"]'),
('49acabcb-b5ee-42de-9d35-fef45b574b8e','論蝴蜂形','賈似道','宋','宋诗','song-poetry','','[]','頭尖肚大象蝴蜂，兩翅含開腿脚窮。',32,'全唐诗/poet.song.221000.json','["頭尖肚大象蝴蜂，兩翅含開腿脚窮。", "此蟲只好無錢鬭，當真必害主人翁。"]'),
('3e0bab36-8727-4608-8f1c-89c1a992bd6d','論蝦脊龜形','賈似道','宋','宋诗','song-poetry','','[]','龜形蝦脊不宜紅，腿脚俱長力不庸。',32,'全唐诗/poet.song.221000.json','["龜形蝦脊不宜紅，腿脚俱長力不庸。", "色黑體肥毛白項，金絲金線絕倫蟲。"]'),
('3cc6497e-11c1-4733-bbd4-339ee2dd3e8f','論龜鶴形','賈似道','宋','宋诗','song-poetry','','[]','頭如蠶嘴肚如琴，兩翅啾啾叫不鳴。',32,'全唐诗/poet.song.221000.json','["頭如蠶嘴肚如琴，兩翅啾啾叫不鳴。", "識者若逢此促織，這般號作大將軍。"]'),
('09d574b1-3a1c-4f00-ab79-8629ea9c212b','論土狗形','賈似道','宋','宋诗','song-poetry','','[]','頭粗項闊肚低拖，翼翅生來半背鋪。',32,'全唐诗/poet.song.221000.json','["頭粗項闊肚低拖，翼翅生來半背鋪。", "脚腿壯肥身巨𪢬，當頭起線叫如鑼。"]'),
('d59eb89e-fb22-4c7b-9252-f0730e0cb8ad','論土蜂形','賈似道','宋','宋诗','song-poetry','','[]','尖翅名呼是土蜂，紫黄色者實難逢。',32,'全唐诗/poet.song.221000.json','["尖翅名呼是土蜂，紫黄色者實難逢。", "這般色樣如君得，不比常蟲是毒蟲。"]'),
('1a3bfef1-01b8-4b30-801c-f6762987edb4','論棗核形','賈似道','宋','宋诗','song-poetry','','[]','身如棗核兩頭尖，仔細觀來却是舡。',32,'全唐诗/poet.song.221000.json','["身如棗核兩頭尖，仔細觀來却是舡。", "交鋒便見强中口，咬退諸蟲不敢前。"]'),
('fe0e6acd-cb4c-4529-93d9-c58f76efd78b','論蟹踞形','賈似道','宋','宋诗','song-poetry','','[]','蛩身弓起如蟹踞，不拘五色或麻頭。',32,'全唐诗/poet.song.221000.json','["蛩身弓起如蟹踞，不拘五色或麻頭。", "任人觀看則不怕，此是名蟲何處求。"]'),
('4644c054-d48e-4a28-9070-34f946ae04dc','論蝦青形','賈似道','宋','宋诗','song-poetry','','[]','龜背蝦青不宜紅，腿脚俱長鬭不慵。',32,'全唐诗/poet.song.221000.json','["龜背蝦青不宜紅，腿脚俱長鬭不慵。", "色黑貌凡非物類，金絲透頂絕倫蟲。"]'),
('37c07012-d7c1-4263-9dd8-199644894f28','論真紅色','賈似道','宋','宋诗','song-poetry','','[]','眼如椒子遍身紅，腿脚如霜鬚尾同。',32,'全唐诗/poet.song.221000.json','["眼如椒子遍身紅，腿脚如霜鬚尾同。", "若逢敵手君休怕，數番咬死又成功。"]'),
('dfbb3f4d-d610-435b-b1f2-940a1d1b65c4','論真青色','賈似道','宋','宋诗','song-poetry','','[]','青金頭象菩提子，頭上毛青靛染成。',32,'全唐诗/poet.song.221000.json','["青金頭象菩提子，頭上毛青靛染成。", "若還鉗得芝蔴白，請君鬭盡莫疑生。"]'),
('9b713276-d93d-4f83-bcda-5ea4b7878766','論真黄色','賈似道','宋','宋诗','song-poetry','','[]','翅金肉白頂紅麻，項糝毛青腿少瑕。',32,'全唐诗/poet.song.221000.json','["翅金肉白頂紅麻，項糝毛青腿少瑕。", "更有一雙牙似墨，這般相貌最爲佳。"]'),
('5237b0ab-1cb1-4225-a26c-fbaa088ed376','論真黑色','賈似道','宋','宋诗','song-poetry','','[]','黑者須當頭似漆，仔細看來無別色。',32,'全唐诗/poet.song.221000.json','["黑者須當頭似漆，仔細看來無別色。", "於中牙肚白如銀，到作將軍爲第一。"]'),
('949ca8e1-6f61-4005-b5f8-0c886315cfd1','論真白色','賈似道','宋','宋诗','song-poetry','','[]','白頭白項翅如銀，上手觀來一似冰。',32,'全唐诗/poet.song.221000.json','["白頭白項翅如銀，上手觀來一似冰。", "棗紅牙齒如針利，總無骨肉似將軍。"]'),
('3273a0cd-a74f-4316-98d5-5b9ce4e94227','論真紫色','賈似道','宋','宋诗','song-poetry','','[]','紫者須當要色濃，更兼肋腿與身同。',32,'全唐诗/poet.song.221000.json','["紫者須當要色濃，更兼肋腿與身同。", "頭雌腰闊陰陽翅，贏盡埸中獨請功。"]'),
('8e2dc804-6edf-41d5-898b-1f5154735ca0','論水紅色','賈似道','宋','宋诗','song-poetry','','[]','水紅鬚尾水紅衣，白肚團員模樣奇。',32,'全唐诗/poet.song.221000.json','["水紅鬚尾水紅衣，白肚團員模樣奇。", "班點一些渾不染，傍人號作杜公兒。"]'),
('0c4f9f0f-fe1f-43e2-abef-d5c070264149','論深青色','賈似道','宋','宋诗','song-poetry','','[]','顔色深沉似污泥，紫頭青項盡相宜。',32,'全唐诗/poet.song.221000.json','["顔色深沉似污泥，紫頭青項盡相宜。", "齒長腹肚兼華白，鬭到秋深花带歸。"]'),
('bb928266-47da-4575-b9d7-7eebd062789f','論淡青色','賈似道','宋','宋诗','song-poetry','','[]','頭紫葡萄項摻青，正身厚闊似鴉明。',32,'全唐诗/poet.song.221000.json','["頭紫葡萄項摻青，正身厚闊似鴉明。", "殻紋淡薄輕銀翅，鬭著交鋒速便贏。"]'),
('f8e56169-f019-42d6-b603-e0625c95072c','論紫青色','賈似道','宋','宋诗','song-poetry','','[]','紫頭青項背如龜，青不青兮紫不緋。',32,'全唐诗/poet.song.221000.json','["紫頭青項背如龜，青不青兮紫不緋。", "仔細看來茄子色，更兼腿大最爲奇。"]'),
('62d634fb-4cba-42a4-a498-6a0b4d6ddd54','論灰青色','賈似道','宋','宋诗','song-poetry','','[]','顔色深沉不好看，灰頭灰項不新鮮。',32,'全唐诗/poet.song.221000.json','["顔色深沉不好看，灰頭灰項不新鮮。", "只因翅皺長牙齒，鬭相凶頑必搶前。"]'),
('b45b35f3-b900-46a0-b495-99ae2097ad22','論淡黄色','賈似道','宋','宋诗','song-poetry','','[]','肉白紅頭項摻青，頭粗脚壯齒如針。',32,'全唐诗/poet.song.221000.json','["肉白紅頭項摻青，頭粗脚壯齒如針。", "這般蟲子非容易，九遍交鋒十次贏。"]'),
('a0aff8a0-78cb-4e6f-8b63-6dbd815ffb23','論河蟹色','賈似道','宋','宋诗','song-poetry','','[]','赤色却如河蟹色，麻頭秀項極難得。',32,'全唐诗/poet.song.221000.json','["赤色却如河蟹色，麻頭秀項極難得。", "棗紅牙齒盡相宜，只恐項光頭又黑。"]'),
('6352a2b2-689a-4a2a-9b63-3a267e2583b2','論蝦青色','賈似道','宋','宋诗','song-poetry','','[]','有等名爲蝦殻青，比似青來翅不金。',32,'全唐诗/poet.song.221000.json','["有等名爲蝦殻青，比似青來翅不金。", "不問牙鉗白不白，須看項上带毛丁。"]'),
('b9426150-aba7-4397-8ec9-8d4dae6a1efa','論油丹色','賈似道','宋','宋诗','song-poetry','','[]','黑頭青項翅油丹，腿脚牙長似雪霜。',32,'全唐诗/poet.song.221000.json','["黑頭青項翅油丹，腿脚牙長似雪霜。", "相貌這般無覓處，鬭時絕勝豈尋常。"]'),
('7a87a3a9-cb38-4e02-80a5-920432f96b3a','論烏鴉色','賈似道','宋','宋诗','song-poetry','','[]','黑色明如黑漆光，白牙綉項皂羅裳。',32,'全唐诗/poet.song.221000.json','["黑色明如黑漆光，白牙綉項皂羅裳。", "肚皮腿脚皆如玉，內相將軍不可當。"]'),
('a05a5d0b-86da-458a-ad90-67a8640a9c0b','青麻頭','賈似道','宋','宋诗','song-poetry','','[]','摻青皺翅紫麻頭，肚白身肥牙似鈎。',32,'全唐诗/poet.song.221000.json','["摻青皺翅紫麻頭，肚白身肥牙似鈎。", "毛項花牙長腿脚，鬬雞生相鬭三秋。"]');
